window.trendingPapers = {
    "today": [{"paper": {"id": "2606.13681", "authors": [{"_id": "6a2b77ca4957fcdd3aac06a4", "user": {"_id": "67580d23f498e0436ce182fb", "avatarUrl": "/avatars/696d1c91dbd43d267747d7e98af096bd.svg", "isPro": false, "fullname": "Jundong Xu", "user": "Aiden0526", "type": "user", "name": "Aiden0526"}, "name": "Jundong Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:56:31.093Z", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a5", "name": "Qingchuan Li", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a6", "name": "Jiaying Wu", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a7", "name": "Yihuai Lan", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a8", "name": "Shuyue Stella Li", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a9", "name": "Huichi Zhou", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06aa", "name": "Bowen Jiang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ab", "name": "Lei Wang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ac", "name": "Jun Wang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ad", "name": "Anh Tuan Luu", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ae", "name": "Caiming Xiong", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06af", "name": "Hae Won Park", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06b0", "name": "Bryan Hooi", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06b1", "name": "Zhiyuan Hu", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "EvoArena: Tracking Memory Evolution for Robust LLM Agents in Dynamic Environments", "submittedOnDailyBy": {"_id": "64351475901c5734bcb64248", "avatarUrl": "/avatars/12346d4301c1bfb00ce0ea128a93cc15.svg", "isPro": false, "fullname": "Zhiyuan Hu", "user": "zhiyuanhucs", "type": "user", "name": "zhiyuanhucs"}, "summary": "Large language model (LLM) agents have achieved strong performance on a wide range of benchmarks, yet most evaluations assume static environments. In contrast, real-world deployment is inherently dynamic, requiring agents to continually align their knowledge, skills, and behavior with changing environments and updated task conditions. To address this gap, we introduce EvoArena, a benchmark suite that models environment changes as sequences of progressive updates across terminal, software, and social domains. We further propose EvoMem, a patch-based memory paradigm that records memory evolution as structured update histories, enabling agents to reason about environmental evolution through changes in their memory. Experiments show that current agents struggle on EvoArena, achieving an average accuracy of 39.6% across evolving terminal, software, and social-preference domains. EvoMem consistently improves performance, yielding an average gain of 1.5% on EvoArena and also improving standard benchmarks such as GAIA and LoCoMo by 6.1% and 4.8%. Beyond individual tasks, EvoMem further improves chain-level accuracy by 3.7% on EvoArena, where success requires completing a consecutive sequence of related evolutionary subtasks. Mechanistic analysis shows that EvoMem improves evidence capture in the memory, indicating better preservation of complete evolving environment states. Our results highlight the importance of modeling evolution in both evaluation and memory for reliable agent deployment.", "upvotes": 104, "discussionId": "6a2b77ca4957fcdd3aac06b2", "projectPage": "https://aiden0526.github.io/EvoArena/", "githubRepo": "https://github.com/Aiden0526/EvoArena", "githubRepoAddedBy": "user", "ai_summary": "EvoArena benchmark and EvoMem memory paradigm address the challenge of dynamic environments in LLM agents by modeling progressive updates and structured memory evolution, showing improved performance on evolving tasks.", "ai_keywords": ["large language model agents", "EvoArena", "EvoMem", "memory evolution", "environment changes", "progressive updates", "terminal domain", "software domain", "social domain", "chain-level accuracy", "mechanistic analysis"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 8, "organization": {"_id": "63728bde14d543d507ae970d", "name": "MIT", "fullname": "Massachusetts Institute of Technology", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/S90qoeEJeEYaYf-c7Zs8g.png"}, "summary_zh": "<ul>\n    <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLM\uff09\u5728\u8bb8\u591a\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u51fa\u8272\uff0c\u4f46\u5927\u90e8\u5206\u8bc4\u4f30\u5047\u8bbe\u73af\u5883\u662f\u9759\u6001\u7684\u3002</li>\n    <li>\u73b0\u5b9e\u4e16\u754c\u662f\u52a8\u6001\u7684\uff0c\u4ee3\u7406\u9700\u8981\u4e0d\u65ad\u8c03\u6574\u77e5\u8bc6\u548c\u6280\u80fd\u4ee5\u9002\u5e94\u73af\u5883\u53d8\u5316\u3002</li>\n    <li>\u6211\u4eec\u63a8\u51fa\u4e86EvoArena\u57fa\u51c6\uff0c\u6a21\u62df\u73af\u5883\u53d8\u5316\u4e3a\u4e00\u7cfb\u5217\u9010\u6b65\u66f4\u65b0\uff0c\u6db5\u76d6\u7ec8\u7aef\u3001\u8f6f\u4ef6\u548c\u793e\u4ea4\u9886\u57df\u3002</li>\n    <li>\u6211\u4eec\u8fd8\u63d0\u51fa\u4e86EvoMem\u8bb0\u5fc6\u6a21\u578b\uff0c\u8bb0\u5f55\u8bb0\u5fc6\u6f14\u53d8\uff0c\u5e2e\u52a9\u4ee3\u7406\u7406\u89e3\u73af\u5883\u53d8\u5316\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u5f53\u524d\u4ee3\u7406\u5728EvoArena\u4e0a\u7684\u8868\u73b0\u8f83\u5dee\uff0cEvoMem\u5219\u80fd\u63d0\u5347\u5176\u8868\u73b0\u548c\u51c6\u786e\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Large language model agents perform well in tests but struggle in changing real-world situations.</li>\n    <li>EvoArena is a new benchmark that simulates changing environments through progressive updates in different domains.</li>\n    <li>EvoMem is a memory system that helps agents track and learn from these changes over time.</li>\n    <li>Current agents only achieve about 39.6% accuracy on EvoArena, but EvoMem boosts their performance by an average of 1.5%.</li>\n    <li>Using EvoMem also improves performance on other standard tests and helps agents better capture and remember evolving states.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "EvoArena: Tracking Memory Evolution for Robust LLM Agents in Dynamic Environments", "summary": "Large language model (LLM) agents have achieved strong performance on a wide range of benchmarks, yet most evaluations assume static environments. In contrast, real-world deployment is inherently dynamic, requiring agents to continually align their knowledge, skills, and behavior with changing environments and updated task conditions. To address this gap, we introduce EvoArena, a benchmark suite that models environment changes as sequences of progressive updates across terminal, software, and social domains. We further propose EvoMem, a patch-based memory paradigm that records memory evolution as structured update histories, enabling agents to reason about environmental evolution through changes in their memory. Experiments show that current agents struggle on EvoArena, achieving an average accuracy of 39.6% across evolving terminal, software, and social-preference domains. EvoMem consistently improves performance, yielding an average gain of 1.5% on EvoArena and also improving standard benchmarks such as GAIA and LoCoMo by 6.1% and 4.8%. Beyond individual tasks, EvoMem further improves chain-level accuracy by 3.7% on EvoArena, where success requires completing a consecutive sequence of related evolutionary subtasks. Mechanistic analysis shows that EvoMem improves evidence capture in the memory, indicating better preservation of complete evolving environment states. Our results highlight the importance of modeling evolution in both evaluation and memory for reliable agent deployment.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13681.png", "numComments": 1, "submittedBy": {"_id": "64351475901c5734bcb64248", "avatarUrl": "/avatars/12346d4301c1bfb00ce0ea128a93cc15.svg", "fullname": "Zhiyuan Hu", "name": "zhiyuanhucs", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 7, "isUserFollowing": false}, "organization": {"_id": "63728bde14d543d507ae970d", "name": "MIT", "fullname": "Massachusetts Institute of Technology", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/S90qoeEJeEYaYf-c7Zs8g.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.13392", "authors": [{"_id": "6a2b99244957fcdd3aac0762", "user": {"_id": "670a145e4bea0a5a62535e80", "avatarUrl": "/avatars/231d61a46c7182384814f2a13a339054.svg", "isPro": false, "fullname": "Xunhao Lai", "user": "Xunhaolai", "type": "user", "name": "Xunhaolai"}, "name": "Xunhao Lai", "status": "admin_assigned", "statusLastChangedAt": "2026-06-12T14:08:46.132Z", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0763", "user": {"_id": "66b1ab0e180542df6bb13038", "avatarUrl": "/avatars/70dacb6043aa9edf8967096f4cfcc068.svg", "isPro": false, "fullname": "weiqi xu", "user": "xiaoxiaoOWO", "type": "user", "name": "xiaoxiaoOWO"}, "name": "Weiqi Xu", "status": "admin_assigned", "statusLastChangedAt": "2026-06-12T14:08:55.187Z", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0764", "name": "Yufeng Yang", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0765", "name": "Qiaorui Chen", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0766", "name": "Yang Xu", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0767", "user": {"_id": "6375dfa7f9aafd41ce145254", "avatarUrl": "/avatars/19e7460dd7ea6c60e1c52d5707660cc8.svg", "isPro": false, "fullname": "Lunbin Zeng", "user": "xiazhi", "type": "user", "name": "xiazhi"}, "name": "Lunbin Zeng", "status": "admin_assigned", "statusLastChangedAt": "2026-06-12T14:09:08.225Z", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0768", "name": "Xiaolong Li", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0769", "user": {"_id": "64b76660f92b20f7a37c3df7", "avatarUrl": "/avatars/40158717bb9370f1e5d0ed156a6fed1f.svg", "isPro": false, "fullname": "HaohaiSun", "user": "HaohaiSun", "type": "user", "name": "HaohaiSun"}, "name": "Haohai Sun", "status": "admin_assigned", "statusLastChangedAt": "2026-06-12T14:10:07.960Z", "hidden": false}, {"_id": "6a2b99244957fcdd3aac076a", "name": "Haichao Zhu", "hidden": false}, {"_id": "6a2b99244957fcdd3aac076b", "name": "Vito Zhang", "hidden": false}, {"_id": "6a2b99244957fcdd3aac076c", "name": "Pengyu Zhao", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "MiniMax Sparse Attention", "submittedOnDailyBy": {"_id": "673463f29cb2775fbe62a626", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/673463f29cb2775fbe62a626/64k_zEitiRQD_U002ojyy.jpeg", "isPro": false, "fullname": "Ryanlee", "user": "ryanlee-dev", "type": "user", "name": "ryanlee-dev"}, "summary": "Ultra-long-context capability is becoming indispensable for frontier LLMs: agentic workflows, repository-scale code reasoning, and persistent memory all require the model to jointly attend over hundreds of thousands to millions of tokens, yet the quadratic cost of softmax attention makes this untenable at deployment scale. We introduce MiniMax Sparse Attention (MSA), a blockwise sparse attention built upon Grouped Query Attention (GQA). A lightweight Index Branch scores key-value blocks and independently selects a Top-k subset for each GQA group, enabling group-specific sparse retrieval while maintaining efficient block-level execution; the Main Branch then performs exact block-sparse attention over only the selected blocks. Designed around a principle of simplicity and scalability, MSA is deliberately streamlined, making it straightforward to deploy efficiently across a broad range of GPUs. To translate sparsity into practical speedups, we co-design MSA with a GPU execution path that uses exp-free Top-k selection and KV-outer sparse attention to improve tensor-core utilization under block-granular access. On a 109B-parameter model with native multimodal training, MSA performs on par with GQA while reducing per-token attention compute by 28.4x at 1M context. Paired with our co-designed kernel, MSA achieves 14.2x prefill and 7.6x decoding wall-clock speedups on H800. Our inference kernel is available at: https://github.com/MiniMax-AI/MSA. A production-grade natively multimodal model powered by MSA has been publicly released at: https://huggingface.co/MiniMaxAI/MiniMax-M3.", "upvotes": 82, "discussionId": "6a2b99244957fcdd3aac076d", "githubRepo": "https://github.com/MiniMax-AI/MSA", "githubRepoAddedBy": "user", "ai_summary": "MiniMax Sparse Attention enables efficient processing of ultra-long contexts in large language models through blockwise sparsity and optimized GPU execution, achieving significant speedups while maintaining performance.", "ai_keywords": ["sparse attention", "Grouped Query Attention", "Top-k selection", "blockwise sparse attention", "tensor-core utilization", "prefill", "decoding", "attention compute", "context length"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 184, "organization": {"_id": "6778fc29920093dbc0c24917", "name": "MiniMaxAI", "fullname": "MiniMax", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/676e38ad04af5bec20bc9faf/dUd-LsZEX0H_d4qefO_g6.jpeg"}, "summary_zh": "<ul>\n    <li>\u8d85\u957f\u4e0a\u4e0b\u6587\u5904\u7406\u80fd\u529b\u5bf9\u4e8e\u524d\u6cbf\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLMs\uff09\u53d8\u5f97\u4e0d\u53ef\u6216\u7f3a\u3002</li>\n    <li>\u4ecb\u7ecd\u4e86\u4e00\u79cd\u540d\u4e3a\u8ff7\u4f60\u6700\u5927\u7a00\u758f\u6ce8\u610f\u529b\uff08MSA\uff09\u7684\u65b0\u65b9\u6cd5\uff0c\u53ef\u4ee5\u6709\u6548\u5904\u7406\u5927\u91cf\u4ee3\u5e01\u3002</li>\n    <li>MSA \u901a\u8fc7\u8f7b\u91cf\u7ea7\u7d22\u5f15\u5206\u652f\u548c\u4e3b\u5206\u652f\u7684\u8bbe\u8ba1\uff0c\u5b9e\u73b0\u4e86\u9ad8\u6548\u7684\u7a00\u758f\u68c0\u7d22\u548c\u8ba1\u7b97\u3002</li>\n    <li>\u5728109B\u53c2\u6570\u7684\u6a21\u578b\u4e0a\uff0cMSA\u7684\u6bcf\u4e2a\u4ee3\u5e01\u6ce8\u610f\u529b\u8ba1\u7b97\u51cf\u5c11\u4e8628.4\u500d\u3002</li>\n    <li>MSA\u7684\u63a8\u7406\u5185\u6838\u548c\u57fa\u4e8e\u6b64\u7684\u591a\u6a21\u6001\u6a21\u578b\u5df2\u516c\u5f00\u53d1\u5e03\uff0c\u63d0\u4f9b\u4e86\u66f4\u5feb\u7684\u63a8\u7406\u901f\u5ea6\u3002</li>\n</ul>", "summary_simple": "<ul>\n  <li>Ultra-long-context capability is essential for advanced language models (LLMs) to handle large amounts of data effectively.</li>\n  <li>MiniMax Sparse Attention (MSA) is a new method that improves how these models manage attention over many tokens without excessive computational costs.</li>\n  <li>MSA uses a two-part system to select and handle only the most relevant pieces of data, making it more efficient for processing.</li>\n  <li>This method significantly speeds up the model's performance, achieving large reductions in the time and resources needed for attention calculations.</li>\n  <li>A multimodal model using MSA has been released, showcasing its effectiveness and efficiency in practical applications.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "MiniMax Sparse Attention", "summary": "Ultra-long-context capability is becoming indispensable for frontier LLMs: agentic workflows, repository-scale code reasoning, and persistent memory all require the model to jointly attend over hundreds of thousands to millions of tokens, yet the quadratic cost of softmax attention makes this untenable at deployment scale. We introduce MiniMax Sparse Attention (MSA), a blockwise sparse attention built upon Grouped Query Attention (GQA). A lightweight Index Branch scores key-value blocks and independently selects a Top-k subset for each GQA group, enabling group-specific sparse retrieval while maintaining efficient block-level execution; the Main Branch then performs exact block-sparse attention over only the selected blocks. Designed around a principle of simplicity and scalability, MSA is deliberately streamlined, making it straightforward to deploy efficiently across a broad range of GPUs. To translate sparsity into practical speedups, we co-design MSA with a GPU execution path that uses exp-free Top-k selection and KV-outer sparse attention to improve tensor-core utilization under block-granular access. On a 109B-parameter model with native multimodal training, MSA performs on par with GQA while reducing per-token attention compute by 28.4x at 1M context. Paired with our co-designed kernel, MSA achieves 14.2x prefill and 7.6x decoding wall-clock speedups on H800. Our inference kernel is available at: https://github.com/MiniMax-AI/MSA. A production-grade natively multimodal model powered by MSA has been publicly released at: https://huggingface.co/MiniMaxAI/MiniMax-M3.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13392.png", "numComments": 1, "submittedBy": {"_id": "673463f29cb2775fbe62a626", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/673463f29cb2775fbe62a626/64k_zEitiRQD_U002ojyy.jpeg", "fullname": "Ryanlee", "name": "ryanlee-dev", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 37, "isUserFollowing": false}, "organization": {"_id": "6778fc29920093dbc0c24917", "name": "MiniMaxAI", "fullname": "MiniMax", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/676e38ad04af5bec20bc9faf/dUd-LsZEX0H_d4qefO_g6.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.13673", "authors": [{"_id": "6a2b69f04957fcdd3aac0602", "name": "Seokju Cho", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0603", "name": "Ryo Hachiuma", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0604", "name": "Abhishek Badki", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0605", "name": "Hang Su", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0606", "user": {"_id": "657152eb12f162153b50ec9d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/657152eb12f162153b50ec9d/qnldHP35PclV0pDz_05q8.jpeg", "isPro": false, "fullname": "Byung-Kwan Lee", "user": "BK-Lee", "type": "user", "name": "BK-Lee"}, "name": "Byung-Kwan Lee", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:56:59.203Z", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0607", "name": "Chan Hee Song", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0608", "name": "Sifei Liu", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0609", "name": "Subhashree Radhakrishnan", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac060a", "name": "Seungryong Kim", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac060b", "name": "Yu-Chiang Frank Wang", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac060c", "user": {"_id": "64ae22dd1aee69ece065cdcd", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ae22dd1aee69ece065cdcd/JG7QaHIrr4i2k4uwR4pZK.png", "isPro": false, "fullname": "Min-Hung Chen", "user": "cmhungsteve", "type": "user", "name": "cmhungsteve"}, "name": "Min-Hung Chen", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:57:01.112Z", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "SpatialClaw: Rethinking Action Interface for Agentic Spatial Reasoning", "submittedOnDailyBy": {"_id": "64ae22dd1aee69ece065cdcd", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ae22dd1aee69ece065cdcd/JG7QaHIrr4i2k4uwR4pZK.png", "isPro": false, "fullname": "Min-Hung Chen", "user": "cmhungsteve", "type": "user", "name": "cmhungsteve"}, "summary": "Spatial reasoning, the ability to determine where objects are, how they relate, and how they move in 3D, remains a fundamental challenge for vision-language models (VLMs). Tool-augmented agents attempt to address this by augmenting VLMs with specialist perception modules, yet their effectiveness is bounded by the action interface through which those tools are invoked. In this work, we study how the design of this interface shapes the agent's capacity for open-ended spatial reasoning. Existing spatial agents either employ single-pass code execution, which commits to a full analysis strategy before any intermediate result is observed, or rely on a structured tool-call interface that often offers less flexibility for freely composing operations or tailoring the analysis to each task. Both designs offer limited flexibility for open-ended, complex 3D/4D spatial reasoning. We therefore propose SpatialClaw, a training-free framework for spatial reasoning that adopts code as the action interface. SpatialClaw maintains a stateful Python kernel pre-loaded with input frames and a suite of perception and geometry primitives, letting a VLM-backed agent write one executable cell per step conditioned on all prior outputs, enabling the agent to flexibly compose and manipulate perception results and adapt its analysis to both intermediate text and visual observations and the demands of each problem. Evaluated across 20 spatial reasoning benchmarks spanning a broad range of static and dynamic 3D/4D spatial reasoning tasks, SpatialClaw achieves 59.9% average accuracy, outperforming the recent spatial agent by +11.2 points, with consistent gains across six VLM backbones from two model families without any benchmark- or model-specific adaptation.", "upvotes": 80, "discussionId": "6a2b69f04957fcdd3aac060d", "projectPage": "https://spatialclaw.github.io/", "githubRepo": "https://github.com/NVlabs/SpatialClaw", "githubRepoAddedBy": "user", "ai_summary": "SpatialClaw is a training-free framework that uses code as an action interface to enable flexible, stateful spatial reasoning in vision-language models, achieving superior performance across diverse 3D/4D spatial reasoning tasks.", "ai_keywords": ["vision-language models", "spatial reasoning", "tool-augmented agents", "action interface", "code execution", "Python kernel", "perception primitives", "geometry primitives", "executable cells", "open-ended reasoning", "3D/4D spatial reasoning", "benchmarks", "VLM backbones"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 53, "organization": {"_id": "60262b67268c201cdc8b7d43", "name": "nvidia", "fullname": "NVIDIA", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65df9200dc3292a8983e5017/Vs5FPVCH-VZBipV3qKTuy.png"}, "summary_zh": "<ul>\n    <li>\u7a7a\u95f4\u63a8\u7406\u662f\u89c6\u89c9\u8bed\u8a00\u6a21\u578b\uff08VLMs\uff09\u9762\u4e34\u7684\u4e00\u4e2a\u91cd\u8981\u6311\u6218\uff0c\u6d89\u53ca\u52303D\u7a7a\u95f4\u4e2d\u5bf9\u8c61\u7684\u4f4d\u7f6e\u3001\u5173\u7cfb\u548c\u8fd0\u52a8\u3002</li>\n    <li>\u76ee\u524d\u7684\u5de5\u5177\u589e\u5f3a\u4ee3\u7406\u901a\u8fc7\u4e13\u95e8\u7684\u611f\u77e5\u6a21\u5757\u6765\u6539\u5584VLMs\uff0c\u4f46\u5176\u6548\u679c\u53d7\u9650\u4e8e\u5de5\u5177\u8c03\u7528\u7684\u63a5\u53e3\u8bbe\u8ba1\u3002</li>\n    <li>\u73b0\u6709\u7684\u7a7a\u95f4\u4ee3\u7406\u8981\u4e48\u91c7\u7528\u5355\u6b21\u4ee3\u7801\u6267\u884c\uff0c\u8981\u4e48\u4f7f\u7528\u7ed3\u6784\u5316\u5de5\u5177\u8c03\u7528\u63a5\u53e3\uff0c\u7075\u6d3b\u6027\u6709\u9650\uff0c\u96be\u4ee5\u8fdb\u884c\u5f00\u653e\u5f0f\u590d\u6742\u7a7a\u95f4\u63a8\u7406\u3002</li>\n    <li>\u672c\u6587\u63d0\u51fa\u4e86SpatialClaw\uff0c\u4e00\u4e2a\u65e0\u8bad\u7ec3\u7684\u7a7a\u95f4\u63a8\u7406\u6846\u67b6\uff0c\u4f7f\u7528\u4ee3\u7801\u4f5c\u4e3a\u64cd\u4f5c\u63a5\u53e3\uff0c\u589e\u5f3a\u4e86\u7075\u6d3b\u6027\u3002</li>\n    <li>\u572820\u4e2a\u7a7a\u95f4\u63a8\u7406\u57fa\u51c6\u6d4b\u8bd5\u4e2d\uff0cSpatialClaw\u5b9e\u73b0\u4e8659.9%\u7684\u5e73\u5747\u51c6\u786e\u7387\uff0c\u6bd4\u6700\u65b0\u7684\u7a7a\u95f4\u4ee3\u7406\u9ad8\u51fa11.2\u4e2a\u767e\u5206\u70b9\uff0c\u4e14\u5728\u591a\u79cd\u6a21\u578b\u4e0a\u8868\u73b0\u4e00\u81f4\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Spatial reasoning is a tough challenge for vision-language models (VLMs) as it involves understanding object positions and movements in 3D space.</li>\n    <li>Current tool-augmented agents have limitations due to their design, which restricts flexibility in handling complex spatial reasoning tasks.</li>\n    <li>SpatialClaw is a new framework that uses a code-based action interface, allowing for more adaptable and flexible reasoning.</li>\n    <li>It operates with a Python kernel that helps the agent write code step-by-step, taking into account previous results for better decision-making.</li>\n    <li>SpatialClaw outperforms existing spatial reasoning agents in various benchmarks, achieving an average accuracy of 59.9% and showing improved performance across different models without needing specific adjustments.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "SpatialClaw: Rethinking Action Interface for Agentic Spatial Reasoning", "summary": "Spatial reasoning, the ability to determine where objects are, how they relate, and how they move in 3D, remains a fundamental challenge for vision-language models (VLMs). Tool-augmented agents attempt to address this by augmenting VLMs with specialist perception modules, yet their effectiveness is bounded by the action interface through which those tools are invoked. In this work, we study how the design of this interface shapes the agent's capacity for open-ended spatial reasoning. Existing spatial agents either employ single-pass code execution, which commits to a full analysis strategy before any intermediate result is observed, or rely on a structured tool-call interface that often offers less flexibility for freely composing operations or tailoring the analysis to each task. Both designs offer limited flexibility for open-ended, complex 3D/4D spatial reasoning. We therefore propose SpatialClaw, a training-free framework for spatial reasoning that adopts code as the action interface. SpatialClaw maintains a stateful Python kernel pre-loaded with input frames and a suite of perception and geometry primitives, letting a VLM-backed agent write one executable cell per step conditioned on all prior outputs, enabling the agent to flexibly compose and manipulate perception results and adapt its analysis to both intermediate text and visual observations and the demands of each problem. Evaluated across 20 spatial reasoning benchmarks spanning a broad range of static and dynamic 3D/4D spatial reasoning tasks, SpatialClaw achieves 59.9% average accuracy, outperforming the recent spatial agent by +11.2 points, with consistent gains across six VLM backbones from two model families without any benchmark- or model-specific adaptation.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13673.png", "numComments": 1, "submittedBy": {"_id": "64ae22dd1aee69ece065cdcd", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ae22dd1aee69ece065cdcd/JG7QaHIrr4i2k4uwR4pZK.png", "fullname": "Min-Hung Chen", "name": "cmhungsteve", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 19, "isUserFollowing": false}, "organization": {"_id": "60262b67268c201cdc8b7d43", "name": "nvidia", "fullname": "NVIDIA", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65df9200dc3292a8983e5017/Vs5FPVCH-VZBipV3qKTuy.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.13679", "authors": [{"_id": "6a2b6bbe4957fcdd3aac061e", "user": {"_id": "67e60ae6ac37824273d74389", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/YvPKZ_0gyJnvNwM1zK3JS.png", "isPro": true, "fullname": "Dian Zheng", "user": "zhengli1013", "type": "user", "name": "zhengli1013"}, "name": "Dian Zheng", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T14:04:59.526Z", "hidden": false}, {"_id": "6a2b6bbe4957fcdd3aac061f", "name": "Harry Lee", "hidden": false}, {"_id": "6a2b6bbe4957fcdd3aac0620", "name": "Manyuan Zhang", "hidden": false}, {"_id": "6a2b6bbe4957fcdd3aac0621", "name": "Kaituo Feng", "hidden": false}, {"_id": "6a2b6bbe4957fcdd3aac0622", "name": "Zoey Guo", "hidden": false}, {"_id": "6a2b6bbe4957fcdd3aac0623", "name": "Ray Zhang", "hidden": false}, {"_id": "6a2b6bbe4957fcdd3aac0624", "name": "Hongsheng Li", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "InterleaveThinker: Reinforcing Agentic Interleaved Generation", "submittedOnDailyBy": {"_id": "67e60ae6ac37824273d74389", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/YvPKZ_0gyJnvNwM1zK3JS.png", "isPro": true, "fullname": "Dian Zheng", "user": "zhengli1013", "type": "user", "name": "zhengli1013"}, "summary": "Recent image generators have demonstrated impressive photorealism and instruction-following capabilities in single-image generation and editing. However, constrained by their architectures, they cannot achieve interleaved generation (text-image sequence), which has crucial applications in visual narratives, guidance, and embodied manipulation. Even the latest open-source Unified Multimodal Models (UMMs) exhibit limited performance in this regard. In this paper, we introduce InterleaveThinker, the first multi-agent pipeline designed to endow any existing image generator with interleaved generation capabilities. Specifically, we employ a planner agent to organize the image-text input sequence, instructing the image generator on the required execution at each step. Subsequently, we introduce a critic agent to evaluate the generator's outputs, identify samples that deviate from the planned instructions, and refine the instructions for regeneration. To implement this pipeline, we construct the Interleave-Planner-SFT-80k and Interleave-Critic-SFT-112k to perform a format cold-start. Then we develop Interleave-Critic-RL-13k to reinforce the step-wise instruction correction capability within a generation trajectory using GRPO. Since a single interleaved generation trajectory may involve over 25 generator calls, optimizing the entire trajectory is computationally impractical. Therefore, we propose accuracy reward and step-wise reward, allowing single-step RL to effectively guide the entire generation trajectory. The results show that InterleaveThinker improves performance across various image generators. On interleaved generation benchmarks, it achieves performance comparable to Nano Banana and GPT-5. Surprisingly, it also significantly enhances the base model on reasoning-based benchmarks; for example, on 4-step FLUX.2-klein, we observe substantial gains on WISE and RISE.", "upvotes": 73, "discussionId": "6a2b6bbe4957fcdd3aac0625", "projectPage": "https://zhengdian1.github.io/InterleaveThinker-proj/", "githubRepo": "https://github.com/zhengdian1/InterleaveThinker", "githubRepoAddedBy": "user", "ai_summary": "InterleaveThinker enables interleaved generation capabilities for image generators through a multi-agent pipeline with planner and critic agents, achieving performance comparable to state-of-the-art models while enhancing reasoning benchmarks.", "ai_keywords": ["multi-agent pipeline", "image generator", "interleaved generation", "planner agent", "critic agent", "reinforcement learning", "GRPO", "accuracy reward", "step-wise reward"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 99, "summary_zh": "<ul>\n    <li>\u6700\u8fd1\u7684\u56fe\u50cf\u751f\u6210\u5668\u5728\u751f\u6210\u548c\u7f16\u8f91\u5355\u5f20\u56fe\u50cf\u65b9\u9762\u8868\u73b0\u51fa\u8272\uff0c\u4f46\u65e0\u6cd5\u5904\u7406\u6587\u672c\u4e0e\u56fe\u50cf\u4ea4\u66ff\u751f\u6210\u3002</li>\n    <li>\u672c\u6587\u4ecb\u7ecd\u4e86InterleaveThinker\uff0c\u8fd9\u662f\u7b2c\u4e00\u4e2a\u591a\u667a\u80fd\u4f53\u7cfb\u7edf\uff0c\u80fd\u4e3a\u73b0\u6709\u56fe\u50cf\u751f\u6210\u5668\u63d0\u4f9b\u4ea4\u66ff\u751f\u6210\u80fd\u529b\u3002</li>\n    <li>\u8be5\u7cfb\u7edf\u4f7f\u7528\u89c4\u5212\u8005\u4ee3\u7406\u7ec4\u7ec7\u56fe\u50cf-\u6587\u672c\u8f93\u5165\uff0c\u5e76\u5f15\u5bfc\u56fe\u50cf\u751f\u6210\u5668\u9010\u6b65\u6267\u884c\u3002</li>\n    <li>\u5f15\u5165\u8bc4\u4ef7\u4ee3\u7406\u6765\u8bc4\u4f30\u751f\u6210\u7684\u8f93\u51fa\uff0c\u5e76\u6839\u636e\u8ba1\u5212\u8fdb\u884c\u6307\u4ee4\u7684\u8c03\u6574\u548c\u518d\u751f\u6210\u3002</li>\n    <li>\u5b9e\u9a8c\u7ed3\u679c\u663e\u793a\uff0cInterleaveThinker\u5728\u591a\u4e2a\u56fe\u50cf\u751f\u6210\u5668\u4e0a\u7684\u8868\u73b0\u5f97\u5230\u4e86\u663e\u8457\u63d0\u5347\uff0c\u7279\u522b\u662f\u5728\u63a8\u7406\u57fa\u7840\u7684\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u4f18\u5f02\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>InterleaveThinker is a new multi-agent system that allows existing image generators to create images based on interleaved text and image instructions.</li>\n    <li>The system uses two main components: a planner to organize input sequences and a critic to evaluate and refine the outputs.</li>\n    <li>To support this, special models were created for planning and critique, helping to improve instruction correction during image generation.</li>\n    <li>InterleaveThinker can handle complex tasks that require many steps, using rewards to guide each step effectively.</li>\n    <li>The results show that it significantly enhances the performance of image generators, achieving results similar to advanced models like Nano Banana and GPT-5.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "InterleaveThinker: Reinforcing Agentic Interleaved Generation", "summary": "Recent image generators have demonstrated impressive photorealism and instruction-following capabilities in single-image generation and editing. However, constrained by their architectures, they cannot achieve interleaved generation (text-image sequence), which has crucial applications in visual narratives, guidance, and embodied manipulation. Even the latest open-source Unified Multimodal Models (UMMs) exhibit limited performance in this regard. In this paper, we introduce InterleaveThinker, the first multi-agent pipeline designed to endow any existing image generator with interleaved generation capabilities. Specifically, we employ a planner agent to organize the image-text input sequence, instructing the image generator on the required execution at each step. Subsequently, we introduce a critic agent to evaluate the generator's outputs, identify samples that deviate from the planned instructions, and refine the instructions for regeneration. To implement this pipeline, we construct the Interleave-Planner-SFT-80k and Interleave-Critic-SFT-112k to perform a format cold-start. Then we develop Interleave-Critic-RL-13k to reinforce the step-wise instruction correction capability within a generation trajectory using GRPO. Since a single interleaved generation trajectory may involve over 25 generator calls, optimizing the entire trajectory is computationally impractical. Therefore, we propose accuracy reward and step-wise reward, allowing single-step RL to effectively guide the entire generation trajectory. The results show that InterleaveThinker improves performance across various image generators. On interleaved generation benchmarks, it achieves performance comparable to Nano Banana and GPT-5. Surprisingly, it also significantly enhances the base model on reasoning-based benchmarks; for example, on 4-step FLUX.2-klein, we observe substantial gains on WISE and RISE.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13679.png", "numComments": 1, "submittedBy": {"_id": "67e60ae6ac37824273d74389", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/YvPKZ_0gyJnvNwM1zK3JS.png", "fullname": "Dian Zheng", "name": "zhengli1013", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 5, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.12087", "authors": [{"_id": "6a2adc0efdec76e893e76283", "name": "Jia Deng", "hidden": false}, {"_id": "6a2adc0efdec76e893e76284", "name": "Yimeng Chen", "hidden": false}, {"_id": "6a2adc0efdec76e893e76285", "name": "Xiaoqing Xiang", "hidden": false}, {"_id": "6a2adc0efdec76e893e76286", "user": {"_id": "6437b514a1fa778a4da67e4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6437b514a1fa778a4da67e4d/dHoNK4Nqr6OVG4IgzkdjH.png", "isPro": false, "fullname": "Finch", "user": "ziyang1060", "type": "user", "name": "ziyang1060"}, "name": "Ziyang Zeng", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T07:12:03.264Z", "hidden": false}, {"_id": "6a2adc0efdec76e893e76287", "name": "Shuo Tang", "hidden": false}, {"_id": "6a2adc0efdec76e893e76288", "name": "Wayne Xin Zhao", "hidden": false}, {"_id": "6a2adc0efdec76e893e76289", "name": "Feng Chang", "hidden": false}, {"_id": "6a2adc0efdec76e893e7628a", "name": "Chuan Hao", "hidden": false}, {"_id": "6a2adc0efdec76e893e7628b", "name": "Yuan Wei", "hidden": false}, {"_id": "6a2adc0efdec76e893e7628c", "name": "Ran Tao", "hidden": false}, {"_id": "6a2adc0efdec76e893e7628d", "name": "Bryan Dai", "hidden": false}, {"_id": "6a2adc0efdec76e893e7628e", "name": "Ji-Rong Wen", "hidden": false}], "publishedAt": "2026-06-10T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "FORT-Searcher: Synthesizing Shortcut-Resistant Search Tasks for Training Deep Search Agents", "submittedOnDailyBy": {"_id": "6544b9b646dbdeca34ee5f52", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6544b9b646dbdeca34ee5f52/nRx6m1C4wfZ_xSWoBUNJf.png", "isPro": false, "fullname": "Yuyang Hu", "user": "namespace-ERI", "type": "user", "name": "namespace-ERI"}, "summary": "Training deep search agents requires verifiable questions whose answers remain unavailable until sufficient evidence has been acquired through search. Existing synthesis methods often increase apparent difficulty by enriching graph structures, but structural complexity alone does not guarantee realized search difficulty: the intended search process can collapse through a cheaper identifying route. We formalize this gap with a shortcut-aware difficulty framework and identify four actionable shortcut risks: evidence co-coverage, single-clue selectivity, exposed constants, and prior-knowledge binding. To diagnose their realized effects, we use trajectory signatures including solving cost, answer hit time, and prior-shortcut rate. Guided by this framework, we introduce FORT, a Framework of Shortcut-Resistant Training-Data Synthesis. FORT constructs shortcut-resistant training data by controlling shortcut risks across entity selection, evidence graph construction, question formulation, and adversarial refinement. Experiments show that FORT induces longer pre-answer search and fewer shortcut patterns than existing open-source deep search datasets. Using the resulting trajectories, we train FORT-Searcher with supervised fine-tuning (SFT) only, and it achieves the best overall performance among comparable-size open-source search agents on challenging deep search benchmarks. Relevant resources will be made available at https://github.com/RUCAIBox/FORT-Searcher.", "upvotes": 71, "discussionId": "6a2adc0ffdec76e893e7628f", "githubRepo": "https://github.com/RUCAIBox/FORT-Searcher", "githubRepoAddedBy": "user", "ai_summary": "A framework for creating shortcut-resistant training data for deep search agents by identifying and mitigating four shortcut risks in data synthesis processes.", "ai_keywords": ["deep search agents", "shortcut-aware difficulty framework", "shortcut risks", "trajectory signatures", "FORT", "supervised fine-tuning", "deep search benchmarks"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 17, "summary_zh": "<ul>\n    <li>\u8bad\u7ec3\u6df1\u5ea6\u641c\u7d22\u4ee3\u7406\u9700\u8981\u53ef\u9a8c\u8bc1\u7684\u95ee\u9898\uff0c\u7b54\u6848\u5728\u83b7\u5f97\u8db3\u591f\u8bc1\u636e\u4e4b\u524d\u4e0d\u53ef\u7528\u3002</li>\n    <li>\u73b0\u6709\u5408\u6210\u65b9\u6cd5\u901a\u8fc7\u4e30\u5bcc\u56fe\u7ed3\u6784\u589e\u52a0\u4e86\u8868\u9762\u96be\u5ea6\uff0c\u4f46\u7ed3\u6784\u590d\u6742\u6027\u5e76\u4e0d\u4e00\u5b9a\u5e26\u6765\u5b9e\u9645\u641c\u7d22\u96be\u5ea6\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u4e2a\u8003\u8651\u6377\u5f84\u98ce\u9669\u7684\u96be\u5ea6\u6846\u67b6\uff0c\u8bc6\u522b\u51fa\u56db\u79cd\u6377\u5f84\u98ce\u9669\u3002</li>\n    <li>\u57fa\u4e8e\u6b64\u6846\u67b6\uff0c\u6211\u4eec\u5f15\u5165\u4e86FORT\uff0c\u4e00\u4e2a\u6297\u6377\u5f84\u8bad\u7ec3\u6570\u636e\u5408\u6210\u7684\u6846\u67b6\uff0c\u80fd\u591f\u63a7\u5236\u6377\u5f84\u98ce\u9669\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cFORT\u751f\u6210\u7684\u6570\u636e\u80fd\u591f\u5b9e\u73b0\u66f4\u957f\u7684\u641c\u7d22\u65f6\u95f4\u548c\u66f4\u5c11\u7684\u6377\u5f84\u6a21\u5f0f\uff0c\u8bad\u7ec3\u51fa\u7684\u641c\u7d22\u4ee3\u7406\u5728\u6df1\u5ea6\u641c\u7d22\u57fa\u51c6\u4e2d\u8868\u73b0\u6700\u4f73\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Training deep search agents needs questions that can't be answered until enough evidence is found.</li>\n    <li>Current methods make problems harder by complicating graph structures, but this doesn't always increase search difficulty.</li>\n    <li>The study introduces a framework that identifies four shortcut risks that can make searches easier than intended.</li>\n    <li>They developed FORT, a system that creates training data resistant to these shortcuts by carefully managing various factors.</li>\n    <li>Tests show FORT leads to deeper searches and better performance compared to existing datasets, training a new search agent called FORT-Searcher.</li>\n</ul>"}, "publishedAt": "2026-06-09T20:00:00.000Z", "title": "FORT-Searcher: Synthesizing Shortcut-Resistant Search Tasks for Training Deep Search Agents", "summary": "Training deep search agents requires verifiable questions whose answers remain unavailable until sufficient evidence has been acquired through search. Existing synthesis methods often increase apparent difficulty by enriching graph structures, but structural complexity alone does not guarantee realized search difficulty: the intended search process can collapse through a cheaper identifying route. We formalize this gap with a shortcut-aware difficulty framework and identify four actionable shortcut risks: evidence co-coverage, single-clue selectivity, exposed constants, and prior-knowledge binding. To diagnose their realized effects, we use trajectory signatures including solving cost, answer hit time, and prior-shortcut rate. Guided by this framework, we introduce FORT, a Framework of Shortcut-Resistant Training-Data Synthesis. FORT constructs shortcut-resistant training data by controlling shortcut risks across entity selection, evidence graph construction, question formulation, and adversarial refinement. Experiments show that FORT induces longer pre-answer search and fewer shortcut patterns than existing open-source deep search datasets. Using the resulting trajectories, we train FORT-Searcher with supervised fine-tuning (SFT) only, and it achieves the best overall performance among comparable-size open-source search agents on challenging deep search benchmarks. Relevant resources will be made available at https://github.com/RUCAIBox/FORT-Searcher.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.12087.png", "numComments": 1, "submittedBy": {"_id": "6544b9b646dbdeca34ee5f52", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6544b9b646dbdeca34ee5f52/nRx6m1C4wfZ_xSWoBUNJf.png", "fullname": "Yuyang Hu", "name": "namespace-ERI", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2606.08063", "authors": [{"_id": "6a2b7f8d4957fcdd3aac06ee", "user": {"_id": "642e7a12ccdcf5da7f9657a0", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/642e7a12ccdcf5da7f9657a0/w8jW5BagTuTp6EvC6KEyR.png", "isPro": true, "fullname": "Jiaqi Tang", "user": "Jiaqi-hkust", "type": "user", "name": "Jiaqi-hkust"}, "name": "Jiaqi Tang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:56:26.807Z", "hidden": false}, {"_id": "6a2b7f8d4957fcdd3aac06ef", "name": "Jianmin Chen", "hidden": false}, {"_id": "6a2b7f8d4957fcdd3aac06f0", "name": "Youyang Zhai", "hidden": false}, {"_id": "6a2b7f8d4957fcdd3aac06f1", "name": "Wei Wei", "hidden": false}, {"_id": "6a2b7f8d4957fcdd3aac06f2", "name": "Runtao Liu", "hidden": false}, {"_id": "6a2b7f8d4957fcdd3aac06f3", "name": "Mengjie Zhao", "hidden": false}, {"_id": "6a2b7f8d4957fcdd3aac06f4", "name": "Xiangyu Wu", "hidden": false}, {"_id": "6a2b7f8d4957fcdd3aac06f5", "name": "Qingfa Xiao", "hidden": false}, {"_id": "6a2b7f8d4957fcdd3aac06f6", "name": "Qifeng Chen", "hidden": false}], "publishedAt": "2026-06-06T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "Robust-U1: Can MLLMs Self-Recover Corrupted Visual Content for Robust Understanding?", "submittedOnDailyBy": {"_id": "642e7a12ccdcf5da7f9657a0", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/642e7a12ccdcf5da7f9657a0/w8jW5BagTuTp6EvC6KEyR.png", "isPro": true, "fullname": "Jiaqi Tang", "user": "Jiaqi-hkust", "type": "user", "name": "Jiaqi-hkust"}, "summary": "Multimodal Large Language Models (MLLMs) have demonstrated remarkable success in visual understanding, yet their performance degrades significantly under real-world visual corruptions. While existing robustness enhancement approaches exist, they are limited: black-box feature alignment lacks interpretability, and white-box text-based reasoning cannot restore lost pixel-level details. This work investigates a fundamental research question: Can MLLMs recover corrupted visual content by themselves? To address this, we propose Robust-U1, a novel framework that equips MLLMs with explicit visual self-recovery capability for robust understanding. The approach comprises three core stages: supervised fine-tuning for initial reconstruction, reinforcement learning with dual rewards (pixel-level SSIM and semantic-level CLIP similarity) for aligning high visual quality, and multimodal reasoning that jointly considers both the corrupted input and the recovered image. Extensive experiments demonstrate that Robust-U1 achieves state-of-the-art robustness on the real-world corruption benchmark and maintains superior performance under adversarial corruptions on general VQA benchmarks. Analysis confirms that high-quality visual recovery directly enhances reasoning performance, establishing self-recovery as a critical mechanism for robust visual understanding. The source code is available at https://github.com/jqtangust/Robust-U1.", "upvotes": 71, "discussionId": "6a2b7f8d4957fcdd3aac06f7", "projectPage": "https://huggingface.co/spaces/Jiaqi-hkust/Robust-U1", "githubRepo": "https://github.com/jqtangust/Robust-U1", "githubRepoAddedBy": "user", "ai_summary": "Robust-U1 enhances multimodal large language models' robustness against visual corruptions through self-recovery capabilities that improve both visual quality and reasoning performance.", "ai_keywords": ["multimodal large language models", "visual corruptions", "robustness enhancement", "supervised fine-tuning", "reinforcement learning", "dual rewards", "pixel-level SSIM", "semantic-level CLIP similarity", "multimodal reasoning", "visual self-recovery"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 72, "summary_zh": "<ul>\n    <li>\u591a\u6a21\u6001\u5927\u8bed\u8a00\u6a21\u578b\uff08MLLMs\uff09\u5728\u89c6\u89c9\u7406\u89e3\u65b9\u9762\u8868\u73b0\u51fa\u8272\uff0c\u4f46\u5728\u771f\u5b9e\u4e16\u754c\u7684\u89c6\u89c9\u5e72\u6270\u4e0b\u6027\u80fd\u663e\u8457\u4e0b\u964d\u3002</li>\n    <li>\u73b0\u6709\u7684\u589e\u5f3a\u9c81\u68d2\u6027\u7684\u65b9\u6cd5\u5b58\u5728\u5c40\u9650\u6027\uff0c\u65e0\u6cd5\u6709\u6548\u6062\u590d\u4e22\u5931\u7684\u50cf\u7d20\u7ec6\u8282\u3002</li>\n    <li>\u672c\u7814\u7a76\u63d0\u51fa\u4e86Robust-U1\u6846\u67b6\uff0c\u4f7fMLLMs\u5177\u5907\u81ea\u6211\u6062\u590d\u53d7\u635f\u89c6\u89c9\u5185\u5bb9\u7684\u80fd\u529b\u3002</li>\n    <li>Robust-U1\u5305\u62ec\u4e09\u4e2a\u6838\u5fc3\u9636\u6bb5\uff1a\u76d1\u7763\u5fae\u8c03\u3001\u5f3a\u5316\u5b66\u4e60\u4e0e\u53cc\u91cd\u5956\u52b1\u4ee5\u53ca\u591a\u6a21\u6001\u63a8\u7406\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cRobust-U1\u5728\u771f\u5b9e\u4e16\u754c\u5e72\u6270\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u4f18\u5f02\uff0c\u4e14\u5728\u4e00\u822c\u89c6\u89c9\u95ee\u7b54\u57fa\u51c6\u4e0a\u4e5f\u5177\u6709\u8f83\u5f3a\u6027\u80fd\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Multimodal Large Language Models (MLLMs) are good at understanding visuals but struggle with real-world visual damage.</li>\n    <li>Current methods to improve their robustness are limited and either lack clarity or can't fix detailed visual issues.</li>\n    <li>This study introduces Robust-U1, a new framework that helps MLLMs recover damaged visuals on their own.</li>\n    <li>Robust-U1 works in three steps: initial training to rebuild images, reinforcement learning to improve quality, and reasoning that combines damaged and recovered images.</li>\n    <li>Robust-U1 shows better performance on real-world visual challenges and improves reasoning by recovering high-quality visuals.</li>\n</ul>"}, "publishedAt": "2026-06-05T20:00:00.000Z", "title": "Robust-U1: Can MLLMs Self-Recover Corrupted Visual Content for Robust Understanding?", "summary": "Multimodal Large Language Models (MLLMs) have demonstrated remarkable success in visual understanding, yet their performance degrades significantly under real-world visual corruptions. While existing robustness enhancement approaches exist, they are limited: black-box feature alignment lacks interpretability, and white-box text-based reasoning cannot restore lost pixel-level details. This work investigates a fundamental research question: Can MLLMs recover corrupted visual content by themselves? To address this, we propose Robust-U1, a novel framework that equips MLLMs with explicit visual self-recovery capability for robust understanding. The approach comprises three core stages: supervised fine-tuning for initial reconstruction, reinforcement learning with dual rewards (pixel-level SSIM and semantic-level CLIP similarity) for aligning high visual quality, and multimodal reasoning that jointly considers both the corrupted input and the recovered image. Extensive experiments demonstrate that Robust-U1 achieves state-of-the-art robustness on the real-world corruption benchmark and maintains superior performance under adversarial corruptions on general VQA benchmarks. Analysis confirms that high-quality visual recovery directly enhances reasoning performance, establishing self-recovery as a critical mechanism for robust visual understanding. The source code is available at https://github.com/jqtangust/Robust-U1.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.08063.png", "numComments": 2, "submittedBy": {"_id": "642e7a12ccdcf5da7f9657a0", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/642e7a12ccdcf5da7f9657a0/w8jW5BagTuTp6EvC6KEyR.png", "fullname": "Jiaqi Tang", "name": "Jiaqi-hkust", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 25, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.13473", "authors": [{"_id": "6a2b6e314957fcdd3aac062f", "user": {"_id": "65352acb7139c5dd8d9a8590", "avatarUrl": "/avatars/e2ff22b596aee45cdfb8f68dc15572f9.svg", "isPro": false, "fullname": "JiachengChen", "user": "JC-Chen", "type": "user", "name": "JC-Chen"}, "name": "Jiacheng Chen", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:56:48.931Z", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0630", "name": "Xinyu Zhang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0631", "name": "Shunkai Zhang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0632", "name": "Yanmohan Wang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0633", "name": "Lin Li", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0634", "name": "Tiancheng Qin", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0635", "name": "Qin Wang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0636", "name": "Zhengmao Zhu", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0637", "name": "Tianle Li", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0638", "name": "Jingyang Li", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0639", "name": "Zehan Li", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac063a", "name": "Binyang Jiang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac063b", "name": "Jin Zhu", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac063c", "name": "Han Ding", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac063d", "name": "Fei Yu", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac063e", "name": "Chenyu Du", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac063f", "name": "Zijian Song", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0640", "name": "Jiayuan Song", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0641", "name": "Zhi Zhang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0642", "name": "Yunan Huang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0643", "name": "Weiyu Cheng", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0644", "name": "Pengyu Zhao", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0645", "name": "Yu Cheng", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "MaxProof: Scaling Mathematical Proof with Generative-Verifier RL and Population-Level Test-Time Scaling", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "We present MaxProof, a population-level test-time scaling framework for competition-level mathematical proof in the MiniMax-M3 series. M3 first trains three proof-oriented capabilities -- proof generation, proof verification, and critique-conditioned proof repair -- using a defense-in-depth generative verifier engineered for low false-positive rate. These capabilities are merged into a single released M3 model. At test time, MaxProof treats the model as a generator, verifier, refiner, and ranker, searches over a population of candidate proofs, and returns one final proof through tournament selection. With MaxProof test-time scaling, the M3 model reaches 35/42 on IMO 2025 and 36/42 on USAMO 2026, exceeding the human gold-medal threshold on both.", "upvotes": 69, "discussionId": "6a2b6e314957fcdd3aac0646", "ai_summary": "MaxProof is a test-time scaling framework that enhances mathematical proof generation by combining multiple proof-oriented capabilities and using population-level search with tournament selection to achieve competitive performance on high-level mathematical competitions.", "ai_keywords": ["test-time scaling", "mathematical proof", "MiniMax-M3 series", "proof generation", "proof verification", "critique-conditioned proof repair", "generative verifier", "tournament selection"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "6778fc29920093dbc0c24917", "name": "MiniMaxAI", "fullname": "MiniMax", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/676e38ad04af5bec20bc9faf/dUd-LsZEX0H_d4qefO_g6.jpeg"}, "summary_zh": "<ul>\n    <li>MaxProof\u662f\u4e00\u79cd\u7528\u4e8e\u7ade\u8d5b\u7ea7\u6570\u5b66\u8bc1\u660e\u7684\u6d4b\u8bd5\u65f6\u95f4\u6269\u5c55\u6846\u67b6\u3002</li>\n    <li>M3\u6a21\u578b\u9996\u5148\u8bad\u7ec3\u4e86\u4e09\u79cd\u80fd\u529b\uff1a\u751f\u6210\u8bc1\u660e\u3001\u9a8c\u8bc1\u8bc1\u660e\u548c\u4fee\u590d\u8bc1\u660e\u3002</li>\n    <li>\u8fd9\u4e9b\u80fd\u529b\u5408\u5e76\u6210\u4e00\u4e2a\u6574\u4f53\u7684M3\u6a21\u578b\u53d1\u5e03\u3002</li>\n    <li>\u5728\u6d4b\u8bd5\u65f6\uff0cMaxProof\u5c06\u6a21\u578b\u7528\u4f5c\u751f\u6210\u5668\u3001\u9a8c\u8bc1\u5668\u3001\u4f18\u5316\u5668\u548c\u6392\u5e8f\u5668\uff0c\u9009\u62e9\u6700\u7ec8\u8bc1\u660e\u3002</li>\n    <li>\u4f7f\u7528MaxProof\uff0cM3\u6a21\u578b\u5728IMO 2025\u548cUSAMO 2026\u4e2d\u8d85\u8fc7\u4e86\u4eba\u7c7b\u91d1\u724c\u7684\u6807\u51c6\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>MaxProof is a new framework designed to improve mathematical proofs at a population level.</li>\n    <li>It combines three main skills: creating proofs, checking their correctness, and fixing any issues in the proofs.</li>\n    <li>The framework uses a special verifier that has a low chance of making mistakes.</li>\n    <li>During testing, MaxProof looks at many possible proofs and selects the best one using a tournament method.</li>\n    <li>With MaxProof, the M3 model performed very well, scoring above human experts in recent math competitions.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "MaxProof: Scaling Mathematical Proof with Generative-Verifier RL and Population-Level Test-Time Scaling", "summary": "We present MaxProof, a population-level test-time scaling framework for competition-level mathematical proof in the MiniMax-M3 series. M3 first trains three proof-oriented capabilities -- proof generation, proof verification, and critique-conditioned proof repair -- using a defense-in-depth generative verifier engineered for low false-positive rate. These capabilities are merged into a single released M3 model. At test time, MaxProof treats the model as a generator, verifier, refiner, and ranker, searches over a population of candidate proofs, and returns one final proof through tournament selection. With MaxProof test-time scaling, the M3 model reaches 35/42 on IMO 2025 and 36/42 on USAMO 2026, exceeding the human gold-medal threshold on both.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13473.png", "numComments": 0, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 316, "isUserFollowing": false}, "organization": {"_id": "6778fc29920093dbc0c24917", "name": "MiniMaxAI", "fullname": "MiniMax", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/676e38ad04af5bec20bc9faf/dUd-LsZEX0H_d4qefO_g6.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.09426", "authors": [{"_id": "6a277fef6dde1c5ef75bcf53", "user": {"_id": "6777886b8c91ac2d4b705eaf", "avatarUrl": "/avatars/ac27c6728d40edd724ce99cb8369808d.svg", "isPro": false, "fullname": "Wanli Li", "user": "wanlilll", "type": "user", "name": "wanlilll"}, "name": "Wanli Li", "status": "claimed_verified", "statusLastChangedAt": "2026-06-11T08:47:20.335Z", "hidden": false}, {"_id": "6a277fef6dde1c5ef75bcf54", "user": {"_id": "69271cf15181f68b030a2596", "avatarUrl": "/avatars/d64da217ce5a07f38494832e7b1679f8.svg", "isPro": false, "fullname": "wen", "user": "Wen36666", "type": "user", "name": "Wen36666"}, "name": "Bowen Zhou", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T07:49:04.234Z", "hidden": false}, {"_id": "6a277fef6dde1c5ef75bcf55", "name": "Yunyao Yu", "hidden": false}, {"_id": "6a277fef6dde1c5ef75bcf56", "name": "Zhou Xu", "hidden": false}, {"_id": "6a277fef6dde1c5ef75bcf57", "name": "Yifan Yang", "hidden": false}, {"_id": "6a277fef6dde1c5ef75bcf58", "name": "Dongsheng Li", "hidden": false}, {"_id": "6a277fef6dde1c5ef75bcf59", "name": "Caihua Shan", "hidden": false}], "publishedAt": "2026-06-08T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "WeaveBench: A Long-Horizon, Real-World Benchmark for Computer-Use Agents with Hybrid Interfaces", "submittedOnDailyBy": {"_id": "6777886b8c91ac2d4b705eaf", "avatarUrl": "/avatars/ac27c6728d40edd724ce99cb8369808d.svg", "isPro": false, "fullname": "Wanli Li", "user": "wanlilll", "type": "user", "name": "wanlilll"}, "summary": "Computer-use agents (CUAs) increasingly operate in runtimes that combine visual desktop control, command-line execution, code editing, browsers, and external tools. Existing benchmarks, however, often evaluate these interfaces as separable capabilities, leaving long-horizon cross-interface orchestration under-tested. Thus, we introduce WeaveBench, a long-horizon hybrid-interface benchmark with 114 tasks across 8 real-world work domains, grounded in real user requests and publicly verifiable artifacts. Each task requires agents to combine GUI observations/actions with CLI/code operations within a single trajectory. We evaluate these tasks on a real Ubuntu desktop inside deployed CLI-agent runtimes, augmented with a minimal desktop-control plugin. We also propose a companion trajectory-aware judge that inspects deliverables, files, screenshots, logs, and action traces, while detecting shortcut behaviors such as fabricated visual evidence or hard-coded metrics. Across frontier model-runtime pairings, the best PassRate reaches only 41.2%, showing the benchmark remains far from saturated. The trajectory-aware judge further reveals that outcome-only grading substantially overestimates agent performance. Overall, WeaveBench exposes a critical gap in CUA evaluation and provides an effective testbed to measure whether agents can orchestrate GUI, CLI, and code operations across long-horizon real-world tasks.", "upvotes": 55, "discussionId": "6a277ff06dde1c5ef75bcf5a", "projectPage": "https://weavebench.github.io/", "githubRepo": "https://github.com/weavebench/WeaveBench", "githubRepoAddedBy": "user", "ai_summary": "WeaveBench presents a comprehensive benchmark for evaluating computer-use agents across multiple interfaces, revealing significant challenges in long-horizon task orchestration and highlighting the limitations of traditional performance assessment methods.", "ai_keywords": ["computer-use agents", "hybrid-interface benchmark", "long-horizon tasks", "GUI observations", "CLI operations", "trajectory-aware judge", "agent performance evaluation", "real-world work domains", "desktop control plugin", "outcome-only grading"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 35, "organization": {"_id": "5e6485f787403103f9f1055e", "name": "microsoft", "fullname": "Microsoft", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1583646260758-5e64858c87403103f9f1055d.png"}, "summary_zh": "<ul>\n    <li>\u8ba1\u7b97\u673a\u4f7f\u7528\u4ee3\u7406\uff08CUAs\uff09\u5728\u7ed3\u5408\u89c6\u89c9\u684c\u9762\u63a7\u5236\u3001\u547d\u4ee4\u884c\u6267\u884c\u548c\u4ee3\u7801\u7f16\u8f91\u7684\u73af\u5883\u4e2d\u8fd0\u884c\u3002</li>\n    <li>\u73b0\u6709\u57fa\u51c6\u6d4b\u8bd5\u5e38\u5e38\u5c06\u8fd9\u4e9b\u754c\u9762\u89c6\u4e3a\u5206\u5f00\u7684\u80fd\u529b\uff0c\u5bfc\u81f4\u8de8\u754c\u9762\u534f\u8c03\u7684\u8bc4\u4f30\u4e0d\u8db3\u3002</li>\n    <li>WeaveBench\u662f\u4e00\u4e2a\u65b0\u7684\u57fa\u51c6\u6d4b\u8bd5\uff0c\u5305\u542b114\u4e2a\u4efb\u52a1\uff0c\u8986\u76d68\u4e2a\u771f\u5b9e\u5de5\u4f5c\u9886\u57df\uff0c\u57fa\u4e8e\u771f\u5b9e\u7528\u6237\u8bf7\u6c42\u3002</li>\n    <li>\u6bcf\u4e2a\u4efb\u52a1\u8981\u6c42\u4ee3\u7406\u5728\u540c\u4e00\u8fc7\u7a0b\u4e2d\u7ed3\u5408\u56fe\u5f62\u7528\u6237\u754c\u9762\uff08GUI\uff09\u548c\u547d\u4ee4\u884c\uff08CLI\uff09\u64cd\u4f5c\u3002</li>\n    <li>\u8be5\u57fa\u51c6\u6d4b\u8bd5\u63ed\u793a\u4e86CUA\u8bc4\u4f30\u4e2d\u7684\u91cd\u5927\u7f3a\u53e3\uff0c\u5e76\u63d0\u4f9b\u4e86\u4e00\u4e2a\u6709\u6548\u7684\u6d4b\u8bd5\u5e73\u53f0\u6765\u8861\u91cf\u4ee3\u7406\u5728\u5b9e\u9645\u4efb\u52a1\u4e2d\u534f\u8c03\u5404\u7c7b\u64cd\u4f5c\u7684\u80fd\u529b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>WeaveBench is a new benchmark designed to test computer-use agents (CUAs) on tasks that require using both graphical and command-line interfaces.</li>\n    <li>It includes 114 tasks from 8 real-world work areas and is based on actual user requests.</li>\n    <li>Each task needs agents to combine visual actions with code execution in one continuous process.</li>\n    <li>The benchmark shows that current agents are not performing well, with the best success rate only reaching 41.2%.</li>\n    <li>A new judging system evaluates tasks more thoroughly, revealing that simply measuring outcomes can give an inflated view of agent abilities.</li>\n</ul>"}, "publishedAt": "2026-06-07T20:00:00.000Z", "title": "WeaveBench: A Long-Horizon, Real-World Benchmark for Computer-Use Agents with Hybrid Interfaces", "summary": "Computer-use agents (CUAs) increasingly operate in runtimes that combine visual desktop control, command-line execution, code editing, browsers, and external tools. Existing benchmarks, however, often evaluate these interfaces as separable capabilities, leaving long-horizon cross-interface orchestration under-tested. Thus, we introduce WeaveBench, a long-horizon hybrid-interface benchmark with 114 tasks across 8 real-world work domains, grounded in real user requests and publicly verifiable artifacts. Each task requires agents to combine GUI observations/actions with CLI/code operations within a single trajectory. We evaluate these tasks on a real Ubuntu desktop inside deployed CLI-agent runtimes, augmented with a minimal desktop-control plugin. We also propose a companion trajectory-aware judge that inspects deliverables, files, screenshots, logs, and action traces, while detecting shortcut behaviors such as fabricated visual evidence or hard-coded metrics. Across frontier model-runtime pairings, the best PassRate reaches only 41.2%, showing the benchmark remains far from saturated. The trajectory-aware judge further reveals that outcome-only grading substantially overestimates agent performance. Overall, WeaveBench exposes a critical gap in CUA evaluation and provides an effective testbed to measure whether agents can orchestrate GUI, CLI, and code operations across long-horizon real-world tasks.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.09426.png", "numComments": 1, "submittedBy": {"_id": "6777886b8c91ac2d4b705eaf", "avatarUrl": "/avatars/ac27c6728d40edd724ce99cb8369808d.svg", "fullname": "Wanli Li", "name": "wanlilll", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 1, "isUserFollowing": false}, "organization": {"_id": "5e6485f787403103f9f1055e", "name": "microsoft", "fullname": "Microsoft", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1583646260758-5e64858c87403103f9f1055d.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.13578", "authors": [{"_id": "6a2b643d4957fcdd3aac05b8", "name": "Baochang Ren", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05b9", "name": "Xinjie Liu", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05ba", "name": "Xi Chen", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05bb", "name": "Yanshuo Liu", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05bc", "name": "Chenxi Li", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05bd", "name": "Daqi Gao", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05be", "name": "Zeqin Su", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05bf", "name": "Jintao Xing", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05c0", "name": "Zirui Xue", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05c1", "name": "Rui Li", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05c2", "name": "Xiangyu Zhao", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05c3", "name": "Shuofei Qiao", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05c4", "name": "Minting Pan", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05c5", "name": "Wangmeng Zuo", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05c6", "name": "Lei Bai", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05c7", "name": "Dongzhan Zhou", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05c8", "user": {"_id": "620b3bbb0668e435407c8d0a", "avatarUrl": "/avatars/e0fccbb2577d76088e09f054c35cffbc.svg", "isPro": false, "fullname": "Ningyu Zhang", "user": "Ningyu", "type": "user", "name": "Ningyu"}, "name": "Ningyu Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:58:01.389Z", "hidden": false}, {"_id": "6a2b643d4957fcdd3aac05c9", "name": "Huajun Chen", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "LabVLA: Grounding Vision-Language-Action Models in Scientific Laboratories", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Scientific laboratories increasingly rely on AI systems to reason about experiments, but the physical act of doing science remains largely outside their reach. AI can help read literature, generate hypotheses, and plan protocols, yet the execution of those protocols at the bench still requires a human operator. Vision-Language-Action (VLA) models provide one possible interface between written protocols and robot execution, but existing policies are trained mostly on household and tabletop demonstrations and rarely encounter the instruments, transparent liquids, or fixed protocol workflows found in scientific laboratories. Closing this gap requires both laboratory-specific supervision and a unified learning framework that can accommodate the diverse robot embodiments used to execute experimental protocols. We therefore identify data and embodiment as central bottlenecks alongside model design. To address the data side, we build RoboGenesis, a simulation-based workflow and data engine that composes configured laboratory workflows from atomic skills, validates and filters rollouts, and exports structured demonstrations across supported robot profiles. On the policy side, we present LabVLA, trained with a two-stage recipe: FAST action token pretraining first makes the Qwen3-VL-4B-Instruct backbone action aware before any continuous control is learned, and flow matching posttraining then attaches a DiT action expert under knowledge insulation. On the LabUtopia benchmark, LabVLA achieves the highest average success rate among all evaluated baselines under both in-distribution and out-of-distribution settings.", "upvotes": 50, "discussionId": "6a2b643e4957fcdd3aac05ca", "projectPage": "https://zjunlp.github.io/LabVLA/", "githubRepo": "https://github.com/zjunlp/LabVLA", "githubRepoAddedBy": "user", "ai_summary": "LabVLA, a vision-language-action model trained with a two-stage approach combining action token pretraining and flow matching, demonstrates superior performance on laboratory automation tasks through simulated data generation and robot-specific learning.", "ai_keywords": ["Vision-Language-Action models", "robotic execution", "laboratory workflows", "simulation-based workflow", "data engine", "LabVLA", "two-stage recipe", "FAST action token pretraining", "Qwen3-VL-4B-Instruct", "flow matching", "DiT action expert", "knowledge insulation", "LabUtopia benchmark"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 45, "summary_zh": "<ul>\n    <li>\u79d1\u5b66\u5b9e\u9a8c\u5ba4\u8d8a\u6765\u8d8a\u4f9d\u8d56\u4eba\u5de5\u667a\u80fd\u6765\u63a8\u7406\u5b9e\u9a8c\uff0c\u4f46\u5b9e\u9645\u64cd\u4f5c\u4ecd\u9700\u4eba\u7c7b\u5b8c\u6210\u3002</li>\n    <li>\u73b0\u6709\u7684AI\u6a21\u578b\u4e3b\u8981\u57fa\u4e8e\u5bb6\u5ead\u548c\u684c\u9762\u6f14\u793a\uff0c\u96be\u4ee5\u9002\u5e94\u5b9e\u9a8c\u5ba4\u7684\u4eea\u5668\u548c\u5de5\u4f5c\u6d41\u7a0b\u3002</li>\n    <li>\u4e3a\u4e86\u63d0\u9ad8AI\u7684\u5b9e\u9a8c\u5ba4\u5e94\u7528\uff0c\u9700\u8981\u9488\u5bf9\u5b9e\u9a8c\u5ba4\u7684\u76d1\u7763\u548c\u7edf\u4e00\u5b66\u4e60\u6846\u67b6\u3002</li>\n    <li>\u6211\u4eec\u5f00\u53d1\u4e86RoboGenesis\uff0c\u4e00\u4e2a\u57fa\u4e8e\u4eff\u771f\u7684\u5de5\u4f5c\u6d41\u7a0b\u548c\u6570\u636e\u5f15\u64ce\uff0c\u7528\u4e8e\u751f\u6210\u5b9e\u9a8c\u5ba4\u5de5\u4f5c\u6d41\u7a0b\u3002</li>\n    <li>LabVLA\u6a21\u578b\u5728LabUtopia\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u6700\u4f73\uff0c\u6210\u529f\u7387\u9ad8\u4e8e\u5176\u4ed6\u8bc4\u4f30\u6a21\u578b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>AI is increasingly used in scientific labs to help with tasks like reading literature and planning experiments, but humans still need to perform the actual experiments.</li>\n    <li>Vision-Language-Action (VLA) models can connect written protocols to robot actions, but they are not well-trained for scientific tasks.</li>\n    <li>To improve robot execution in labs, we need better training data and a unified learning approach for different robots.</li>\n    <li>We developed RoboGenesis, a system that creates and manages lab workflows and provides structured data for robots.</li>\n    <li>Our AI model, LabVLA, shows the best success rate in experiments, demonstrating its effectiveness in both standard and new lab settings.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "LabVLA: Grounding Vision-Language-Action Models in Scientific Laboratories", "summary": "Scientific laboratories increasingly rely on AI systems to reason about experiments, but the physical act of doing science remains largely outside their reach. AI can help read literature, generate hypotheses, and plan protocols, yet the execution of those protocols at the bench still requires a human operator. Vision-Language-Action (VLA) models provide one possible interface between written protocols and robot execution, but existing policies are trained mostly on household and tabletop demonstrations and rarely encounter the instruments, transparent liquids, or fixed protocol workflows found in scientific laboratories. Closing this gap requires both laboratory-specific supervision and a unified learning framework that can accommodate the diverse robot embodiments used to execute experimental protocols. We therefore identify data and embodiment as central bottlenecks alongside model design. To address the data side, we build RoboGenesis, a simulation-based workflow and data engine that composes configured laboratory workflows from atomic skills, validates and filters rollouts, and exports structured demonstrations across supported robot profiles. On the policy side, we present LabVLA, trained with a two-stage recipe: FAST action token pretraining first makes the Qwen3-VL-4B-Instruct backbone action aware before any continuous control is learned, and flow matching posttraining then attaches a DiT action expert under knowledge insulation. On the LabUtopia benchmark, LabVLA achieves the highest average success rate among all evaluated baselines under both in-distribution and out-of-distribution settings.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13578.png", "numComments": 1, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 316, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.13289", "authors": [{"_id": "6a2bc498ca6c5360cc7cfa82", "name": "Guozhen Zhang", "hidden": false}, {"_id": "6a2bc498ca6c5360cc7cfa83", "name": "Xuerui Qiu", "hidden": false}, {"_id": "6a2bc498ca6c5360cc7cfa84", "name": "Yutao Cui", "hidden": false}, {"_id": "6a2bc498ca6c5360cc7cfa85", "name": "Tianhui Song", "hidden": false}, {"_id": "6a2bc498ca6c5360cc7cfa86", "name": "Changlin Li", "hidden": false}, {"_id": "6a2bc498ca6c5360cc7cfa87", "name": "Junzhe Li", "hidden": false}, {"_id": "6a2bc498ca6c5360cc7cfa88", "name": "Tao Huang", "hidden": false}, {"_id": "6a2bc498ca6c5360cc7cfa89", "name": "Xiao Zhang", "hidden": false}, {"_id": "6a2bc498ca6c5360cc7cfa8a", "name": "Yang Li", "hidden": false}, {"_id": "6a2bc498ca6c5360cc7cfa8b", "name": "Jianbing Wu", "hidden": false}, {"_id": "6a2bc498ca6c5360cc7cfa8c", "name": "Miles Yang", "hidden": false}, {"_id": "6a2bc498ca6c5360cc7cfa8d", "name": "Zhao Zhong", "hidden": false}, {"_id": "6a2bc498ca6c5360cc7cfa8e", "name": "Liefeng Bo", "hidden": false}, {"_id": "6a2bc498ca6c5360cc7cfa8f", "name": "Limin Wang", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6684152a443492c24cdac044/uyQ5ja30uT_DAp9cvnpDO.png"], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "HYDRA-X: Native Unified Multimodal Models with Holistic Visual Tokenizers", "submittedOnDailyBy": {"_id": "6684152a443492c24cdac044", "avatarUrl": "/avatars/1d5abbde12a808aa743769603e494ddb.svg", "isPro": false, "fullname": "Guozhen Zhang", "user": "zgzaacm", "type": "user", "name": "zgzaacm"}, "summary": "Holistic visual tokenizers are fundamental to unified multimodal models (UMMs) as they map diverse visual inputs into a unified representation space. In this paper, we present HYDRA-X, the first UMM that unifies image and video tokenization within a single Vision Transformer (ViT). Our design is driven by two core challenges: efficiently injecting spatiotemporal reconstruction capability into a native ViT, and embedding image- and video-level semantic awareness into the latent space. To address the first, comprehensive ablations reveal two key findings: (1) frame-level causal temporal attention suffices for visual reconstruction, whereas full spatiotemporal attention degrades it; and (2) hierarchical temporal compression substantially outperforms single-step alternatives. To tackle the second, we propose a lightweight decompressor that upsamples temporally compressed features under joint image-video teacher supervision, thereby enforcing complementary semantic structures within the compact latent space. Building on this holistic tokenizer, we further propose a principled improvement of the editing pipeline: source-target interaction should occur at the latent level inside the tokenizer rather than at the semantic level inside the LLM, substantially improving editing consistency and accelerating convergence. Instantiated at the 7B dense model, HYDRA-X achieves strong performance across image and video understanding and generation tasks, paving the way for future unified-tokenizer UMMs.", "upvotes": 24, "discussionId": "6a2bc499ca6c5360cc7cfa90", "ai_summary": "HYDRA-X presents a unified multimodal model that integrates image and video tokenization within a single Vision Transformer, addressing spatiotemporal reconstruction and semantic awareness through causal temporal attention and hierarchical compression.", "ai_keywords": ["Vision Transformer", "spatiotemporal reconstruction", "causal temporal attention", "hierarchical temporal compression", "latent space", "decompressor", "teacher supervision", "unified multimodal models", "visual tokenizers"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "6314524a5f47a1896274d586", "name": "NJU", "fullname": "Nanjing University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1662276136108-6314518e5f47a1896274d080.jpeg"}, "summary_zh": "<ul>\n    <li>HYDRA-X\u662f\u9996\u4e2a\u5c06\u56fe\u50cf\u548c\u89c6\u9891\u6807\u8bb0\u7edf\u4e00\u5728\u5355\u4e00\u89c6\u89c9\u8f6c\u6362\u5668\u4e2d\u7684\u7edf\u4e00\u591a\u6a21\u6001\u6a21\u578b\u3002</li>\n    <li>\u8be5\u6a21\u578b\u89e3\u51b3\u4e86\u5728\u89c6\u89c9\u8f6c\u6362\u5668\u4e2d\u9ad8\u6548\u6ce8\u5165\u65f6\u7a7a\u91cd\u5efa\u80fd\u529b\u548c\u5d4c\u5165\u56fe\u50cf\u4e0e\u89c6\u9891\u8bed\u4e49\u610f\u8bc6\u7684\u4e24\u4e2a\u6838\u5fc3\u6311\u6218\u3002</li>\n    <li>\u7814\u7a76\u53d1\u73b0\uff0c\u5e27\u7ea7\u56e0\u679c\u65f6\u5e8f\u6ce8\u610f\u529b\u8db3\u591f\u8fdb\u884c\u89c6\u89c9\u91cd\u5efa\uff0c\u800c\u5168\u65f6\u7a7a\u6ce8\u610f\u529b\u4f1a\u964d\u4f4e\u6027\u80fd\u3002</li>\n    <li>\u63d0\u51fa\u4e86\u4e00\u79cd\u8f7b\u91cf\u7ea7\u89e3\u538b\u5668\uff0c\u80fd\u591f\u5728\u56fe\u50cf\u548c\u89c6\u9891\u7684\u8054\u5408\u6559\u5e08\u76d1\u7763\u4e0b\u63d0\u5347\u65f6\u5e8f\u538b\u7f29\u7279\u5f81\u3002</li>\n    <li>HYDRA-X\u5728\u56fe\u50cf\u548c\u89c6\u9891\u7406\u89e3\u53ca\u751f\u6210\u4efb\u52a1\u4e2d\u8868\u73b0\u4f18\u5f02\uff0c\u4e3a\u672a\u6765\u7684\u7edf\u4e00\u6807\u8bb0\u5668\u591a\u6a21\u6001\u6a21\u578b\u5960\u5b9a\u57fa\u7840\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>HYDRA-X is a new model that combines image and video processing using a single Vision Transformer (ViT).</li>\n    <li>It addresses key challenges like enhancing visual reconstruction and understanding both images and videos.</li>\n    <li>Findings show that using frame-level attention is better for reconstruction than full attention, and hierarchical compression works better than simpler methods.</li>\n    <li>The model includes a decompressor that improves feature quality by using guidance from both images and videos.</li>\n    <li>HYDRA-X shows strong results in tasks involving image and video understanding and generation, setting the stage for future developments in unified models.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "HYDRA-X: Native Unified Multimodal Models with Holistic Visual Tokenizers", "summary": "Holistic visual tokenizers are fundamental to unified multimodal models (UMMs) as they map diverse visual inputs into a unified representation space. In this paper, we present HYDRA-X, the first UMM that unifies image and video tokenization within a single Vision Transformer (ViT). Our design is driven by two core challenges: efficiently injecting spatiotemporal reconstruction capability into a native ViT, and embedding image- and video-level semantic awareness into the latent space. To address the first, comprehensive ablations reveal two key findings: (1) frame-level causal temporal attention suffices for visual reconstruction, whereas full spatiotemporal attention degrades it; and (2) hierarchical temporal compression substantially outperforms single-step alternatives. To tackle the second, we propose a lightweight decompressor that upsamples temporally compressed features under joint image-video teacher supervision, thereby enforcing complementary semantic structures within the compact latent space. Building on this holistic tokenizer, we further propose a principled improvement of the editing pipeline: source-target interaction should occur at the latent level inside the tokenizer rather than at the semantic level inside the LLM, substantially improving editing consistency and accelerating convergence. Instantiated at the 7B dense model, HYDRA-X achieves strong performance across image and video understanding and generation tasks, paving the way for future unified-tokenizer UMMs.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6684152a443492c24cdac044/uyQ5ja30uT_DAp9cvnpDO.png"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13289.png", "numComments": 1, "submittedBy": {"_id": "6684152a443492c24cdac044", "avatarUrl": "/avatars/1d5abbde12a808aa743769603e494ddb.svg", "fullname": "Guozhen Zhang", "name": "zgzaacm", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3, "isUserFollowing": false}, "organization": {"_id": "6314524a5f47a1896274d586", "name": "NJU", "fullname": "Nanjing University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1662276136108-6314518e5f47a1896274d080.jpeg"}, "isAuthorParticipating": false}],
    "week": [{"paper": {"id": "2606.10651", "authors": [{"_id": "6a28cfb8e7d78ea7587e5406", "name": "Kwai Keye Team", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5407", "name": "Bin Wen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5408", "name": "Changyi Liu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5409", "name": "Chengru Song", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540a", "name": "Chongling Rao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540b", "name": "Guowang Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540c", "name": "Han Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540d", "name": "Haonan Fan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540e", "name": "Hengrui Ju", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540f", "name": "Jiankang Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5410", "name": "Jiapeng Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5411", "name": "Jiawei Yuan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5412", "name": "Kaixuan Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5413", "name": "Kaiyu Jiang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5414", "name": "Kun Gai", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5415", "name": "Lingzhi Zhou", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5416", "name": "Na Nie", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5417", "name": "Sen Na", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5418", "name": "Tianke Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5419", "name": "Tingting Gao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541a", "name": "Xuanyu Zheng", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541b", "name": "Yulong Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541c", "name": "Fan Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541d", "name": "Haixuan Gao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541e", "name": "Lele Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541f", "name": "Mingqiao Liu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5420", "name": "Muxi Diao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5421", "name": "Qi Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5422", "name": "Qile Su", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5423", "name": "Wei Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5424", "name": "Wentao Hong", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5425", "name": "Xingyu Lu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5426", "name": "Yancheng Long", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5427", "name": "Yankai Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5428", "name": "Yingxin Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5429", "name": "Yiyang Fan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542a", "name": "Yu Xia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542b", "name": "Yuzhe Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542c", "name": "Ziliang Lai", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542d", "name": "Chuan Yi", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542e", "name": "Haonan Jia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542f", "name": "Tianming Liang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5430", "name": "Weixin Xu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5431", "name": "Xiaoxiao Ma", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5432", "name": "Yang Tian", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5433", "name": "Yufei Han", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5434", "name": "Feng Han", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5435", "name": "Hang Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5436", "name": "Jing Wang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5437", "name": "Jinghui Jia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5438", "name": "Junmin Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5439", "name": "Junyu Shi", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e543a", "name": "Ruilin Zhang", "hidden": false}], "publishedAt": "2026-06-09T00:00:00.000Z", "submittedOnDailyAt": "2026-06-10T00:00:00.000Z", "title": "Kwai Keye-VL-2.0 Technical Report", "submittedOnDailyBy": {"_id": "66c98c27fafc0fc87c280749", "avatarUrl": "/avatars/c71db3bee0fcd9aabcc38fd871d1cb75.svg", "isPro": false, "fullname": "Tianming Liang", "user": "liangtm", "type": "user", "name": "liangtm"}, "summary": "We introduce Kwai Keye-VL-2.0-30B-A3B, an open-source Mixture-of-Experts (MoE) multimodal foundation model designed to advance long-video understanding and agentic intelligence. To address the challenges of ultra-long contexts, information redundancy, and prohibitive computational costs inherent in hour-level videos, Keye-VL-2.0 is the first to adapt DeepSeek Sparse Attention (DSA) to GQA-based multimodal architectures, enabling lossless 256K context processing while capturing critical frames and long-range temporal dependencies. This architecture is underpinned by a highly optimized training and inference infrastructure, including scalable video I/O, heterogeneous ViT-LM parallelism, and custom DSA kernels that significantly maximize throughput and minimize computational overhead. Furthermore, to overcome the algorithmic dilemma of catastrophic forgetting during multi-task alignment, we introduce Cross-Modal Multi-Teacher On-Policy Distillation (MOPD) paired with Context-RL and Video-RL. By distilling dense token-level teacher feedback from on-policy rollouts back into the MoE backbone, which activates only 3B parameters, Keye-VL-2.0 natively empowers advanced agent collaboration across Code, Tool, and Search scenarios with multimodal self-correction. Extensive evaluations across video understanding, temporal grounding, reasoning, STEM, and agent benchmarks demonstrate that Keye-VL-2.0-30B-A3B achieves state-of-the-art performance among models of similar scale, particularly excelling in fine-grained temporal localization on TimeLens and long-video comprehension on Video-MME-v2 and LongVideoBench. We release our model checkpoints to accelerate community progress toward scalable and robust multimodal agentic applications.", "upvotes": 167, "discussionId": "6a28cfb8e7d78ea7587e543b", "projectPage": "https://kwai-keye.github.io/", "githubRepo": "https://github.com/Kwai-Keye/Keye", "githubRepoAddedBy": "user", "ai_summary": "Kwai Keye-VL-2.0-30B-A3B is an open-source Mixture-of-Experts multimodal foundation model that enables long-video understanding and agentic intelligence through DeepSeek Sparse Attention and specialized training infrastructure.", "ai_keywords": ["Mixture-of-Experts", "multimodal foundation model", "DeepSeek Sparse Attention", "GQA-based architectures", "256K context processing", "heterogeneous ViT-LM parallelism", "custom DSA kernels", "Cross-Modal Multi-Teacher On-Policy Distillation", "Context-RL", "Video-RL", "dense token-level teacher feedback", "on-policy rollouts", "agent collaboration", "Code", "Tool", "Search scenarios", "multimodal self-correction"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 785, "organization": {"_id": "685d2e9b7aa0388f4fcaf7b2", "name": "KwaiKeye", "fullname": "Kwai Keye", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/685ba798484e3233f5ff6f11/gW0pROtvsWctypxYTBbWZ.png"}, "summary_zh": "<ul>\n    <li>\u6211\u4eec\u4ecb\u7ecd\u4e86Kwai Keye-VL-2.0-30B-A3B\uff0c\u8fd9\u662f\u4e00\u4e2a\u5f00\u6e90\u7684\u591a\u6a21\u6001\u57fa\u7840\u6a21\u578b\uff0c\u65e8\u5728\u63d0\u9ad8\u5bf9\u957f\u89c6\u9891\u7684\u7406\u89e3\u548c\u667a\u80fd\u4ee3\u7406\u80fd\u529b\u3002</li>\n    <li>\u8be5\u6a21\u578b\u91c7\u7528\u4e86DeepSeek\u7a00\u758f\u6ce8\u610f\u529b\u673a\u5236\uff0c\u80fd\u591f\u5904\u7406256K\u4e0a\u4e0b\u6587\u4fe1\u606f\uff0c\u5e76\u6355\u6349\u91cd\u8981\u5e27\u548c\u957f\u65f6\u95f4\u7684\u4f9d\u8d56\u5173\u7cfb\u3002</li>\n    <li>Keye-VL-2.0\u5177\u6709\u4f18\u5316\u7684\u8bad\u7ec3\u548c\u63a8\u7406\u57fa\u7840\u8bbe\u65bd\uff0c\u652f\u6301\u53ef\u6269\u5c55\u7684\u89c6\u9891\u8f93\u5165\u8f93\u51fa\u548c\u9ad8\u6548\u7684\u5e76\u884c\u5904\u7406\u3002</li>\n    <li>\u4e3a\u4e86\u89e3\u51b3\u591a\u4efb\u52a1\u5bf9\u9f50\u4e2d\u7684\u9057\u5fd8\u95ee\u9898\uff0c\u6a21\u578b\u5f15\u5165\u4e86\u8de8\u6a21\u6001\u591a\u6559\u5e08\u5728\u7ebf\u84b8\u998f\u6280\u672f\uff0c\u53ef\u4ee5\u63d0\u9ad8\u591a\u6a21\u6001\u81ea\u6211\u4fee\u6b63\u80fd\u529b\u3002</li>\n    <li>\u5728\u591a\u4e2a\u89c6\u9891\u7406\u89e3\u548c\u667a\u80fd\u4ee3\u7406\u7684\u57fa\u51c6\u6d4b\u8bd5\u4e2d\uff0cKeye-VL-2.0\u8868\u73b0\u4f18\u5f02\uff0c\u5c24\u5176\u5728\u957f\u89c6\u9891\u7406\u89e3\u65b9\u9762\u8fbe\u5230\u4e86\u884c\u4e1a\u9886\u5148\u6c34\u5e73\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Kwai Keye-VL-2.0-30B-A3B is an open-source model that helps understand long videos and improve intelligent agents.</li>\n    <li>It uses a special attention technique to handle very long video contexts without losing important information.</li>\n    <li>The model is built with efficient training methods to reduce computing costs and improve performance.</li>\n    <li>It includes a new way to prevent loss of information when learning multiple tasks, enhancing collaboration between different tools and codes.</li>\n    <li>Keye-VL-2.0 shows top performance in video understanding and other tasks, and the team is sharing the model to help others in the field.</li>\n</ul>"}, "publishedAt": "2026-06-08T20:00:00.000Z", "title": "Kwai Keye-VL-2.0 Technical Report", "summary": "We introduce Kwai Keye-VL-2.0-30B-A3B, an open-source Mixture-of-Experts (MoE) multimodal foundation model designed to advance long-video understanding and agentic intelligence. To address the challenges of ultra-long contexts, information redundancy, and prohibitive computational costs inherent in hour-level videos, Keye-VL-2.0 is the first to adapt DeepSeek Sparse Attention (DSA) to GQA-based multimodal architectures, enabling lossless 256K context processing while capturing critical frames and long-range temporal dependencies. This architecture is underpinned by a highly optimized training and inference infrastructure, including scalable video I/O, heterogeneous ViT-LM parallelism, and custom DSA kernels that significantly maximize throughput and minimize computational overhead. Furthermore, to overcome the algorithmic dilemma of catastrophic forgetting during multi-task alignment, we introduce Cross-Modal Multi-Teacher On-Policy Distillation (MOPD) paired with Context-RL and Video-RL. By distilling dense token-level teacher feedback from on-policy rollouts back into the MoE backbone, which activates only 3B parameters, Keye-VL-2.0 natively empowers advanced agent collaboration across Code, Tool, and Search scenarios with multimodal self-correction. Extensive evaluations across video understanding, temporal grounding, reasoning, STEM, and agent benchmarks demonstrate that Keye-VL-2.0-30B-A3B achieves state-of-the-art performance among models of similar scale, particularly excelling in fine-grained temporal localization on TimeLens and long-video comprehension on Video-MME-v2 and LongVideoBench. We release our model checkpoints to accelerate community progress toward scalable and robust multimodal agentic applications.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.10651.png", "numComments": 1, "submittedBy": {"_id": "66c98c27fafc0fc87c280749", "avatarUrl": "/avatars/c71db3bee0fcd9aabcc38fd871d1cb75.svg", "fullname": "Tianming Liang", "name": "liangtm", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "685d2e9b7aa0388f4fcaf7b2", "name": "KwaiKeye", "fullname": "Kwai Keye", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/685ba798484e3233f5ff6f11/gW0pROtvsWctypxYTBbWZ.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.13681", "authors": [{"_id": "6a2b77ca4957fcdd3aac06a4", "user": {"_id": "67580d23f498e0436ce182fb", "avatarUrl": "/avatars/696d1c91dbd43d267747d7e98af096bd.svg", "isPro": false, "fullname": "Jundong Xu", "user": "Aiden0526", "type": "user", "name": "Aiden0526"}, "name": "Jundong Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:56:31.093Z", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a5", "name": "Qingchuan Li", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a6", "name": "Jiaying Wu", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a7", "name": "Yihuai Lan", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a8", "name": "Shuyue Stella Li", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a9", "name": "Huichi Zhou", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06aa", "name": "Bowen Jiang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ab", "name": "Lei Wang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ac", "name": "Jun Wang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ad", "name": "Anh Tuan Luu", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ae", "name": "Caiming Xiong", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06af", "name": "Hae Won Park", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06b0", "name": "Bryan Hooi", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06b1", "name": "Zhiyuan Hu", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "EvoArena: Tracking Memory Evolution for Robust LLM Agents in Dynamic Environments", "submittedOnDailyBy": {"_id": "64351475901c5734bcb64248", "avatarUrl": "/avatars/12346d4301c1bfb00ce0ea128a93cc15.svg", "isPro": false, "fullname": "Zhiyuan Hu", "user": "zhiyuanhucs", "type": "user", "name": "zhiyuanhucs"}, "summary": "Large language model (LLM) agents have achieved strong performance on a wide range of benchmarks, yet most evaluations assume static environments. In contrast, real-world deployment is inherently dynamic, requiring agents to continually align their knowledge, skills, and behavior with changing environments and updated task conditions. To address this gap, we introduce EvoArena, a benchmark suite that models environment changes as sequences of progressive updates across terminal, software, and social domains. We further propose EvoMem, a patch-based memory paradigm that records memory evolution as structured update histories, enabling agents to reason about environmental evolution through changes in their memory. Experiments show that current agents struggle on EvoArena, achieving an average accuracy of 39.6% across evolving terminal, software, and social-preference domains. EvoMem consistently improves performance, yielding an average gain of 1.5% on EvoArena and also improving standard benchmarks such as GAIA and LoCoMo by 6.1% and 4.8%. Beyond individual tasks, EvoMem further improves chain-level accuracy by 3.7% on EvoArena, where success requires completing a consecutive sequence of related evolutionary subtasks. Mechanistic analysis shows that EvoMem improves evidence capture in the memory, indicating better preservation of complete evolving environment states. Our results highlight the importance of modeling evolution in both evaluation and memory for reliable agent deployment.", "upvotes": 104, "discussionId": "6a2b77ca4957fcdd3aac06b2", "projectPage": "https://aiden0526.github.io/EvoArena/", "githubRepo": "https://github.com/Aiden0526/EvoArena", "githubRepoAddedBy": "user", "ai_summary": "EvoArena benchmark and EvoMem memory paradigm address the challenge of dynamic environments in LLM agents by modeling progressive updates and structured memory evolution, showing improved performance on evolving tasks.", "ai_keywords": ["large language model agents", "EvoArena", "EvoMem", "memory evolution", "environment changes", "progressive updates", "terminal domain", "software domain", "social domain", "chain-level accuracy", "mechanistic analysis"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 8, "organization": {"_id": "63728bde14d543d507ae970d", "name": "MIT", "fullname": "Massachusetts Institute of Technology", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/S90qoeEJeEYaYf-c7Zs8g.png"}, "summary_zh": "<ul>\n    <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLM\uff09\u5728\u8bb8\u591a\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u51fa\u8272\uff0c\u4f46\u5927\u90e8\u5206\u8bc4\u4f30\u5047\u8bbe\u73af\u5883\u662f\u9759\u6001\u7684\u3002</li>\n    <li>\u73b0\u5b9e\u4e16\u754c\u662f\u52a8\u6001\u7684\uff0c\u4ee3\u7406\u9700\u8981\u4e0d\u65ad\u8c03\u6574\u77e5\u8bc6\u548c\u6280\u80fd\u4ee5\u9002\u5e94\u73af\u5883\u53d8\u5316\u3002</li>\n    <li>\u6211\u4eec\u63a8\u51fa\u4e86EvoArena\u57fa\u51c6\uff0c\u6a21\u62df\u73af\u5883\u53d8\u5316\u4e3a\u4e00\u7cfb\u5217\u9010\u6b65\u66f4\u65b0\uff0c\u6db5\u76d6\u7ec8\u7aef\u3001\u8f6f\u4ef6\u548c\u793e\u4ea4\u9886\u57df\u3002</li>\n    <li>\u6211\u4eec\u8fd8\u63d0\u51fa\u4e86EvoMem\u8bb0\u5fc6\u6a21\u578b\uff0c\u8bb0\u5f55\u8bb0\u5fc6\u6f14\u53d8\uff0c\u5e2e\u52a9\u4ee3\u7406\u7406\u89e3\u73af\u5883\u53d8\u5316\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u5f53\u524d\u4ee3\u7406\u5728EvoArena\u4e0a\u7684\u8868\u73b0\u8f83\u5dee\uff0cEvoMem\u5219\u80fd\u63d0\u5347\u5176\u8868\u73b0\u548c\u51c6\u786e\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Large language model agents perform well in tests but struggle in changing real-world situations.</li>\n    <li>EvoArena is a new benchmark that simulates changing environments through progressive updates in different domains.</li>\n    <li>EvoMem is a memory system that helps agents track and learn from these changes over time.</li>\n    <li>Current agents only achieve about 39.6% accuracy on EvoArena, but EvoMem boosts their performance by an average of 1.5%.</li>\n    <li>Using EvoMem also improves performance on other standard tests and helps agents better capture and remember evolving states.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "EvoArena: Tracking Memory Evolution for Robust LLM Agents in Dynamic Environments", "summary": "Large language model (LLM) agents have achieved strong performance on a wide range of benchmarks, yet most evaluations assume static environments. In contrast, real-world deployment is inherently dynamic, requiring agents to continually align their knowledge, skills, and behavior with changing environments and updated task conditions. To address this gap, we introduce EvoArena, a benchmark suite that models environment changes as sequences of progressive updates across terminal, software, and social domains. We further propose EvoMem, a patch-based memory paradigm that records memory evolution as structured update histories, enabling agents to reason about environmental evolution through changes in their memory. Experiments show that current agents struggle on EvoArena, achieving an average accuracy of 39.6% across evolving terminal, software, and social-preference domains. EvoMem consistently improves performance, yielding an average gain of 1.5% on EvoArena and also improving standard benchmarks such as GAIA and LoCoMo by 6.1% and 4.8%. Beyond individual tasks, EvoMem further improves chain-level accuracy by 3.7% on EvoArena, where success requires completing a consecutive sequence of related evolutionary subtasks. Mechanistic analysis shows that EvoMem improves evidence capture in the memory, indicating better preservation of complete evolving environment states. Our results highlight the importance of modeling evolution in both evaluation and memory for reliable agent deployment.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13681.png", "numComments": 1, "submittedBy": {"_id": "64351475901c5734bcb64248", "avatarUrl": "/avatars/12346d4301c1bfb00ce0ea128a93cc15.svg", "fullname": "Zhiyuan Hu", "name": "zhiyuanhucs", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 7, "isUserFollowing": false}, "organization": {"_id": "63728bde14d543d507ae970d", "name": "MIT", "fullname": "Massachusetts Institute of Technology", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/S90qoeEJeEYaYf-c7Zs8g.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.13392", "authors": [{"_id": "6a2b99244957fcdd3aac0762", "user": {"_id": "670a145e4bea0a5a62535e80", "avatarUrl": "/avatars/231d61a46c7182384814f2a13a339054.svg", "isPro": false, "fullname": "Xunhao Lai", "user": "Xunhaolai", "type": "user", "name": "Xunhaolai"}, "name": "Xunhao Lai", "status": "admin_assigned", "statusLastChangedAt": "2026-06-12T14:08:46.132Z", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0763", "user": {"_id": "66b1ab0e180542df6bb13038", "avatarUrl": "/avatars/70dacb6043aa9edf8967096f4cfcc068.svg", "isPro": false, "fullname": "weiqi xu", "user": "xiaoxiaoOWO", "type": "user", "name": "xiaoxiaoOWO"}, "name": "Weiqi Xu", "status": "admin_assigned", "statusLastChangedAt": "2026-06-12T14:08:55.187Z", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0764", "name": "Yufeng Yang", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0765", "name": "Qiaorui Chen", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0766", "name": "Yang Xu", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0767", "user": {"_id": "6375dfa7f9aafd41ce145254", "avatarUrl": "/avatars/19e7460dd7ea6c60e1c52d5707660cc8.svg", "isPro": false, "fullname": "Lunbin Zeng", "user": "xiazhi", "type": "user", "name": "xiazhi"}, "name": "Lunbin Zeng", "status": "admin_assigned", "statusLastChangedAt": "2026-06-12T14:09:08.225Z", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0768", "name": "Xiaolong Li", "hidden": false}, {"_id": "6a2b99244957fcdd3aac0769", "user": {"_id": "64b76660f92b20f7a37c3df7", "avatarUrl": "/avatars/40158717bb9370f1e5d0ed156a6fed1f.svg", "isPro": false, "fullname": "HaohaiSun", "user": "HaohaiSun", "type": "user", "name": "HaohaiSun"}, "name": "Haohai Sun", "status": "admin_assigned", "statusLastChangedAt": "2026-06-12T14:10:07.960Z", "hidden": false}, {"_id": "6a2b99244957fcdd3aac076a", "name": "Haichao Zhu", "hidden": false}, {"_id": "6a2b99244957fcdd3aac076b", "name": "Vito Zhang", "hidden": false}, {"_id": "6a2b99244957fcdd3aac076c", "name": "Pengyu Zhao", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "MiniMax Sparse Attention", "submittedOnDailyBy": {"_id": "673463f29cb2775fbe62a626", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/673463f29cb2775fbe62a626/64k_zEitiRQD_U002ojyy.jpeg", "isPro": false, "fullname": "Ryanlee", "user": "ryanlee-dev", "type": "user", "name": "ryanlee-dev"}, "summary": "Ultra-long-context capability is becoming indispensable for frontier LLMs: agentic workflows, repository-scale code reasoning, and persistent memory all require the model to jointly attend over hundreds of thousands to millions of tokens, yet the quadratic cost of softmax attention makes this untenable at deployment scale. We introduce MiniMax Sparse Attention (MSA), a blockwise sparse attention built upon Grouped Query Attention (GQA). A lightweight Index Branch scores key-value blocks and independently selects a Top-k subset for each GQA group, enabling group-specific sparse retrieval while maintaining efficient block-level execution; the Main Branch then performs exact block-sparse attention over only the selected blocks. Designed around a principle of simplicity and scalability, MSA is deliberately streamlined, making it straightforward to deploy efficiently across a broad range of GPUs. To translate sparsity into practical speedups, we co-design MSA with a GPU execution path that uses exp-free Top-k selection and KV-outer sparse attention to improve tensor-core utilization under block-granular access. On a 109B-parameter model with native multimodal training, MSA performs on par with GQA while reducing per-token attention compute by 28.4x at 1M context. Paired with our co-designed kernel, MSA achieves 14.2x prefill and 7.6x decoding wall-clock speedups on H800. Our inference kernel is available at: https://github.com/MiniMax-AI/MSA. A production-grade natively multimodal model powered by MSA has been publicly released at: https://huggingface.co/MiniMaxAI/MiniMax-M3.", "upvotes": 82, "discussionId": "6a2b99244957fcdd3aac076d", "githubRepo": "https://github.com/MiniMax-AI/MSA", "githubRepoAddedBy": "user", "ai_summary": "MiniMax Sparse Attention enables efficient processing of ultra-long contexts in large language models through blockwise sparsity and optimized GPU execution, achieving significant speedups while maintaining performance.", "ai_keywords": ["sparse attention", "Grouped Query Attention", "Top-k selection", "blockwise sparse attention", "tensor-core utilization", "prefill", "decoding", "attention compute", "context length"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 184, "organization": {"_id": "6778fc29920093dbc0c24917", "name": "MiniMaxAI", "fullname": "MiniMax", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/676e38ad04af5bec20bc9faf/dUd-LsZEX0H_d4qefO_g6.jpeg"}, "summary_zh": "<ul>\n    <li>\u8d85\u957f\u4e0a\u4e0b\u6587\u5904\u7406\u80fd\u529b\u5bf9\u4e8e\u524d\u6cbf\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLMs\uff09\u53d8\u5f97\u4e0d\u53ef\u6216\u7f3a\u3002</li>\n    <li>\u4ecb\u7ecd\u4e86\u4e00\u79cd\u540d\u4e3a\u8ff7\u4f60\u6700\u5927\u7a00\u758f\u6ce8\u610f\u529b\uff08MSA\uff09\u7684\u65b0\u65b9\u6cd5\uff0c\u53ef\u4ee5\u6709\u6548\u5904\u7406\u5927\u91cf\u4ee3\u5e01\u3002</li>\n    <li>MSA \u901a\u8fc7\u8f7b\u91cf\u7ea7\u7d22\u5f15\u5206\u652f\u548c\u4e3b\u5206\u652f\u7684\u8bbe\u8ba1\uff0c\u5b9e\u73b0\u4e86\u9ad8\u6548\u7684\u7a00\u758f\u68c0\u7d22\u548c\u8ba1\u7b97\u3002</li>\n    <li>\u5728109B\u53c2\u6570\u7684\u6a21\u578b\u4e0a\uff0cMSA\u7684\u6bcf\u4e2a\u4ee3\u5e01\u6ce8\u610f\u529b\u8ba1\u7b97\u51cf\u5c11\u4e8628.4\u500d\u3002</li>\n    <li>MSA\u7684\u63a8\u7406\u5185\u6838\u548c\u57fa\u4e8e\u6b64\u7684\u591a\u6a21\u6001\u6a21\u578b\u5df2\u516c\u5f00\u53d1\u5e03\uff0c\u63d0\u4f9b\u4e86\u66f4\u5feb\u7684\u63a8\u7406\u901f\u5ea6\u3002</li>\n</ul>", "summary_simple": "<ul>\n  <li>Ultra-long-context capability is essential for advanced language models (LLMs) to handle large amounts of data effectively.</li>\n  <li>MiniMax Sparse Attention (MSA) is a new method that improves how these models manage attention over many tokens without excessive computational costs.</li>\n  <li>MSA uses a two-part system to select and handle only the most relevant pieces of data, making it more efficient for processing.</li>\n  <li>This method significantly speeds up the model's performance, achieving large reductions in the time and resources needed for attention calculations.</li>\n  <li>A multimodal model using MSA has been released, showcasing its effectiveness and efficiency in practical applications.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "MiniMax Sparse Attention", "summary": "Ultra-long-context capability is becoming indispensable for frontier LLMs: agentic workflows, repository-scale code reasoning, and persistent memory all require the model to jointly attend over hundreds of thousands to millions of tokens, yet the quadratic cost of softmax attention makes this untenable at deployment scale. We introduce MiniMax Sparse Attention (MSA), a blockwise sparse attention built upon Grouped Query Attention (GQA). A lightweight Index Branch scores key-value blocks and independently selects a Top-k subset for each GQA group, enabling group-specific sparse retrieval while maintaining efficient block-level execution; the Main Branch then performs exact block-sparse attention over only the selected blocks. Designed around a principle of simplicity and scalability, MSA is deliberately streamlined, making it straightforward to deploy efficiently across a broad range of GPUs. To translate sparsity into practical speedups, we co-design MSA with a GPU execution path that uses exp-free Top-k selection and KV-outer sparse attention to improve tensor-core utilization under block-granular access. On a 109B-parameter model with native multimodal training, MSA performs on par with GQA while reducing per-token attention compute by 28.4x at 1M context. Paired with our co-designed kernel, MSA achieves 14.2x prefill and 7.6x decoding wall-clock speedups on H800. Our inference kernel is available at: https://github.com/MiniMax-AI/MSA. A production-grade natively multimodal model powered by MSA has been publicly released at: https://huggingface.co/MiniMaxAI/MiniMax-M3.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13392.png", "numComments": 1, "submittedBy": {"_id": "673463f29cb2775fbe62a626", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/673463f29cb2775fbe62a626/64k_zEitiRQD_U002ojyy.jpeg", "fullname": "Ryanlee", "name": "ryanlee-dev", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 37, "isUserFollowing": false}, "organization": {"_id": "6778fc29920093dbc0c24917", "name": "MiniMaxAI", "fullname": "MiniMax", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/676e38ad04af5bec20bc9faf/dUd-LsZEX0H_d4qefO_g6.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.13673", "authors": [{"_id": "6a2b69f04957fcdd3aac0602", "name": "Seokju Cho", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0603", "name": "Ryo Hachiuma", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0604", "name": "Abhishek Badki", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0605", "name": "Hang Su", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0606", "user": {"_id": "657152eb12f162153b50ec9d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/657152eb12f162153b50ec9d/qnldHP35PclV0pDz_05q8.jpeg", "isPro": false, "fullname": "Byung-Kwan Lee", "user": "BK-Lee", "type": "user", "name": "BK-Lee"}, "name": "Byung-Kwan Lee", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:56:59.203Z", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0607", "name": "Chan Hee Song", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0608", "name": "Sifei Liu", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac0609", "name": "Subhashree Radhakrishnan", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac060a", "name": "Seungryong Kim", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac060b", "name": "Yu-Chiang Frank Wang", "hidden": false}, {"_id": "6a2b69f04957fcdd3aac060c", "user": {"_id": "64ae22dd1aee69ece065cdcd", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ae22dd1aee69ece065cdcd/JG7QaHIrr4i2k4uwR4pZK.png", "isPro": false, "fullname": "Min-Hung Chen", "user": "cmhungsteve", "type": "user", "name": "cmhungsteve"}, "name": "Min-Hung Chen", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:57:01.112Z", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "SpatialClaw: Rethinking Action Interface for Agentic Spatial Reasoning", "submittedOnDailyBy": {"_id": "64ae22dd1aee69ece065cdcd", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ae22dd1aee69ece065cdcd/JG7QaHIrr4i2k4uwR4pZK.png", "isPro": false, "fullname": "Min-Hung Chen", "user": "cmhungsteve", "type": "user", "name": "cmhungsteve"}, "summary": "Spatial reasoning, the ability to determine where objects are, how they relate, and how they move in 3D, remains a fundamental challenge for vision-language models (VLMs). Tool-augmented agents attempt to address this by augmenting VLMs with specialist perception modules, yet their effectiveness is bounded by the action interface through which those tools are invoked. In this work, we study how the design of this interface shapes the agent's capacity for open-ended spatial reasoning. Existing spatial agents either employ single-pass code execution, which commits to a full analysis strategy before any intermediate result is observed, or rely on a structured tool-call interface that often offers less flexibility for freely composing operations or tailoring the analysis to each task. Both designs offer limited flexibility for open-ended, complex 3D/4D spatial reasoning. We therefore propose SpatialClaw, a training-free framework for spatial reasoning that adopts code as the action interface. SpatialClaw maintains a stateful Python kernel pre-loaded with input frames and a suite of perception and geometry primitives, letting a VLM-backed agent write one executable cell per step conditioned on all prior outputs, enabling the agent to flexibly compose and manipulate perception results and adapt its analysis to both intermediate text and visual observations and the demands of each problem. Evaluated across 20 spatial reasoning benchmarks spanning a broad range of static and dynamic 3D/4D spatial reasoning tasks, SpatialClaw achieves 59.9% average accuracy, outperforming the recent spatial agent by +11.2 points, with consistent gains across six VLM backbones from two model families without any benchmark- or model-specific adaptation.", "upvotes": 80, "discussionId": "6a2b69f04957fcdd3aac060d", "projectPage": "https://spatialclaw.github.io/", "githubRepo": "https://github.com/NVlabs/SpatialClaw", "githubRepoAddedBy": "user", "ai_summary": "SpatialClaw is a training-free framework that uses code as an action interface to enable flexible, stateful spatial reasoning in vision-language models, achieving superior performance across diverse 3D/4D spatial reasoning tasks.", "ai_keywords": ["vision-language models", "spatial reasoning", "tool-augmented agents", "action interface", "code execution", "Python kernel", "perception primitives", "geometry primitives", "executable cells", "open-ended reasoning", "3D/4D spatial reasoning", "benchmarks", "VLM backbones"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 53, "organization": {"_id": "60262b67268c201cdc8b7d43", "name": "nvidia", "fullname": "NVIDIA", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65df9200dc3292a8983e5017/Vs5FPVCH-VZBipV3qKTuy.png"}, "summary_zh": "<ul>\n    <li>\u7a7a\u95f4\u63a8\u7406\u662f\u89c6\u89c9\u8bed\u8a00\u6a21\u578b\uff08VLMs\uff09\u9762\u4e34\u7684\u4e00\u4e2a\u91cd\u8981\u6311\u6218\uff0c\u6d89\u53ca\u52303D\u7a7a\u95f4\u4e2d\u5bf9\u8c61\u7684\u4f4d\u7f6e\u3001\u5173\u7cfb\u548c\u8fd0\u52a8\u3002</li>\n    <li>\u76ee\u524d\u7684\u5de5\u5177\u589e\u5f3a\u4ee3\u7406\u901a\u8fc7\u4e13\u95e8\u7684\u611f\u77e5\u6a21\u5757\u6765\u6539\u5584VLMs\uff0c\u4f46\u5176\u6548\u679c\u53d7\u9650\u4e8e\u5de5\u5177\u8c03\u7528\u7684\u63a5\u53e3\u8bbe\u8ba1\u3002</li>\n    <li>\u73b0\u6709\u7684\u7a7a\u95f4\u4ee3\u7406\u8981\u4e48\u91c7\u7528\u5355\u6b21\u4ee3\u7801\u6267\u884c\uff0c\u8981\u4e48\u4f7f\u7528\u7ed3\u6784\u5316\u5de5\u5177\u8c03\u7528\u63a5\u53e3\uff0c\u7075\u6d3b\u6027\u6709\u9650\uff0c\u96be\u4ee5\u8fdb\u884c\u5f00\u653e\u5f0f\u590d\u6742\u7a7a\u95f4\u63a8\u7406\u3002</li>\n    <li>\u672c\u6587\u63d0\u51fa\u4e86SpatialClaw\uff0c\u4e00\u4e2a\u65e0\u8bad\u7ec3\u7684\u7a7a\u95f4\u63a8\u7406\u6846\u67b6\uff0c\u4f7f\u7528\u4ee3\u7801\u4f5c\u4e3a\u64cd\u4f5c\u63a5\u53e3\uff0c\u589e\u5f3a\u4e86\u7075\u6d3b\u6027\u3002</li>\n    <li>\u572820\u4e2a\u7a7a\u95f4\u63a8\u7406\u57fa\u51c6\u6d4b\u8bd5\u4e2d\uff0cSpatialClaw\u5b9e\u73b0\u4e8659.9%\u7684\u5e73\u5747\u51c6\u786e\u7387\uff0c\u6bd4\u6700\u65b0\u7684\u7a7a\u95f4\u4ee3\u7406\u9ad8\u51fa11.2\u4e2a\u767e\u5206\u70b9\uff0c\u4e14\u5728\u591a\u79cd\u6a21\u578b\u4e0a\u8868\u73b0\u4e00\u81f4\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Spatial reasoning is a tough challenge for vision-language models (VLMs) as it involves understanding object positions and movements in 3D space.</li>\n    <li>Current tool-augmented agents have limitations due to their design, which restricts flexibility in handling complex spatial reasoning tasks.</li>\n    <li>SpatialClaw is a new framework that uses a code-based action interface, allowing for more adaptable and flexible reasoning.</li>\n    <li>It operates with a Python kernel that helps the agent write code step-by-step, taking into account previous results for better decision-making.</li>\n    <li>SpatialClaw outperforms existing spatial reasoning agents in various benchmarks, achieving an average accuracy of 59.9% and showing improved performance across different models without needing specific adjustments.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "SpatialClaw: Rethinking Action Interface for Agentic Spatial Reasoning", "summary": "Spatial reasoning, the ability to determine where objects are, how they relate, and how they move in 3D, remains a fundamental challenge for vision-language models (VLMs). Tool-augmented agents attempt to address this by augmenting VLMs with specialist perception modules, yet their effectiveness is bounded by the action interface through which those tools are invoked. In this work, we study how the design of this interface shapes the agent's capacity for open-ended spatial reasoning. Existing spatial agents either employ single-pass code execution, which commits to a full analysis strategy before any intermediate result is observed, or rely on a structured tool-call interface that often offers less flexibility for freely composing operations or tailoring the analysis to each task. Both designs offer limited flexibility for open-ended, complex 3D/4D spatial reasoning. We therefore propose SpatialClaw, a training-free framework for spatial reasoning that adopts code as the action interface. SpatialClaw maintains a stateful Python kernel pre-loaded with input frames and a suite of perception and geometry primitives, letting a VLM-backed agent write one executable cell per step conditioned on all prior outputs, enabling the agent to flexibly compose and manipulate perception results and adapt its analysis to both intermediate text and visual observations and the demands of each problem. Evaluated across 20 spatial reasoning benchmarks spanning a broad range of static and dynamic 3D/4D spatial reasoning tasks, SpatialClaw achieves 59.9% average accuracy, outperforming the recent spatial agent by +11.2 points, with consistent gains across six VLM backbones from two model families without any benchmark- or model-specific adaptation.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13673.png", "numComments": 1, "submittedBy": {"_id": "64ae22dd1aee69ece065cdcd", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ae22dd1aee69ece065cdcd/JG7QaHIrr4i2k4uwR4pZK.png", "fullname": "Min-Hung Chen", "name": "cmhungsteve", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 19, "isUserFollowing": false}, "organization": {"_id": "60262b67268c201cdc8b7d43", "name": "nvidia", "fullname": "NVIDIA", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65df9200dc3292a8983e5017/Vs5FPVCH-VZBipV3qKTuy.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.12397", "authors": [{"_id": "6a2a33e080a9c7c6830c0fc5", "user": {"_id": "662aa42f4eaa187e4cf6827b", "avatarUrl": "/avatars/17139f0b6e8092cf4c135028db03a7ff.svg", "isPro": false, "fullname": "Songhao Wu", "user": "shwu", "type": "user", "name": "shwu"}, "name": "Songhao Wu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-11T08:38:11.792Z", "hidden": false}, {"_id": "6a2a33e080a9c7c6830c0fc6", "user": {"_id": "64b8ca3c5067873176d4b436", "avatarUrl": "/avatars/b659d147b2454b47c9a7e89bbed525fc.svg", "isPro": false, "fullname": "AngLv", "user": "AngLv", "type": "user", "name": "AngLv"}, "name": "Ang Lv", "status": "claimed_verified", "statusLastChangedAt": "2026-06-11T08:38:09.713Z", "hidden": false}, {"_id": "6a2a33e080a9c7c6830c0fc7", "name": "Ruobing Xie", "hidden": false}, {"_id": "6a2a33e080a9c7c6830c0fc8", "name": "Yankai Lin", "hidden": false}], "publishedAt": "2026-06-10T00:00:00.000Z", "submittedOnDailyAt": "2026-06-11T00:00:00.000Z", "title": "Redesign Mixture-of-Experts Routers with Manifold Power Iteration", "submittedOnDailyBy": {"_id": "662aa42f4eaa187e4cf6827b", "avatarUrl": "/avatars/17139f0b6e8092cf4c135028db03a7ff.svg", "isPro": false, "fullname": "Songhao Wu", "user": "shwu", "type": "user", "name": "shwu"}, "summary": "Router is the cornerstone component to the Mixture-of-Experts models. Serving as expert proxies, the rows of the router matrix compute their similarity to the MoE inputs to determine which subset of experts is activated. Ideally, each router row is designed to encode the expert matrix into this representative vector, such that its dot-product with token can better reflect token-expert affinity. However, there exists no design principles to enforce this condensation. In this paper, we propose to align each router row with the principal singular direction of the associated expert, as this direction provides the most expressive mathematical description of a matrix. Based on this principle, we propose a router redesign with Manifold Power Iteration (MPI). Specifically, it introduces a \"Power-then-Retract\" paradigm, where a power iteration step is performed on the router weights, followed by a retraction to impose a norm constraint to ensure both efficiency and stability. Theoretically, we show that MPI drives router rows to converge toward the principal singular directions of associated experts. Empirically, we pretrain MoE model across scales from 1B to 11B parameters to confirm that this alignment facilitates more effective MoE models.", "upvotes": 74, "discussionId": "6a2a33e080a9c7c6830c0fc9", "githubRepo": "https://github.com/ericshwu/Router-with-Manifold-Power-Iteration", "githubRepoAddedBy": "user", "ai_summary": "Researchers propose a novel router redesign for Mixture-of-Experts models that aligns router rows with the principal singular directions of expert matrices using Manifold Power Iteration to improve model effectiveness.", "ai_keywords": ["Mixture-of-Experts", "router", "expert proxies", "router matrix", "singular value decomposition", "Manifold Power Iteration", "power iteration", "retraction", "principal singular direction", "expert matrix"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 4, "summary_zh": "<ul>\n    <li>\u8def\u7531\u5668\u662fMixture-of-Experts\uff08MoE\uff09\u6a21\u578b\u7684\u91cd\u8981\u7ec4\u6210\u90e8\u5206\uff0c\u5e2e\u52a9\u51b3\u5b9a\u6fc0\u6d3b\u54ea\u4e9b\u4e13\u5bb6\u3002</li>\n    <li>\u6bcf\u4e2a\u8def\u7531\u5668\u884c\u5e94\u7f16\u7801\u4e13\u5bb6\u77e9\u9635\uff0c\u4ee5\u4fbf\u66f4\u597d\u5730\u53cd\u6620\u8f93\u5165\u4e0e\u4e13\u5bb6\u7684\u5173\u8054\u3002</li>\n    <li>\u672c\u6587\u63d0\u51fa\u901a\u8fc7\u4e3b\u5947\u5f02\u65b9\u5411\u6765\u91cd\u65b0\u8bbe\u8ba1\u8def\u7531\u5668\uff0c\u4ee5\u589e\u5f3a\u8868\u8fbe\u80fd\u529b\u3002</li>\n    <li>\u5f15\u5165\u201c\u5148\u5e42\u8fd0\u7b97\u540e\u6536\u655b\u201d\u7684\u65b9\u6cd5\uff0c\u786e\u4fdd\u8def\u7531\u5668\u7684\u6743\u91cd\u6709\u6548\u4e14\u7a33\u5b9a\u3002</li>\n    <li>\u5b9e\u9a8c\u8bc1\u660e\uff0c\u8fd9\u79cd\u5bf9\u9f50\u65b9\u6cd5\u80fd\u63d0\u9ad8\u4e0d\u540c\u89c4\u6a21\u7684MoE\u6a21\u578b\u7684\u6709\u6548\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>The router is a key part of Mixture-of-Experts (MoE) models, helping to choose which experts to activate based on input data.</li>\n    <li>The paper suggests a new way to design the router, aligning its rows with the main direction of the associated expert to improve performance.</li>\n    <li>This new design uses a method called Manifold Power Iteration (MPI), which involves adjusting the router weights and ensuring they stay stable.</li>\n    <li>Theoretically, this method helps the router rows better match the most important features of the experts.</li>\n    <li>Tests show that this approach makes MoE models more effective, even when scaling from 1 billion to 11 billion parameters.</li>\n</ul>"}, "publishedAt": "2026-06-09T20:00:00.000Z", "title": "Redesign Mixture-of-Experts Routers with Manifold Power Iteration", "summary": "Router is the cornerstone component to the Mixture-of-Experts models. Serving as expert proxies, the rows of the router matrix compute their similarity to the MoE inputs to determine which subset of experts is activated. Ideally, each router row is designed to encode the expert matrix into this representative vector, such that its dot-product with token can better reflect token-expert affinity. However, there exists no design principles to enforce this condensation. In this paper, we propose to align each router row with the principal singular direction of the associated expert, as this direction provides the most expressive mathematical description of a matrix. Based on this principle, we propose a router redesign with Manifold Power Iteration (MPI). Specifically, it introduces a \"Power-then-Retract\" paradigm, where a power iteration step is performed on the router weights, followed by a retraction to impose a norm constraint to ensure both efficiency and stability. Theoretically, we show that MPI drives router rows to converge toward the principal singular directions of associated experts. Empirically, we pretrain MoE model across scales from 1B to 11B parameters to confirm that this alignment facilitates more effective MoE models.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.12397.png", "numComments": 2, "submittedBy": {"_id": "662aa42f4eaa187e4cf6827b", "avatarUrl": "/avatars/17139f0b6e8092cf4c135028db03a7ff.svg", "fullname": "Songhao Wu", "name": "shwu", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 6, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.13679", "authors": [{"_id": "6a2b6bbe4957fcdd3aac061e", "user": {"_id": "67e60ae6ac37824273d74389", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/YvPKZ_0gyJnvNwM1zK3JS.png", "isPro": true, "fullname": "Dian Zheng", "user": "zhengli1013", "type": "user", "name": "zhengli1013"}, "name": "Dian Zheng", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T14:04:59.526Z", "hidden": false}, {"_id": "6a2b6bbe4957fcdd3aac061f", "name": "Harry Lee", "hidden": false}, {"_id": "6a2b6bbe4957fcdd3aac0620", "name": "Manyuan Zhang", "hidden": false}, {"_id": "6a2b6bbe4957fcdd3aac0621", "name": "Kaituo Feng", "hidden": false}, {"_id": "6a2b6bbe4957fcdd3aac0622", "name": "Zoey Guo", "hidden": false}, {"_id": "6a2b6bbe4957fcdd3aac0623", "name": "Ray Zhang", "hidden": false}, {"_id": "6a2b6bbe4957fcdd3aac0624", "name": "Hongsheng Li", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "InterleaveThinker: Reinforcing Agentic Interleaved Generation", "submittedOnDailyBy": {"_id": "67e60ae6ac37824273d74389", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/YvPKZ_0gyJnvNwM1zK3JS.png", "isPro": true, "fullname": "Dian Zheng", "user": "zhengli1013", "type": "user", "name": "zhengli1013"}, "summary": "Recent image generators have demonstrated impressive photorealism and instruction-following capabilities in single-image generation and editing. However, constrained by their architectures, they cannot achieve interleaved generation (text-image sequence), which has crucial applications in visual narratives, guidance, and embodied manipulation. Even the latest open-source Unified Multimodal Models (UMMs) exhibit limited performance in this regard. In this paper, we introduce InterleaveThinker, the first multi-agent pipeline designed to endow any existing image generator with interleaved generation capabilities. Specifically, we employ a planner agent to organize the image-text input sequence, instructing the image generator on the required execution at each step. Subsequently, we introduce a critic agent to evaluate the generator's outputs, identify samples that deviate from the planned instructions, and refine the instructions for regeneration. To implement this pipeline, we construct the Interleave-Planner-SFT-80k and Interleave-Critic-SFT-112k to perform a format cold-start. Then we develop Interleave-Critic-RL-13k to reinforce the step-wise instruction correction capability within a generation trajectory using GRPO. Since a single interleaved generation trajectory may involve over 25 generator calls, optimizing the entire trajectory is computationally impractical. Therefore, we propose accuracy reward and step-wise reward, allowing single-step RL to effectively guide the entire generation trajectory. The results show that InterleaveThinker improves performance across various image generators. On interleaved generation benchmarks, it achieves performance comparable to Nano Banana and GPT-5. Surprisingly, it also significantly enhances the base model on reasoning-based benchmarks; for example, on 4-step FLUX.2-klein, we observe substantial gains on WISE and RISE.", "upvotes": 73, "discussionId": "6a2b6bbe4957fcdd3aac0625", "projectPage": "https://zhengdian1.github.io/InterleaveThinker-proj/", "githubRepo": "https://github.com/zhengdian1/InterleaveThinker", "githubRepoAddedBy": "user", "ai_summary": "InterleaveThinker enables interleaved generation capabilities for image generators through a multi-agent pipeline with planner and critic agents, achieving performance comparable to state-of-the-art models while enhancing reasoning benchmarks.", "ai_keywords": ["multi-agent pipeline", "image generator", "interleaved generation", "planner agent", "critic agent", "reinforcement learning", "GRPO", "accuracy reward", "step-wise reward"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 99, "summary_zh": "<ul>\n    <li>\u6700\u8fd1\u7684\u56fe\u50cf\u751f\u6210\u5668\u5728\u751f\u6210\u548c\u7f16\u8f91\u5355\u5f20\u56fe\u50cf\u65b9\u9762\u8868\u73b0\u51fa\u8272\uff0c\u4f46\u65e0\u6cd5\u5904\u7406\u6587\u672c\u4e0e\u56fe\u50cf\u4ea4\u66ff\u751f\u6210\u3002</li>\n    <li>\u672c\u6587\u4ecb\u7ecd\u4e86InterleaveThinker\uff0c\u8fd9\u662f\u7b2c\u4e00\u4e2a\u591a\u667a\u80fd\u4f53\u7cfb\u7edf\uff0c\u80fd\u4e3a\u73b0\u6709\u56fe\u50cf\u751f\u6210\u5668\u63d0\u4f9b\u4ea4\u66ff\u751f\u6210\u80fd\u529b\u3002</li>\n    <li>\u8be5\u7cfb\u7edf\u4f7f\u7528\u89c4\u5212\u8005\u4ee3\u7406\u7ec4\u7ec7\u56fe\u50cf-\u6587\u672c\u8f93\u5165\uff0c\u5e76\u5f15\u5bfc\u56fe\u50cf\u751f\u6210\u5668\u9010\u6b65\u6267\u884c\u3002</li>\n    <li>\u5f15\u5165\u8bc4\u4ef7\u4ee3\u7406\u6765\u8bc4\u4f30\u751f\u6210\u7684\u8f93\u51fa\uff0c\u5e76\u6839\u636e\u8ba1\u5212\u8fdb\u884c\u6307\u4ee4\u7684\u8c03\u6574\u548c\u518d\u751f\u6210\u3002</li>\n    <li>\u5b9e\u9a8c\u7ed3\u679c\u663e\u793a\uff0cInterleaveThinker\u5728\u591a\u4e2a\u56fe\u50cf\u751f\u6210\u5668\u4e0a\u7684\u8868\u73b0\u5f97\u5230\u4e86\u663e\u8457\u63d0\u5347\uff0c\u7279\u522b\u662f\u5728\u63a8\u7406\u57fa\u7840\u7684\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u4f18\u5f02\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>InterleaveThinker is a new multi-agent system that allows existing image generators to create images based on interleaved text and image instructions.</li>\n    <li>The system uses two main components: a planner to organize input sequences and a critic to evaluate and refine the outputs.</li>\n    <li>To support this, special models were created for planning and critique, helping to improve instruction correction during image generation.</li>\n    <li>InterleaveThinker can handle complex tasks that require many steps, using rewards to guide each step effectively.</li>\n    <li>The results show that it significantly enhances the performance of image generators, achieving results similar to advanced models like Nano Banana and GPT-5.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "InterleaveThinker: Reinforcing Agentic Interleaved Generation", "summary": "Recent image generators have demonstrated impressive photorealism and instruction-following capabilities in single-image generation and editing. However, constrained by their architectures, they cannot achieve interleaved generation (text-image sequence), which has crucial applications in visual narratives, guidance, and embodied manipulation. Even the latest open-source Unified Multimodal Models (UMMs) exhibit limited performance in this regard. In this paper, we introduce InterleaveThinker, the first multi-agent pipeline designed to endow any existing image generator with interleaved generation capabilities. Specifically, we employ a planner agent to organize the image-text input sequence, instructing the image generator on the required execution at each step. Subsequently, we introduce a critic agent to evaluate the generator's outputs, identify samples that deviate from the planned instructions, and refine the instructions for regeneration. To implement this pipeline, we construct the Interleave-Planner-SFT-80k and Interleave-Critic-SFT-112k to perform a format cold-start. Then we develop Interleave-Critic-RL-13k to reinforce the step-wise instruction correction capability within a generation trajectory using GRPO. Since a single interleaved generation trajectory may involve over 25 generator calls, optimizing the entire trajectory is computationally impractical. Therefore, we propose accuracy reward and step-wise reward, allowing single-step RL to effectively guide the entire generation trajectory. The results show that InterleaveThinker improves performance across various image generators. On interleaved generation benchmarks, it achieves performance comparable to Nano Banana and GPT-5. Surprisingly, it also significantly enhances the base model on reasoning-based benchmarks; for example, on 4-step FLUX.2-klein, we observe substantial gains on WISE and RISE.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13679.png", "numComments": 1, "submittedBy": {"_id": "67e60ae6ac37824273d74389", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/YvPKZ_0gyJnvNwM1zK3JS.png", "fullname": "Dian Zheng", "name": "zhengli1013", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 5, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.10917", "authors": [{"_id": "6a28c5ffe7d78ea7587e5319", "name": "Xucong Wang", "hidden": false}, {"_id": "6a28c5ffe7d78ea7587e531a", "name": "Ziyu Ma", "hidden": false}, {"_id": "6a28c5ffe7d78ea7587e531b", "name": "Shidong Yang", "hidden": false}, {"_id": "6a28c5ffe7d78ea7587e531c", "name": "Tongwen Huang", "hidden": false}, {"_id": "6a28c5ffe7d78ea7587e531d", "name": "Pengkun Wang", "hidden": false}, {"_id": "6a28c5ffe7d78ea7587e531e", "name": "Yong Wang", "hidden": false}, {"_id": "6a28c5ffe7d78ea7587e531f", "name": "Xiangxiang Chu", "hidden": false}], "publishedAt": "2026-06-09T14:28:07.000Z", "submittedOnDailyAt": "2026-06-10T00:00:00.000Z", "title": "Role-Agent: Bootstrapping LLM Agents via Dual-Role Evolution", "submittedOnDailyBy": {"_id": "69a52b6bfc49cf45f641d563", "avatarUrl": "/avatars/71be1cf443f24755f2a69801aeb5c451.svg", "isPro": false, "fullname": "wangxucong", "user": "xuc865", "type": "user", "name": "xuc865"}, "summary": "Although Large Language Model (LLM) agents have demonstrated strong performance on complex tasks, their learning is often limited by inefficient interaction feedback and static training environments, which hinder broader generalization. To address these limitations, this paper introduces Role-Agent, black{a framework} that harnesses a single LLM to function concurrently as both the agent and the environment, enabling a bootstrapped co-evolution. Role-Agent comprises two synergistic components: World-In-Agent (WIA) and Agent-In-World (AIW). In WIA, the LLM acts as the agent and predicts future states after each action; the alignment between predicted and actual states is then used as a process reward, encouraging environment-aware reasoning. In AIW, the LLM analyzes failure modes from failed trajectories and retrieves tasks with similar failure patterns, thereby reshaping the training data distribution for targeted practice. Experiments on multiple benchmarks show that Role-Agent consistently improves performance, yielding an average gain of over 4\\% over strong baselines.", "upvotes": 73, "discussionId": "6a28c5ffe7d78ea7587e5320", "githubRepo": "https://github.com/AMAP-ML/roleagent", "githubRepoAddedBy": "user", "ai_summary": "Role-Agent framework enables LLM agents to function as both agent and environment through bootstrapped co-evolution, improving performance via environment-aware reasoning and targeted practice.", "ai_keywords": ["Large Language Model", "LLM agents", "bootstrapped co-evolution", "World-In-Agent", "Agent-In-World", "environment-aware reasoning", "targeted practice"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 74, "summary_zh": "<ul>\n    <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLM\uff09\u5728\u590d\u6742\u4efb\u52a1\u4e2d\u8868\u73b0\u51fa\u8272\uff0c\u4f46\u5b66\u4e60\u53d7\u9650\u4e8e\u4f4e\u6548\u7684\u53cd\u9988\u548c\u9759\u6001\u8bad\u7ec3\u73af\u5883\u3002</li>\n    <li>\u4e3a\u4e86\u89e3\u51b3\u8fd9\u4e9b\u95ee\u9898\uff0c\u672c\u6587\u63d0\u51fa\u4e86Role-Agent\u6846\u67b6\uff0c\u4f7fLLM\u540c\u65f6\u4f5c\u4e3a\u4ee3\u7406\u548c\u73af\u5883\uff0c\u5b9e\u73b0\u5171\u540c\u8fdb\u5316\u3002</li>\n    <li>Role-Agent\u5305\u542b\u4e24\u4e2a\u534f\u540c\u90e8\u5206\uff1aWorld-In-Agent\uff08WIA\uff09\u548cAgent-In-World\uff08AIW\uff09\u3002</li>\n    <li>\u5728WIA\u4e2d\uff0cLLM\u9884\u6d4b\u6bcf\u4e2a\u52a8\u4f5c\u540e\u7684\u672a\u6765\u72b6\u6001\uff0c\u5e76\u6839\u636e\u9884\u6d4b\u4e0e\u5b9e\u9645\u72b6\u6001\u7684\u5bf9\u9f50\u4f5c\u4e3a\u5956\u52b1\uff0c\u4fc3\u8fdb\u73af\u5883\u610f\u8bc6\u7684\u63a8\u7406\u3002</li>\n    <li>\u5728AIW\u4e2d\uff0cLLM\u5206\u6790\u5931\u8d25\u6a21\u5f0f\u5e76\u68c0\u7d22\u76f8\u4f3c\u4efb\u52a1\uff0c\u4ece\u800c\u91cd\u5851\u8bad\u7ec3\u6570\u636e\u5206\u5e03\uff0c\u8fdb\u884c\u6709\u9488\u5bf9\u6027\u7684\u7ec3\u4e60\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cRole-Agent\u5728\u591a\u4e2a\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u63d0\u9ad8\u4e86\u6027\u80fd\uff0c\u5e73\u5747\u63d0\u5347\u8d85\u8fc74%\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Large Language Model (LLM) agents can struggle with learning due to poor feedback and fixed training setups.</li>\n    <li>The paper presents Role-Agent, a new framework that allows an LLM to act as both the agent and the environment.</li>\n    <li>Role-Agent has two parts: World-In-Agent (WIA) helps the LLM predict future outcomes, while Agent-In-World (AIW) analyzes failures to improve training.</li>\n    <li>Using Role-Agent leads to better performance in tasks, with an average improvement of over 4% compared to strong existing methods.</li>\n</ul>"}, "publishedAt": "2026-06-09T10:28:07.000Z", "title": "Role-Agent: Bootstrapping LLM Agents via Dual-Role Evolution", "summary": "Although Large Language Model (LLM) agents have demonstrated strong performance on complex tasks, their learning is often limited by inefficient interaction feedback and static training environments, which hinder broader generalization. To address these limitations, this paper introduces Role-Agent, black{a framework} that harnesses a single LLM to function concurrently as both the agent and the environment, enabling a bootstrapped co-evolution. Role-Agent comprises two synergistic components: World-In-Agent (WIA) and Agent-In-World (AIW). In WIA, the LLM acts as the agent and predicts future states after each action; the alignment between predicted and actual states is then used as a process reward, encouraging environment-aware reasoning. In AIW, the LLM analyzes failure modes from failed trajectories and retrieves tasks with similar failure patterns, thereby reshaping the training data distribution for targeted practice. Experiments on multiple benchmarks show that Role-Agent consistently improves performance, yielding an average gain of over 4\\% over strong baselines.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.10917.png", "numComments": 2, "submittedBy": {"_id": "69a52b6bfc49cf45f641d563", "avatarUrl": "/avatars/71be1cf443f24755f2a69801aeb5c451.svg", "fullname": "wangxucong", "name": "xuc865", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2606.12087", "authors": [{"_id": "6a2adc0efdec76e893e76283", "name": "Jia Deng", "hidden": false}, {"_id": "6a2adc0efdec76e893e76284", "name": "Yimeng Chen", "hidden": false}, {"_id": "6a2adc0efdec76e893e76285", "name": "Xiaoqing Xiang", "hidden": false}, {"_id": "6a2adc0efdec76e893e76286", "user": {"_id": "6437b514a1fa778a4da67e4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6437b514a1fa778a4da67e4d/dHoNK4Nqr6OVG4IgzkdjH.png", "isPro": false, "fullname": "Finch", "user": "ziyang1060", "type": "user", "name": "ziyang1060"}, "name": "Ziyang Zeng", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T07:12:03.264Z", "hidden": false}, {"_id": "6a2adc0efdec76e893e76287", "name": "Shuo Tang", "hidden": false}, {"_id": "6a2adc0efdec76e893e76288", "name": "Wayne Xin Zhao", "hidden": false}, {"_id": "6a2adc0efdec76e893e76289", "name": "Feng Chang", "hidden": false}, {"_id": "6a2adc0efdec76e893e7628a", "name": "Chuan Hao", "hidden": false}, {"_id": "6a2adc0efdec76e893e7628b", "name": "Yuan Wei", "hidden": false}, {"_id": "6a2adc0efdec76e893e7628c", "name": "Ran Tao", "hidden": false}, {"_id": "6a2adc0efdec76e893e7628d", "name": "Bryan Dai", "hidden": false}, {"_id": "6a2adc0efdec76e893e7628e", "name": "Ji-Rong Wen", "hidden": false}], "publishedAt": "2026-06-10T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "FORT-Searcher: Synthesizing Shortcut-Resistant Search Tasks for Training Deep Search Agents", "submittedOnDailyBy": {"_id": "6544b9b646dbdeca34ee5f52", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6544b9b646dbdeca34ee5f52/nRx6m1C4wfZ_xSWoBUNJf.png", "isPro": false, "fullname": "Yuyang Hu", "user": "namespace-ERI", "type": "user", "name": "namespace-ERI"}, "summary": "Training deep search agents requires verifiable questions whose answers remain unavailable until sufficient evidence has been acquired through search. Existing synthesis methods often increase apparent difficulty by enriching graph structures, but structural complexity alone does not guarantee realized search difficulty: the intended search process can collapse through a cheaper identifying route. We formalize this gap with a shortcut-aware difficulty framework and identify four actionable shortcut risks: evidence co-coverage, single-clue selectivity, exposed constants, and prior-knowledge binding. To diagnose their realized effects, we use trajectory signatures including solving cost, answer hit time, and prior-shortcut rate. Guided by this framework, we introduce FORT, a Framework of Shortcut-Resistant Training-Data Synthesis. FORT constructs shortcut-resistant training data by controlling shortcut risks across entity selection, evidence graph construction, question formulation, and adversarial refinement. Experiments show that FORT induces longer pre-answer search and fewer shortcut patterns than existing open-source deep search datasets. Using the resulting trajectories, we train FORT-Searcher with supervised fine-tuning (SFT) only, and it achieves the best overall performance among comparable-size open-source search agents on challenging deep search benchmarks. Relevant resources will be made available at https://github.com/RUCAIBox/FORT-Searcher.", "upvotes": 71, "discussionId": "6a2adc0ffdec76e893e7628f", "githubRepo": "https://github.com/RUCAIBox/FORT-Searcher", "githubRepoAddedBy": "user", "ai_summary": "A framework for creating shortcut-resistant training data for deep search agents by identifying and mitigating four shortcut risks in data synthesis processes.", "ai_keywords": ["deep search agents", "shortcut-aware difficulty framework", "shortcut risks", "trajectory signatures", "FORT", "supervised fine-tuning", "deep search benchmarks"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 17, "summary_zh": "<ul>\n    <li>\u8bad\u7ec3\u6df1\u5ea6\u641c\u7d22\u4ee3\u7406\u9700\u8981\u53ef\u9a8c\u8bc1\u7684\u95ee\u9898\uff0c\u7b54\u6848\u5728\u83b7\u5f97\u8db3\u591f\u8bc1\u636e\u4e4b\u524d\u4e0d\u53ef\u7528\u3002</li>\n    <li>\u73b0\u6709\u5408\u6210\u65b9\u6cd5\u901a\u8fc7\u4e30\u5bcc\u56fe\u7ed3\u6784\u589e\u52a0\u4e86\u8868\u9762\u96be\u5ea6\uff0c\u4f46\u7ed3\u6784\u590d\u6742\u6027\u5e76\u4e0d\u4e00\u5b9a\u5e26\u6765\u5b9e\u9645\u641c\u7d22\u96be\u5ea6\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u4e2a\u8003\u8651\u6377\u5f84\u98ce\u9669\u7684\u96be\u5ea6\u6846\u67b6\uff0c\u8bc6\u522b\u51fa\u56db\u79cd\u6377\u5f84\u98ce\u9669\u3002</li>\n    <li>\u57fa\u4e8e\u6b64\u6846\u67b6\uff0c\u6211\u4eec\u5f15\u5165\u4e86FORT\uff0c\u4e00\u4e2a\u6297\u6377\u5f84\u8bad\u7ec3\u6570\u636e\u5408\u6210\u7684\u6846\u67b6\uff0c\u80fd\u591f\u63a7\u5236\u6377\u5f84\u98ce\u9669\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cFORT\u751f\u6210\u7684\u6570\u636e\u80fd\u591f\u5b9e\u73b0\u66f4\u957f\u7684\u641c\u7d22\u65f6\u95f4\u548c\u66f4\u5c11\u7684\u6377\u5f84\u6a21\u5f0f\uff0c\u8bad\u7ec3\u51fa\u7684\u641c\u7d22\u4ee3\u7406\u5728\u6df1\u5ea6\u641c\u7d22\u57fa\u51c6\u4e2d\u8868\u73b0\u6700\u4f73\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Training deep search agents needs questions that can't be answered until enough evidence is found.</li>\n    <li>Current methods make problems harder by complicating graph structures, but this doesn't always increase search difficulty.</li>\n    <li>The study introduces a framework that identifies four shortcut risks that can make searches easier than intended.</li>\n    <li>They developed FORT, a system that creates training data resistant to these shortcuts by carefully managing various factors.</li>\n    <li>Tests show FORT leads to deeper searches and better performance compared to existing datasets, training a new search agent called FORT-Searcher.</li>\n</ul>"}, "publishedAt": "2026-06-09T20:00:00.000Z", "title": "FORT-Searcher: Synthesizing Shortcut-Resistant Search Tasks for Training Deep Search Agents", "summary": "Training deep search agents requires verifiable questions whose answers remain unavailable until sufficient evidence has been acquired through search. Existing synthesis methods often increase apparent difficulty by enriching graph structures, but structural complexity alone does not guarantee realized search difficulty: the intended search process can collapse through a cheaper identifying route. We formalize this gap with a shortcut-aware difficulty framework and identify four actionable shortcut risks: evidence co-coverage, single-clue selectivity, exposed constants, and prior-knowledge binding. To diagnose their realized effects, we use trajectory signatures including solving cost, answer hit time, and prior-shortcut rate. Guided by this framework, we introduce FORT, a Framework of Shortcut-Resistant Training-Data Synthesis. FORT constructs shortcut-resistant training data by controlling shortcut risks across entity selection, evidence graph construction, question formulation, and adversarial refinement. Experiments show that FORT induces longer pre-answer search and fewer shortcut patterns than existing open-source deep search datasets. Using the resulting trajectories, we train FORT-Searcher with supervised fine-tuning (SFT) only, and it achieves the best overall performance among comparable-size open-source search agents on challenging deep search benchmarks. Relevant resources will be made available at https://github.com/RUCAIBox/FORT-Searcher.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.12087.png", "numComments": 1, "submittedBy": {"_id": "6544b9b646dbdeca34ee5f52", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6544b9b646dbdeca34ee5f52/nRx6m1C4wfZ_xSWoBUNJf.png", "fullname": "Yuyang Hu", "name": "namespace-ERI", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2606.13473", "authors": [{"_id": "6a2b6e314957fcdd3aac062f", "user": {"_id": "65352acb7139c5dd8d9a8590", "avatarUrl": "/avatars/e2ff22b596aee45cdfb8f68dc15572f9.svg", "isPro": false, "fullname": "JiachengChen", "user": "JC-Chen", "type": "user", "name": "JC-Chen"}, "name": "Jiacheng Chen", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:56:48.931Z", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0630", "name": "Xinyu Zhang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0631", "name": "Shunkai Zhang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0632", "name": "Yanmohan Wang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0633", "name": "Lin Li", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0634", "name": "Tiancheng Qin", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0635", "name": "Qin Wang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0636", "name": "Zhengmao Zhu", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0637", "name": "Tianle Li", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0638", "name": "Jingyang Li", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0639", "name": "Zehan Li", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac063a", "name": "Binyang Jiang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac063b", "name": "Jin Zhu", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac063c", "name": "Han Ding", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac063d", "name": "Fei Yu", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac063e", "name": "Chenyu Du", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac063f", "name": "Zijian Song", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0640", "name": "Jiayuan Song", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0641", "name": "Zhi Zhang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0642", "name": "Yunan Huang", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0643", "name": "Weiyu Cheng", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0644", "name": "Pengyu Zhao", "hidden": false}, {"_id": "6a2b6e314957fcdd3aac0645", "name": "Yu Cheng", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "MaxProof: Scaling Mathematical Proof with Generative-Verifier RL and Population-Level Test-Time Scaling", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "We present MaxProof, a population-level test-time scaling framework for competition-level mathematical proof in the MiniMax-M3 series. M3 first trains three proof-oriented capabilities -- proof generation, proof verification, and critique-conditioned proof repair -- using a defense-in-depth generative verifier engineered for low false-positive rate. These capabilities are merged into a single released M3 model. At test time, MaxProof treats the model as a generator, verifier, refiner, and ranker, searches over a population of candidate proofs, and returns one final proof through tournament selection. With MaxProof test-time scaling, the M3 model reaches 35/42 on IMO 2025 and 36/42 on USAMO 2026, exceeding the human gold-medal threshold on both.", "upvotes": 69, "discussionId": "6a2b6e314957fcdd3aac0646", "ai_summary": "MaxProof is a test-time scaling framework that enhances mathematical proof generation by combining multiple proof-oriented capabilities and using population-level search with tournament selection to achieve competitive performance on high-level mathematical competitions.", "ai_keywords": ["test-time scaling", "mathematical proof", "MiniMax-M3 series", "proof generation", "proof verification", "critique-conditioned proof repair", "generative verifier", "tournament selection"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "6778fc29920093dbc0c24917", "name": "MiniMaxAI", "fullname": "MiniMax", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/676e38ad04af5bec20bc9faf/dUd-LsZEX0H_d4qefO_g6.jpeg"}, "summary_zh": "<ul>\n    <li>MaxProof\u662f\u4e00\u79cd\u7528\u4e8e\u7ade\u8d5b\u7ea7\u6570\u5b66\u8bc1\u660e\u7684\u6d4b\u8bd5\u65f6\u95f4\u6269\u5c55\u6846\u67b6\u3002</li>\n    <li>M3\u6a21\u578b\u9996\u5148\u8bad\u7ec3\u4e86\u4e09\u79cd\u80fd\u529b\uff1a\u751f\u6210\u8bc1\u660e\u3001\u9a8c\u8bc1\u8bc1\u660e\u548c\u4fee\u590d\u8bc1\u660e\u3002</li>\n    <li>\u8fd9\u4e9b\u80fd\u529b\u5408\u5e76\u6210\u4e00\u4e2a\u6574\u4f53\u7684M3\u6a21\u578b\u53d1\u5e03\u3002</li>\n    <li>\u5728\u6d4b\u8bd5\u65f6\uff0cMaxProof\u5c06\u6a21\u578b\u7528\u4f5c\u751f\u6210\u5668\u3001\u9a8c\u8bc1\u5668\u3001\u4f18\u5316\u5668\u548c\u6392\u5e8f\u5668\uff0c\u9009\u62e9\u6700\u7ec8\u8bc1\u660e\u3002</li>\n    <li>\u4f7f\u7528MaxProof\uff0cM3\u6a21\u578b\u5728IMO 2025\u548cUSAMO 2026\u4e2d\u8d85\u8fc7\u4e86\u4eba\u7c7b\u91d1\u724c\u7684\u6807\u51c6\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>MaxProof is a new framework designed to improve mathematical proofs at a population level.</li>\n    <li>It combines three main skills: creating proofs, checking their correctness, and fixing any issues in the proofs.</li>\n    <li>The framework uses a special verifier that has a low chance of making mistakes.</li>\n    <li>During testing, MaxProof looks at many possible proofs and selects the best one using a tournament method.</li>\n    <li>With MaxProof, the M3 model performed very well, scoring above human experts in recent math competitions.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "MaxProof: Scaling Mathematical Proof with Generative-Verifier RL and Population-Level Test-Time Scaling", "summary": "We present MaxProof, a population-level test-time scaling framework for competition-level mathematical proof in the MiniMax-M3 series. M3 first trains three proof-oriented capabilities -- proof generation, proof verification, and critique-conditioned proof repair -- using a defense-in-depth generative verifier engineered for low false-positive rate. These capabilities are merged into a single released M3 model. At test time, MaxProof treats the model as a generator, verifier, refiner, and ranker, searches over a population of candidate proofs, and returns one final proof through tournament selection. With MaxProof test-time scaling, the M3 model reaches 35/42 on IMO 2025 and 36/42 on USAMO 2026, exceeding the human gold-medal threshold on both.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13473.png", "numComments": 0, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 316, "isUserFollowing": false}, "organization": {"_id": "6778fc29920093dbc0c24917", "name": "MiniMaxAI", "fullname": "MiniMax", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/676e38ad04af5bec20bc9faf/dUd-LsZEX0H_d4qefO_g6.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.11926", "authors": [{"_id": "6a2a238680a9c7c6830c0f1c", "name": "Jiajie Jin", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f1d", "user": {"_id": "6544b9b646dbdeca34ee5f52", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6544b9b646dbdeca34ee5f52/nRx6m1C4wfZ_xSWoBUNJf.png", "isPro": false, "fullname": "Yuyang Hu", "user": "namespace-ERI", "type": "user", "name": "namespace-ERI"}, "name": "Yuyang Hu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-11T08:38:18.829Z", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f1e", "name": "Kai Qiu", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f1f", "name": "Qi Dai", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f20", "name": "Chong Luo", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f21", "user": {"_id": "61cd4b833dd34ba1985e0753", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/61cd4b833dd34ba1985e0753/BfHfrwotoMESpXZOHiIe4.png", "isPro": false, "fullname": "KABI", "user": "dongguanting", "type": "user", "name": "dongguanting"}, "name": "Guanting Dong", "status": "claimed_verified", "statusLastChangedAt": "2026-06-11T08:38:16.710Z", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f22", "name": "Xiaoxi Li", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f23", "name": "Tong Zhao", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f24", "name": "Xiaolong Ma", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f25", "name": "Gongrui Zhang", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f26", "name": "Zhirong Wu", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f27", "name": "Bei Liu", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f28", "name": "Zhengyuan Yang", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f29", "name": "Linjie Li", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f2a", "name": "Lijuan Wang", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f2b", "name": "Hongjin Qian", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f2c", "name": "Yutao Zhu", "hidden": false}, {"_id": "6a2a238680a9c7c6830c0f2d", "name": "Zhicheng Dou", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6544b9b646dbdeca34ee5f52/oR8IjFj2gazUkimyf1o7n.mp4"], "publishedAt": "2026-06-10T00:00:00.000Z", "submittedOnDailyAt": "2026-06-11T00:00:00.000Z", "title": "Toward Generalist Autonomous Research via Hypothesis-Tree Refinement", "submittedOnDailyBy": {"_id": "6544b9b646dbdeca34ee5f52", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6544b9b646dbdeca34ee5f52/nRx6m1C4wfZ_xSWoBUNJf.png", "isPro": false, "fullname": "Yuyang Hu", "user": "namespace-ERI", "type": "user", "name": "namespace-ERI"}, "summary": "Scientific progress depends on a repeated loop of exploration, experimentation, and abstraction. Researchers test candidate directions, interpret the evidence, and carry the resulting lessons into later attempts. We study how an AI agent can run this loop autonomously over long horizons. We introduce Arbor, a general framework for autonomous research that combines a long-lived coordinator, short-lived executors, and Hypothesis Tree Refinement (HTR), a persistent tree that links hypotheses, artifacts, evidence, and distilled insights across time. The coordinator manages global research strategy over the tree, while executors implement and test individual hypotheses in isolated worktrees. As results return, Arbor updates the tree, propagates reusable lessons, refines the search frontier, and admits verified improvements. This design turns autonomous research from a sequence of local attempts into a cumulative process in which strategy, execution, and evidence are carried across time. We evaluate Arbor under Autonomous Optimization (AO), an operational setting where an agent improves an initial research artifact through iterative experimentation without step-level human supervision. Across six real research tasks in model training, harness engineering, and data synthesis, Arbor achieves the best held-out result on all six tasks, attaining more than 2.5x the average relative held-out gain of Codex and Claude Code under the same task interface and resource budget. On MLE-Bench Lite, Arbor reaches 86.36% Any Medal with GPT-5.5, the strongest result in our comparison.", "upvotes": 68, "discussionId": "6a2a238680a9c7c6830c0f2e", "projectPage": "https://ruc-nlpir.github.io/Arbor/", "githubRepo": "https://github.com/RUC-NLPIR/Arbor", "githubRepoAddedBy": "user", "ai_summary": "An AI framework called Arbor enables autonomous scientific research by combining strategic coordination, isolated hypothesis testing, and a persistent knowledge tree to iteratively improve research outcomes across multiple domains.", "ai_keywords": ["autonomous research", "long horizons", "Hypothesis Tree Refinement", "coordinator", "executors", "worktrees", "iterative experimentation", "research artifact", "held-out result", "MLE-Bench Lite"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 89, "organization": {"_id": "6695ed048765c1560ce56423", "name": "RUC-NLPIR", "fullname": "NLPIR Lab @ RUC", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/625e62452a7279d3c77b5c38/CBwmyPCRzm4rHTGWhiCzR.jpeg"}, "summary_zh": "<ul>\n    <li>\u79d1\u5b66\u8fdb\u6b65\u4f9d\u8d56\u4e8e\u63a2\u7d22\u3001\u5b9e\u9a8c\u548c\u62bd\u8c61\u7684\u5faa\u73af\u8fc7\u7a0b\u3002</li>\n    <li>\u6211\u4eec\u7814\u7a76\u4e86\u4e00\u4e2aAI\u4ee3\u7406\u5982\u4f55\u81ea\u4e3b\u5730\u8fdb\u884c\u957f\u671f\u7684\u7814\u7a76\u5faa\u73af\u3002</li>\n    <li>\u4ecb\u7ecd\u4e86Arbor\u6846\u67b6\uff0c\u5b83\u7ed3\u5408\u4e86\u957f\u671f\u534f\u8c03\u8005\u548c\u77ed\u671f\u6267\u884c\u8005\uff0c\u4ee5\u53ca\u4e00\u4e2a\u6301\u4e45\u7684\u5047\u8bbe\u6811\u3002</li>\n    <li>\u534f\u8c03\u8005\u7ba1\u7406\u6574\u4f53\u7814\u7a76\u7b56\u7565\uff0c\u800c\u6267\u884c\u8005\u5728\u72ec\u7acb\u5de5\u4f5c\u6811\u4e2d\u6d4b\u8bd5\u5047\u8bbe\u3002</li>\n    <li>\u5728\u516d\u4e2a\u5b9e\u9645\u7814\u7a76\u4efb\u52a1\u4e2d\uff0cArbor\u8868\u73b0\u4f18\u8d8a\uff0c\u53d6\u5f97\u4e86\u6700\u4f73\u7ed3\u679c\uff0c\u63d0\u5347\u4e86\u7814\u7a76\u6548\u7387\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Scientific progress relies on a cycle of exploration, testing, and learning from results.</li>\n    <li>Arbor is an AI system designed to conduct this research cycle automatically over long periods.</li>\n    <li>It features a coordinator that oversees the research strategy and executors that test specific ideas.</li>\n    <li>Arbor updates its knowledge base as it gathers results, improving future research efforts.</li>\n    <li>In tests, Arbor outperformed other AI systems, achieving significantly better results on various research tasks.</li>\n</ul>"}, "publishedAt": "2026-06-09T20:00:00.000Z", "title": "Toward Generalist Autonomous Research via Hypothesis-Tree Refinement", "summary": "Scientific progress depends on a repeated loop of exploration, experimentation, and abstraction. Researchers test candidate directions, interpret the evidence, and carry the resulting lessons into later attempts. We study how an AI agent can run this loop autonomously over long horizons. We introduce Arbor, a general framework for autonomous research that combines a long-lived coordinator, short-lived executors, and Hypothesis Tree Refinement (HTR), a persistent tree that links hypotheses, artifacts, evidence, and distilled insights across time. The coordinator manages global research strategy over the tree, while executors implement and test individual hypotheses in isolated worktrees. As results return, Arbor updates the tree, propagates reusable lessons, refines the search frontier, and admits verified improvements. This design turns autonomous research from a sequence of local attempts into a cumulative process in which strategy, execution, and evidence are carried across time. We evaluate Arbor under Autonomous Optimization (AO), an operational setting where an agent improves an initial research artifact through iterative experimentation without step-level human supervision. Across six real research tasks in model training, harness engineering, and data synthesis, Arbor achieves the best held-out result on all six tasks, attaining more than 2.5x the average relative held-out gain of Codex and Claude Code under the same task interface and resource budget. On MLE-Bench Lite, Arbor reaches 86.36% Any Medal with GPT-5.5, the strongest result in our comparison.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6544b9b646dbdeca34ee5f52/oR8IjFj2gazUkimyf1o7n.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.11926.png", "numComments": 3, "submittedBy": {"_id": "6544b9b646dbdeca34ee5f52", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6544b9b646dbdeca34ee5f52/nRx6m1C4wfZ_xSWoBUNJf.png", "fullname": "Yuyang Hu", "name": "namespace-ERI", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4, "isUserFollowing": false}, "organization": {"_id": "6695ed048765c1560ce56423", "name": "RUC-NLPIR", "fullname": "NLPIR Lab @ RUC", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/625e62452a7279d3c77b5c38/CBwmyPCRzm4rHTGWhiCzR.jpeg"}, "isAuthorParticipating": true}],
    "month": [{"paper": {"id": "2606.09967", "authors": [{"_id": "6a28c3c5e7d78ea7587e52bd", "name": "Ming Qian", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52be", "name": "Tianjian Ouyang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52bf", "name": "Mingchao Sun", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c0", "name": "Zijian Wang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c1", "name": "Jincheng Xiong", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c2", "name": "Jiarong Han", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c3", "name": "Yongchang Zhang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c4", "name": "Jiawei Zhang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c5", "name": "Xu Wang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c6", "name": "Yu Liu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c7", "name": "Luyang Tang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c8", "name": "Fei Yu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c9", "name": "Zengye Ge", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52ca", "name": "Mengmeng Du", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cb", "name": "Yuan Liu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cc", "name": "Nianfei Fan", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cd", "name": "Song Wang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52ce", "name": "Yingliang Peng", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cf", "name": "Chunxue Jia", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d0", "name": "Yang Liu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d1", "name": "Shiying Zeng", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d2", "name": "Haozhe Shi", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d3", "name": "Junnan Lai", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d4", "name": "Hongyu Pan", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d5", "name": "Zheng Wu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d6", "name": "Ning Guo", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d7", "name": "Mu Xu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d8", "name": "Hang Zhang", "hidden": false}], "publishedAt": "2026-06-08T00:00:00.000Z", "submittedOnDailyAt": "2026-06-10T00:00:00.000Z", "title": "ABot-Earth 0.5: Generative 3D Earth Model", "submittedOnDailyBy": {"_id": "6433bc32a4c9c55871a42812", "avatarUrl": "/avatars/c27c063d02419b8ba32657514c07e3b2.svg", "isPro": false, "fullname": "qian#143", "user": "qian43", "type": "user", "name": "qian43"}, "summary": "We present ABot-Earth 0.5, a generative 3D framework designed to synthesize vast, seamless 3D environments from ubiquitous, geospatially referenced satellite imagery. To achieve this, we propose a novel generative model formulated directly with the 3D Gaussian Splatting (3DGS) representation. The model is trained on a diverse corpus of existing real-world urban reconstructions, learning to generate realistic geometry and textures. At inference, it synthesizes novel 3D scenes conditioned solely on satellite imagery at a scalable rate of under 10 minutes per square kilometer, while demonstrating exceptional realism. The framework is designed for accessibility, with integrated hierarchical level-of-detail (LOD) structures that permit real-time, interactive visualization on web-based map engines. This high-fidelity simulation sandbox effectively mitigates the sim-to-real domain gap, enabling critical downstream Embodied AI applications like closed-loop UAV navigation. By providing an ultra-low-cost and high-efficiency solution, ABot-Earth 0.5 significantly lowers the technical and financial barriers to large-scale 3D reconstruction and empowers the future of global digital earth visualization.", "upvotes": 194, "discussionId": "6a28c3c5e7d78ea7587e52d9", "projectPage": "https://abot-earth.amap.com/", "githubRepo": "https://github.com/amap-cvlab/ABot-Earth-0.5", "githubRepoAddedBy": "user", "ai_summary": "ABot-Earth 0.5 generates realistic 3D environments from satellite imagery using 3D Gaussian Splatting representation, enabling fast synthesis and real-time visualization for Embodied AI applications.", "ai_keywords": ["3D Gaussian Splatting", "generative model", "satellite imagery", "3D environment synthesis", "level-of-detail", "real-time visualization", "Embodied AI", "UAV navigation", "digital earth visualization"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 109, "organization": {"_id": "641415d08900ef6afa2fcb73", "name": "acvlab", "fullname": "Alibaba AMAP CV Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6414106ce7d5f817d204e160/dfveRtrRy8Xn7QpG684zl.png"}, "summary_zh": "<ul>\n    <li>ABot-Earth 0.5\u662f\u4e00\u4e2a\u751f\u6210\u5f0f3D\u6846\u67b6\uff0c\u53ef\u4ee5\u4ece\u536b\u661f\u56fe\u50cf\u5408\u6210\u65e0\u7f1d\u76843D\u73af\u5883\u3002</li>\n    <li>\u8be5\u6a21\u578b\u4f7f\u75283D Gaussian Splatting (3DGS)\u8868\u793a\u6cd5\uff0c\u5e76\u5728\u771f\u5b9e\u57ce\u5e02\u91cd\u5efa\u6570\u636e\u4e0a\u8fdb\u884c\u8bad\u7ec3\uff0c\u4ee5\u751f\u6210\u903c\u771f\u7684\u51e0\u4f55\u5f62\u72b6\u548c\u7eb9\u7406\u3002</li>\n    <li>\u5408\u6210\u65b03D\u573a\u666f\u53ea\u9700\u572810\u5206\u949f\u5185\u5b8c\u6210\u6bcf\u5e73\u65b9\u516c\u91cc\uff0c\u4e14\u6548\u679c\u6781\u4e3a\u771f\u5b9e\u3002</li>\n    <li>\u6846\u67b6\u5177\u6709\u5c42\u6b21\u5316\u7ec6\u8282\uff08LOD\uff09\u7ed3\u6784\uff0c\u652f\u6301\u7f51\u7edc\u5730\u56fe\u5f15\u64ce\u7684\u5b9e\u65f6\u4e92\u52a8\u53ef\u89c6\u5316\u3002</li>\n    <li>ABot-Earth 0.5\u964d\u4f4e\u4e86\u5927\u89c4\u6a213D\u91cd\u5efa\u7684\u6280\u672f\u548c\u8d22\u52a1\u95e8\u69db\uff0c\u4fc3\u8fdb\u5168\u7403\u6570\u5b57\u5730\u7403\u53ef\u89c6\u5316\u7684\u53d1\u5c55\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>ABot-Earth 0.5 is a new tool that creates detailed 3D environments using satellite images.</li>\n    <li>It uses a unique model to learn from existing urban 3D designs, generating realistic shapes and textures.</li>\n    <li>The tool can create new 3D scenes from satellite pictures in less than 10 minutes per square kilometer.</li>\n    <li>It allows for real-time viewing on web maps and helps improve AI applications like drone navigation.</li>\n    <li>ABot-Earth 0.5 makes 3D reconstruction cheaper and easier, promoting better global digital maps.</li>\n</ul>"}, "publishedAt": "2026-06-07T20:00:00.000Z", "title": "ABot-Earth 0.5: Generative 3D Earth Model", "summary": "We present ABot-Earth 0.5, a generative 3D framework designed to synthesize vast, seamless 3D environments from ubiquitous, geospatially referenced satellite imagery. To achieve this, we propose a novel generative model formulated directly with the 3D Gaussian Splatting (3DGS) representation. The model is trained on a diverse corpus of existing real-world urban reconstructions, learning to generate realistic geometry and textures. At inference, it synthesizes novel 3D scenes conditioned solely on satellite imagery at a scalable rate of under 10 minutes per square kilometer, while demonstrating exceptional realism. The framework is designed for accessibility, with integrated hierarchical level-of-detail (LOD) structures that permit real-time, interactive visualization on web-based map engines. This high-fidelity simulation sandbox effectively mitigates the sim-to-real domain gap, enabling critical downstream Embodied AI applications like closed-loop UAV navigation. By providing an ultra-low-cost and high-efficiency solution, ABot-Earth 0.5 significantly lowers the technical and financial barriers to large-scale 3D reconstruction and empowers the future of global digital earth visualization.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.09967.png", "numComments": 3, "submittedBy": {"_id": "6433bc32a4c9c55871a42812", "avatarUrl": "/avatars/c27c063d02419b8ba32657514c07e3b2.svg", "fullname": "qian#143", "name": "qian43", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 6, "isUserFollowing": false}, "organization": {"_id": "641415d08900ef6afa2fcb73", "name": "acvlab", "fullname": "Alibaba AMAP CV Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6414106ce7d5f817d204e160/dfveRtrRy8Xn7QpG684zl.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.10651", "authors": [{"_id": "6a28cfb8e7d78ea7587e5406", "name": "Kwai Keye Team", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5407", "name": "Bin Wen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5408", "name": "Changyi Liu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5409", "name": "Chengru Song", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540a", "name": "Chongling Rao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540b", "name": "Guowang Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540c", "name": "Han Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540d", "name": "Haonan Fan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540e", "name": "Hengrui Ju", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540f", "name": "Jiankang Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5410", "name": "Jiapeng Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5411", "name": "Jiawei Yuan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5412", "name": "Kaixuan Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5413", "name": "Kaiyu Jiang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5414", "name": "Kun Gai", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5415", "name": "Lingzhi Zhou", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5416", "name": "Na Nie", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5417", "name": "Sen Na", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5418", "name": "Tianke Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5419", "name": "Tingting Gao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541a", "name": "Xuanyu Zheng", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541b", "name": "Yulong Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541c", "name": "Fan Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541d", "name": "Haixuan Gao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541e", "name": "Lele Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541f", "name": "Mingqiao Liu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5420", "name": "Muxi Diao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5421", "name": "Qi Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5422", "name": "Qile Su", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5423", "name": "Wei Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5424", "name": "Wentao Hong", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5425", "name": "Xingyu Lu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5426", "name": "Yancheng Long", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5427", "name": "Yankai Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5428", "name": "Yingxin Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5429", "name": "Yiyang Fan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542a", "name": "Yu Xia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542b", "name": "Yuzhe Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542c", "name": "Ziliang Lai", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542d", "name": "Chuan Yi", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542e", "name": "Haonan Jia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542f", "name": "Tianming Liang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5430", "name": "Weixin Xu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5431", "name": "Xiaoxiao Ma", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5432", "name": "Yang Tian", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5433", "name": "Yufei Han", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5434", "name": "Feng Han", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5435", "name": "Hang Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5436", "name": "Jing Wang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5437", "name": "Jinghui Jia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5438", "name": "Junmin Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5439", "name": "Junyu Shi", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e543a", "name": "Ruilin Zhang", "hidden": false}], "publishedAt": "2026-06-09T00:00:00.000Z", "submittedOnDailyAt": "2026-06-10T00:00:00.000Z", "title": "Kwai Keye-VL-2.0 Technical Report", "submittedOnDailyBy": {"_id": "66c98c27fafc0fc87c280749", "avatarUrl": "/avatars/c71db3bee0fcd9aabcc38fd871d1cb75.svg", "isPro": false, "fullname": "Tianming Liang", "user": "liangtm", "type": "user", "name": "liangtm"}, "summary": "We introduce Kwai Keye-VL-2.0-30B-A3B, an open-source Mixture-of-Experts (MoE) multimodal foundation model designed to advance long-video understanding and agentic intelligence. To address the challenges of ultra-long contexts, information redundancy, and prohibitive computational costs inherent in hour-level videos, Keye-VL-2.0 is the first to adapt DeepSeek Sparse Attention (DSA) to GQA-based multimodal architectures, enabling lossless 256K context processing while capturing critical frames and long-range temporal dependencies. This architecture is underpinned by a highly optimized training and inference infrastructure, including scalable video I/O, heterogeneous ViT-LM parallelism, and custom DSA kernels that significantly maximize throughput and minimize computational overhead. Furthermore, to overcome the algorithmic dilemma of catastrophic forgetting during multi-task alignment, we introduce Cross-Modal Multi-Teacher On-Policy Distillation (MOPD) paired with Context-RL and Video-RL. By distilling dense token-level teacher feedback from on-policy rollouts back into the MoE backbone, which activates only 3B parameters, Keye-VL-2.0 natively empowers advanced agent collaboration across Code, Tool, and Search scenarios with multimodal self-correction. Extensive evaluations across video understanding, temporal grounding, reasoning, STEM, and agent benchmarks demonstrate that Keye-VL-2.0-30B-A3B achieves state-of-the-art performance among models of similar scale, particularly excelling in fine-grained temporal localization on TimeLens and long-video comprehension on Video-MME-v2 and LongVideoBench. We release our model checkpoints to accelerate community progress toward scalable and robust multimodal agentic applications.", "upvotes": 167, "discussionId": "6a28cfb8e7d78ea7587e543b", "projectPage": "https://kwai-keye.github.io/", "githubRepo": "https://github.com/Kwai-Keye/Keye", "githubRepoAddedBy": "user", "ai_summary": "Kwai Keye-VL-2.0-30B-A3B is an open-source Mixture-of-Experts multimodal foundation model that enables long-video understanding and agentic intelligence through DeepSeek Sparse Attention and specialized training infrastructure.", "ai_keywords": ["Mixture-of-Experts", "multimodal foundation model", "DeepSeek Sparse Attention", "GQA-based architectures", "256K context processing", "heterogeneous ViT-LM parallelism", "custom DSA kernels", "Cross-Modal Multi-Teacher On-Policy Distillation", "Context-RL", "Video-RL", "dense token-level teacher feedback", "on-policy rollouts", "agent collaboration", "Code", "Tool", "Search scenarios", "multimodal self-correction"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 785, "organization": {"_id": "685d2e9b7aa0388f4fcaf7b2", "name": "KwaiKeye", "fullname": "Kwai Keye", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/685ba798484e3233f5ff6f11/gW0pROtvsWctypxYTBbWZ.png"}, "summary_zh": "<ul>\n    <li>\u6211\u4eec\u4ecb\u7ecd\u4e86Kwai Keye-VL-2.0-30B-A3B\uff0c\u8fd9\u662f\u4e00\u4e2a\u5f00\u6e90\u7684\u591a\u6a21\u6001\u57fa\u7840\u6a21\u578b\uff0c\u65e8\u5728\u63d0\u9ad8\u5bf9\u957f\u89c6\u9891\u7684\u7406\u89e3\u548c\u667a\u80fd\u4ee3\u7406\u80fd\u529b\u3002</li>\n    <li>\u8be5\u6a21\u578b\u91c7\u7528\u4e86DeepSeek\u7a00\u758f\u6ce8\u610f\u529b\u673a\u5236\uff0c\u80fd\u591f\u5904\u7406256K\u4e0a\u4e0b\u6587\u4fe1\u606f\uff0c\u5e76\u6355\u6349\u91cd\u8981\u5e27\u548c\u957f\u65f6\u95f4\u7684\u4f9d\u8d56\u5173\u7cfb\u3002</li>\n    <li>Keye-VL-2.0\u5177\u6709\u4f18\u5316\u7684\u8bad\u7ec3\u548c\u63a8\u7406\u57fa\u7840\u8bbe\u65bd\uff0c\u652f\u6301\u53ef\u6269\u5c55\u7684\u89c6\u9891\u8f93\u5165\u8f93\u51fa\u548c\u9ad8\u6548\u7684\u5e76\u884c\u5904\u7406\u3002</li>\n    <li>\u4e3a\u4e86\u89e3\u51b3\u591a\u4efb\u52a1\u5bf9\u9f50\u4e2d\u7684\u9057\u5fd8\u95ee\u9898\uff0c\u6a21\u578b\u5f15\u5165\u4e86\u8de8\u6a21\u6001\u591a\u6559\u5e08\u5728\u7ebf\u84b8\u998f\u6280\u672f\uff0c\u53ef\u4ee5\u63d0\u9ad8\u591a\u6a21\u6001\u81ea\u6211\u4fee\u6b63\u80fd\u529b\u3002</li>\n    <li>\u5728\u591a\u4e2a\u89c6\u9891\u7406\u89e3\u548c\u667a\u80fd\u4ee3\u7406\u7684\u57fa\u51c6\u6d4b\u8bd5\u4e2d\uff0cKeye-VL-2.0\u8868\u73b0\u4f18\u5f02\uff0c\u5c24\u5176\u5728\u957f\u89c6\u9891\u7406\u89e3\u65b9\u9762\u8fbe\u5230\u4e86\u884c\u4e1a\u9886\u5148\u6c34\u5e73\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Kwai Keye-VL-2.0-30B-A3B is an open-source model that helps understand long videos and improve intelligent agents.</li>\n    <li>It uses a special attention technique to handle very long video contexts without losing important information.</li>\n    <li>The model is built with efficient training methods to reduce computing costs and improve performance.</li>\n    <li>It includes a new way to prevent loss of information when learning multiple tasks, enhancing collaboration between different tools and codes.</li>\n    <li>Keye-VL-2.0 shows top performance in video understanding and other tasks, and the team is sharing the model to help others in the field.</li>\n</ul>"}, "publishedAt": "2026-06-08T20:00:00.000Z", "title": "Kwai Keye-VL-2.0 Technical Report", "summary": "We introduce Kwai Keye-VL-2.0-30B-A3B, an open-source Mixture-of-Experts (MoE) multimodal foundation model designed to advance long-video understanding and agentic intelligence. To address the challenges of ultra-long contexts, information redundancy, and prohibitive computational costs inherent in hour-level videos, Keye-VL-2.0 is the first to adapt DeepSeek Sparse Attention (DSA) to GQA-based multimodal architectures, enabling lossless 256K context processing while capturing critical frames and long-range temporal dependencies. This architecture is underpinned by a highly optimized training and inference infrastructure, including scalable video I/O, heterogeneous ViT-LM parallelism, and custom DSA kernels that significantly maximize throughput and minimize computational overhead. Furthermore, to overcome the algorithmic dilemma of catastrophic forgetting during multi-task alignment, we introduce Cross-Modal Multi-Teacher On-Policy Distillation (MOPD) paired with Context-RL and Video-RL. By distilling dense token-level teacher feedback from on-policy rollouts back into the MoE backbone, which activates only 3B parameters, Keye-VL-2.0 natively empowers advanced agent collaboration across Code, Tool, and Search scenarios with multimodal self-correction. Extensive evaluations across video understanding, temporal grounding, reasoning, STEM, and agent benchmarks demonstrate that Keye-VL-2.0-30B-A3B achieves state-of-the-art performance among models of similar scale, particularly excelling in fine-grained temporal localization on TimeLens and long-video comprehension on Video-MME-v2 and LongVideoBench. We release our model checkpoints to accelerate community progress toward scalable and robust multimodal agentic applications.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.10651.png", "numComments": 1, "submittedBy": {"_id": "66c98c27fafc0fc87c280749", "avatarUrl": "/avatars/c71db3bee0fcd9aabcc38fd871d1cb75.svg", "fullname": "Tianming Liang", "name": "liangtm", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "685d2e9b7aa0388f4fcaf7b2", "name": "KwaiKeye", "fullname": "Kwai Keye", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/685ba798484e3233f5ff6f11/gW0pROtvsWctypxYTBbWZ.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.22355", "authors": [{"_id": "6a0fc10ea53a61ce2e422c9a", "user": {"_id": "6964ab352fb9f77cbe8c9854", "avatarUrl": "/avatars/2c4734b40bb98d162837fbe6b128f7d7.svg", "isPro": false, "fullname": "Hanyu Guo", "user": "MaoPaJia", "type": "user", "name": "MaoPaJia"}, "name": "Hanyu Guo", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:08:45.926Z", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9b", "name": "Jiedong Yang", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9c", "name": "Chao Chen", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9d", "user": {"_id": "682eeb11d28d9650c926abb0", "avatarUrl": "/avatars/3c8a34cc61aa2330ffcb52446a9afe70.svg", "isPro": false, "fullname": "LONGFEI XU", "user": "Xufew", "type": "user", "name": "Xufew"}, "name": "Longfei Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:08:49.010Z", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9e", "name": "Kaikui Liu", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9f", "name": "Xiangxiang Chu", "hidden": false}], "publishedAt": "2026-05-21T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "TransitLM: A Large-Scale Dataset and Benchmark for Map-Free Transit Route Generation", "submittedOnDailyBy": {"_id": "66d255e3947594430c723ff6", "avatarUrl": "/avatars/c56e4792332a01bf34085a75ee64916e.svg", "isPro": false, "fullname": "xiaochonglinghu", "user": "xiaochonglinghu", "type": "user", "name": "xiaochonglinghu"}, "summary": "Public transit route planning traditionally depends on structured map infrastructure and complex routing engines, and no existing dataset supports training models to bypass this dependency. We present TransitLM, a large-scale dataset of over 13 million transit route planning records from four Chinese cities covering 120,845 stations and 13,666 lines, released as a continual pre-training corpus and benchmark data for three evaluation tasks with complementary metrics. Experiments show that an LLM trained on TransitLM produces structurally valid routes at high accuracy and implicitly grounds arbitrary GPS coordinates to appropriate stations without any explicit mapping. These results demonstrate that transit route planning can be learned entirely from data, enabling end-to-end, map-free route generation directly from origin-destination information. The dataset and benchmark are available at https://huggingface.co/datasets/GD-ML/TransitLM, with evaluation code at https://github.com/HotTricker/TransitLM.", "upvotes": 162, "discussionId": "6a0fc10ea53a61ce2e422ca0", "githubRepo": "https://github.com/HotTricker/TransitLM", "githubRepoAddedBy": "user", "ai_summary": "TransitLM dataset enables end-to-end transit route planning using large language models trained on structured transit data, eliminating the need for traditional map-based approaches.", "ai_keywords": ["large language models", "transit route planning", "structured map infrastructure", "routing engines", "continual pre-training", "evaluation tasks", "GPS coordinates", "origin-destination information"], "githubStars": 107, "organization": {"_id": "67d11771890254196d3174e5", "name": "GD-ML", "fullname": "AMAP-ML", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67d116c47be76de1a40873ca/s5ukAx9E36ZZIKvbpBRi4.png"}, "summary_zh": "<ul>\n    <li>TransitLM\u662f\u4e00\u4e2a\u5927\u578b\u6570\u636e\u96c6\uff0c\u5305\u542b\u6765\u81ea\u56db\u4e2a\u4e2d\u56fd\u57ce\u5e02\u76841300\u591a\u4e07\u6761\u516c\u5171\u4ea4\u901a\u8def\u7ebf\u89c4\u5212\u8bb0\u5f55\u3002</li>\n    <li>\u6570\u636e\u96c6\u8986\u76d6\u4e86120,845\u4e2a\u7ad9\u70b9\u548c13,666\u6761\u7ebf\u8def\uff0c\u65e8\u5728\u652f\u6301\u516c\u5171\u4ea4\u901a\u8def\u7ebf\u89c4\u5212\u6a21\u578b\u7684\u8bad\u7ec3\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u57fa\u4e8eTransitLM\u8bad\u7ec3\u7684\u5927\u578b\u8bed\u8a00\u6a21\u578b\u80fd\u591f\u9ad8\u51c6\u786e\u7387\u751f\u6210\u6709\u6548\u7684\u8def\u7ebf\uff0c\u5e76\u5c06\u4efb\u610fGPS\u5750\u6807\u5bf9\u5e94\u5230\u5408\u9002\u7684\u7ad9\u70b9\u3002</li>\n    <li>\u8fd9\u4e00\u7814\u7a76\u8868\u660e\uff0c\u516c\u5171\u4ea4\u901a\u8def\u7ebf\u89c4\u5212\u53ef\u4ee5\u5b8c\u5168\u901a\u8fc7\u6570\u636e\u5b66\u4e60\uff0c\u65e0\u9700\u4f9d\u8d56\u5730\u56fe\uff0c\u5b9e\u73b0\u4ece\u8d77\u70b9\u5230\u7ec8\u70b9\u7684\u76f4\u63a5\u8def\u7ebf\u751f\u6210\u3002</li>\n    <li>\u6570\u636e\u96c6\u548c\u8bc4\u4f30\u57fa\u51c6\u53ef\u5728\u6307\u5b9a\u7f51\u7ad9\u4e0a\u83b7\u53d6\uff0c\u5305\u542b\u8bc4\u4f30\u4ee3\u7801\u7684\u94fe\u63a5\u4e5f\u5df2\u63d0\u4f9b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>TransitLM is a new dataset with over 13 million transit route records from four cities in China.</li>\n    <li>It includes information on 120,845 stations and 13,666 transit lines.</li>\n    <li>The dataset can help train models to plan routes without needing traditional maps or complex systems.</li>\n    <li>Experiments show that models trained on this dataset can create accurate transit routes using just start and end points.</li>\n    <li>The dataset and tools for evaluation are available online for public use.</li>\n</ul>"}, "publishedAt": "2026-05-20T20:00:00.000Z", "title": "TransitLM: A Large-Scale Dataset and Benchmark for Map-Free Transit Route Generation", "summary": "Public transit route planning traditionally depends on structured map infrastructure and complex routing engines, and no existing dataset supports training models to bypass this dependency. We present TransitLM, a large-scale dataset of over 13 million transit route planning records from four Chinese cities covering 120,845 stations and 13,666 lines, released as a continual pre-training corpus and benchmark data for three evaluation tasks with complementary metrics. Experiments show that an LLM trained on TransitLM produces structurally valid routes at high accuracy and implicitly grounds arbitrary GPS coordinates to appropriate stations without any explicit mapping. These results demonstrate that transit route planning can be learned entirely from data, enabling end-to-end, map-free route generation directly from origin-destination information. The dataset and benchmark are available at https://huggingface.co/datasets/GD-ML/TransitLM, with evaluation code at https://github.com/HotTricker/TransitLM.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.22355.png", "numComments": 2, "submittedBy": {"_id": "66d255e3947594430c723ff6", "avatarUrl": "/avatars/c56e4792332a01bf34085a75ee64916e.svg", "fullname": "xiaochonglinghu", "name": "xiaochonglinghu", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "67d11771890254196d3174e5", "name": "GD-ML", "fullname": "AMAP-ML", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67d116c47be76de1a40873ca/s5ukAx9E36ZZIKvbpBRi4.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.28816", "authors": [{"_id": "6a17a1c1b4840f905a67423f", "name": "Fangfu Liu", "hidden": false}, {"_id": "6a17a1c1b4840f905a674240", "name": "Kai He", "hidden": false}, {"_id": "6a17a1c1b4840f905a674241", "name": "Tianchang Shen", "hidden": false}, {"_id": "6a17a1c1b4840f905a674242", "name": "Tianshi Cao", "hidden": false}, {"_id": "6a17a1c1b4840f905a674243", "name": "Sanja Fidler", "hidden": false}, {"_id": "6a17a1c1b4840f905a674244", "name": "Yueqi Duan", "hidden": false}, {"_id": "6a17a1c1b4840f905a674245", "name": "Jun Gao", "hidden": false}, {"_id": "6a17a1c1b4840f905a674246", "name": "Igor Gilitschenski", "hidden": false}, {"_id": "6a17a1c1b4840f905a674247", "name": "Zian Wang", "hidden": false}, {"_id": "6a17a1c1b4840f905a674248", "name": "Xuanchi Ren", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/_NpefLBu0wIqfoZP0K0uR.png", "https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/A2fGxpraAXcD9_RIUiZX2.mp4"], "publishedAt": "2026-05-27T00:00:00.000Z", "submittedOnDailyAt": "2026-05-28T00:00:00.000Z", "title": "Gamma-World: Generative Multi-Agent World Modeling Beyond Two Players", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "World models for interactive video generation have largely focused on single-agent settings, where future observations are generated from a single control signal. However, many generated environments require multi-agent interaction: multiple players, robots, or embodied agents act simultaneously within a shared space. Scaling world models to such settings requires a principled multi-agent design: agents should remain independently controllable, permutation-symmetric, and support efficient inference while maintaining consistency across time and perspectives. In this paper, we present our generative multi-agent world model for interactive simulation. It introduces Simplex Rotary Agent Encoding, a parameter-free extension of 3D RoPE that represents agents as vertices of a regular simplex in rotary angle space. This gives each agent a distinct phase while making all agents permutation-equivalent, enabling scalable agent identity without learned per-slot identities or a fixed agent ordering. To avoid dense all-to-all attention across agents, we further propose Sparse Hub Attention, where learnable hub tokens mediate token interaction across agents, reducing cross-agent attention cost from quadratic to linear in the number of agents. For real-time rollout, we distill a full-context diffusion teacher into a causal student that generates temporal blocks sequentially with KV caching, enabling action-responsive generation at 24 FPS. Experiments in multiplayer virtual environments show that our model improves video fidelity, action controllability, and inter-agent consistency over slot-based and dense-attention baselines, while generalizing from two to four players without additional training.", "upvotes": 156, "discussionId": "6a17a1c2b4840f905a674249", "projectPage": "https://research.nvidia.com/labs/sil/projects/gamma-world/", "ai_summary": "A generative multi-agent world model is presented that uses simplex rotary agent encoding and sparse hub attention to enable scalable, permutation-symmetric interaction between multiple agents in interactive video generation.", "ai_keywords": ["world models", "multi-agent interaction", "rotary angle space", "permutation-symmetric", "sparse hub attention", "causal student", "KV caching", "diffusion teacher", "action-responsive generation"], "organization": {"_id": "60262b67268c201cdc8b7d43", "name": "nvidia", "fullname": "NVIDIA", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65df9200dc3292a8983e5017/Vs5FPVCH-VZBipV3qKTuy.png"}, "summary_zh": "<ul>\n    <li>\u672c\u7814\u7a76\u63d0\u51fa\u4e86\u4e00\u79cd\u591a\u667a\u80fd\u4f53\u4e16\u754c\u6a21\u578b\uff0c\u7528\u4e8e\u4ea4\u4e92\u5f0f\u89c6\u9891\u751f\u6210\u3002</li>\n    <li>\u6a21\u578b\u8bbe\u8ba1\u4f7f\u5f97\u591a\u4e2a\u667a\u80fd\u4f53\u53ef\u4ee5\u5728\u5171\u4eab\u7a7a\u95f4\u4e2d\u72ec\u7acb\u63a7\u5236\uff0c\u5e76\u4e14\u4fdd\u6301\u4e00\u81f4\u6027\u3002</li>\n    <li>\u5f15\u5165\u4e86Simplex Rotary Agent Encoding\uff0c\u4f7f\u6bcf\u4e2a\u667a\u80fd\u4f53\u5177\u6709\u72ec\u7279\u7684\u76f8\u4f4d\uff0c\u540c\u65f6\u4fdd\u6301\u53ef\u6269\u5c55\u6027\u3002</li>\n    <li>\u63d0\u51fa\u4e86\u7a00\u758f\u4e2d\u5fc3\u6ce8\u610f\u529b\u673a\u5236\uff0c\u964d\u4f4e\u4e86\u667a\u80fd\u4f53\u95f4\u7684\u6ce8\u610f\u529b\u8ba1\u7b97\u6210\u672c\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u8be5\u6a21\u578b\u5728\u591a\u4eba\u865a\u62df\u73af\u5883\u4e2d\u63d0\u9ad8\u4e86\u89c6\u9891\u8d28\u91cf\u3001\u52a8\u4f5c\u53ef\u63a7\u6027\u548c\u667a\u80fd\u4f53\u4e4b\u95f4\u7684\u4e00\u81f4\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Current video generation models mainly focus on single-agent scenarios, but many environments require multiple agents to interact simultaneously.</li>\n    <li>The paper presents a new multi-agent world model that allows agents to be independently controlled while being able to interact in a shared space.</li>\n    <li>It introduces a unique encoding method that represents agents as vertices in a way that keeps them interchangeable and allows for scalable identities.</li>\n    <li>The model uses a technique called Sparse Hub Attention to reduce the computational cost of interactions between agents.</li>\n    <li>Tests show that this new model improves video quality and responsiveness in multiplayer settings, working well with different numbers of players without extra training.</li>\n</ul>"}, "publishedAt": "2026-05-26T20:00:00.000Z", "title": "Gamma-World: Generative Multi-Agent World Modeling Beyond Two Players", "summary": "World models for interactive video generation have largely focused on single-agent settings, where future observations are generated from a single control signal. However, many generated environments require multi-agent interaction: multiple players, robots, or embodied agents act simultaneously within a shared space. Scaling world models to such settings requires a principled multi-agent design: agents should remain independently controllable, permutation-symmetric, and support efficient inference while maintaining consistency across time and perspectives. In this paper, we present our generative multi-agent world model for interactive simulation. It introduces Simplex Rotary Agent Encoding, a parameter-free extension of 3D RoPE that represents agents as vertices of a regular simplex in rotary angle space. This gives each agent a distinct phase while making all agents permutation-equivalent, enabling scalable agent identity without learned per-slot identities or a fixed agent ordering. To avoid dense all-to-all attention across agents, we further propose Sparse Hub Attention, where learnable hub tokens mediate token interaction across agents, reducing cross-agent attention cost from quadratic to linear in the number of agents. For real-time rollout, we distill a full-context diffusion teacher into a causal student that generates temporal blocks sequentially with KV caching, enabling action-responsive generation at 24 FPS. Experiments in multiplayer virtual environments show that our model improves video fidelity, action controllability, and inter-agent consistency over slot-based and dense-attention baselines, while generalizing from two to four players without additional training.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/_NpefLBu0wIqfoZP0K0uR.png", "https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/A2fGxpraAXcD9_RIUiZX2.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.28816.png", "numComments": 1, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 307, "isUserFollowing": false}, "organization": {"_id": "60262b67268c201cdc8b7d43", "name": "nvidia", "fullname": "NVIDIA", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65df9200dc3292a8983e5017/Vs5FPVCH-VZBipV3qKTuy.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.23904", "authors": [{"_id": "6a13aad74d9e8d8602d201a8", "user": {"_id": "62d18eb81e36881a57f29bf4", "avatarUrl": "/avatars/104851421b4ee9641daaf15942fa7ea1.svg", "isPro": false, "fullname": "Yif Yang", "user": "Yif29", "type": "user", "name": "Yif29"}, "name": "Yifan Yang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-25T15:12:31.312Z", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201a9", "user": {"_id": "660691330be1fbe3b9e4c33d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/660691330be1fbe3b9e4c33d/TxrDFH_cRu3AlpMC3xmhv.jpeg", "isPro": false, "fullname": "ZiYang Gong", "user": "Cusyoung", "type": "user", "name": "Cusyoung"}, "name": "Ziyang Gong", "status": "claimed_verified", "statusLastChangedAt": "2026-05-25T15:12:29.154Z", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201aa", "name": "Weiquan Huang", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201ab", "name": "Qihao Yang", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201ac", "name": "Ziwei Zhou", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201ad", "user": {"_id": "662b6a8f0b7f23f3c000559e", "avatarUrl": "/avatars/0a5b4e09ac9a8e40342131319ff32b29.svg", "isPro": false, "fullname": "Zisu Huang", "user": "zisuh", "type": "user", "name": "zisuh"}, "name": "Zisu Huang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-25T15:12:25.187Z", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201ae", "name": "Yan Li", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201af", "name": "Xuemei Gao", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201b0", "name": "Qi Dai", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201b1", "name": "Bei Liu", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201b2", "name": "Kai Qiu", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201b3", "name": "Yuqing Yang", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201b4", "name": "Dongdong Chen", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201b5", "name": "Xue Yang", "hidden": false}, {"_id": "6a13aad74d9e8d8602d201b6", "name": "Chong Luo", "hidden": false}], "publishedAt": "2026-05-22T00:00:00.000Z", "submittedOnDailyAt": "2026-05-25T00:00:00.000Z", "title": "SkillOpt: Executive Strategy for Self-Evolving Agent Skills", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Agent skills today are hand-crafted, generated one-shot, or evolved through loosely controlled self-revision, none of which behaves like a deep-learning optimizer for the skill, and none of which reliably improves over its starting point under feedback. We argue the skill should instead be trained as the external state of a frozen agent, with the same discipline that makes weight-space optimization reproducible. SkillOpt is, to our knowledge, the first systematic controllable text-space optimizer for agent skills: a separate optimizer model turns scored rollouts into bounded add/delete/replace edits on a single skill document, and an edit is accepted only when it strictly improves a held-out validation score. A textual learning-rate budget, rejected-edit buffer, and epoch-wise slow/meta update make skill training stable while adding zero inference-time model calls at deployment. Across six benchmarks, seven target models, and three execution harnesses (direct chat, Codex, Claude Code), SkillOpt is best or tied on all 52 evaluated (model, benchmark, harness) cells and beats every per-cell competitor among human, one-shot LLM, Trace2Skill, TextGrad, GEPA, and EvoSkill skills. On GPT-5.5 it lifts the average no-skill accuracy by +23.5 points in direct chat, by +24.8 inside the Codex agentic loop, and by +19.1 inside Claude Code. Transfer experiments further show that optimized skill artifacts retain value when moved across model scales, between Codex and Claude Code execution environments, and to a nearby math benchmark without further optimization.", "upvotes": 155, "discussionId": "6a13aad74d9e8d8602d201b7", "projectPage": "https://microsoft.github.io/SkillOpt/", "githubRepo": "https://github.com/microsoft/SkillOpt", "githubRepoAddedBy": "user", "ai_summary": "SkillOpt introduces a systematic text-space optimizer for agent skills that trains skills as external agent state with stable updates and zero deployment inference overhead, achieving superior performance across multiple benchmarks and execution environments.", "ai_keywords": ["agent skills", "skill training", "text-space optimizer", "rollouts", "add/delete/replace edits", "validation score", "textual learning-rate budget", "rejected-edit buffer", "epoch-wise slow/meta update", "skill optimization", "transfer experiments", "agent state", "reproducible optimization"], "githubStars": 72, "organization": {"_id": "68151d0f51add3813f3f7d1b", "name": "MicrosoftResearch", "fullname": "Microsoft Research", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6529a4f2f1205983224fa513/PeuVr7jSuJflmDBBGxoDX.png"}, "summary_zh": "<ul>\n    <li>\u76ee\u524d\u7684\u667a\u80fd\u4f53\u6280\u80fd\u662f\u624b\u5de5\u5236\u4f5c\u6216\u901a\u8fc7\u81ea\u6211\u4fee\u6b63\u751f\u6210\u7684\uff0c\u65e0\u6cd5\u50cf\u6df1\u5ea6\u5b66\u4e60\u4f18\u5316\u5668\u90a3\u6837\u6709\u6548\u63d0\u5347\u6280\u80fd\u3002</li>\n    <li>SkillOpt\u662f\u9996\u4e2a\u7cfb\u7edf\u5316\u7684\u53ef\u63a7\u6587\u672c\u7a7a\u95f4\u4f18\u5316\u5668\uff0c\u901a\u8fc7\u4f18\u5316\u6a21\u578b\u5bf9\u6280\u80fd\u8fdb\u884c\u6539\u8fdb\uff0c\u786e\u4fdd\u53ea\u5728\u63d0\u9ad8\u9a8c\u8bc1\u5f97\u5206\u65f6\u63a5\u53d7\u7f16\u8f91\u3002</li>\n    <li>SkillOpt\u5728\u516d\u4e2a\u57fa\u51c6\u6d4b\u8bd5\u548c\u591a\u4e2a\u6267\u884c\u73af\u5883\u4e2d\u8868\u73b0\u4f18\u5f02\uff0c\u8d85\u8fc7\u4e86\u6240\u6709\u5176\u4ed6\u7ade\u4e89\u5bf9\u624b\u3002</li>\n    <li>\u5728GPT-5.5\u4e0a\uff0cSkillOpt\u663e\u8457\u63d0\u9ad8\u4e86\u76f4\u63a5\u804a\u5929\u3001Codex\u548cClaude Code\u7684\u65e0\u6280\u80fd\u51c6\u786e\u7387\u3002</li>\n    <li>\u4f18\u5316\u540e\u7684\u6280\u80fd\u5728\u4e0d\u540c\u6a21\u578b\u95f4\u8fc1\u79fb\u548c\u6267\u884c\u73af\u5883\u4e2d\u4fdd\u6301\u4ef7\u503c\uff0c\u4e14\u65e0\u9700\u8fdb\u4e00\u6b65\u4f18\u5316\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Current agent skills are manually created or adjusted but do not improve reliably with feedback.</li>\n    <li>SkillOpt is a new method that optimizes agent skills systematically, using a separate model to edit skills based on performance scores.</li>\n    <li>Edits to the skills are only accepted if they improve validation scores, ensuring better quality skills.</li>\n    <li>SkillOpt performs exceptionally well across various tests, improving accuracy significantly in different scenarios.</li>\n    <li>Optimized skills can be used effectively across different models and environments without needing further adjustments.</li>\n</ul>"}, "publishedAt": "2026-05-21T20:00:00.000Z", "title": "SkillOpt: Executive Strategy for Self-Evolving Agent Skills", "summary": "Agent skills today are hand-crafted, generated one-shot, or evolved through loosely controlled self-revision, none of which behaves like a deep-learning optimizer for the skill, and none of which reliably improves over its starting point under feedback. We argue the skill should instead be trained as the external state of a frozen agent, with the same discipline that makes weight-space optimization reproducible. SkillOpt is, to our knowledge, the first systematic controllable text-space optimizer for agent skills: a separate optimizer model turns scored rollouts into bounded add/delete/replace edits on a single skill document, and an edit is accepted only when it strictly improves a held-out validation score. A textual learning-rate budget, rejected-edit buffer, and epoch-wise slow/meta update make skill training stable while adding zero inference-time model calls at deployment. Across six benchmarks, seven target models, and three execution harnesses (direct chat, Codex, Claude Code), SkillOpt is best or tied on all 52 evaluated (model, benchmark, harness) cells and beats every per-cell competitor among human, one-shot LLM, Trace2Skill, TextGrad, GEPA, and EvoSkill skills. On GPT-5.5 it lifts the average no-skill accuracy by +23.5 points in direct chat, by +24.8 inside the Codex agentic loop, and by +19.1 inside Claude Code. Transfer experiments further show that optimized skill artifacts retain value when moved across model scales, between Codex and Claude Code execution environments, and to a nearby math benchmark without further optimization.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.23904.png", "numComments": 2, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 304, "isUserFollowing": false}, "organization": {"_id": "68151d0f51add3813f3f7d1b", "name": "MicrosoftResearch", "fullname": "Microsoft Research", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6529a4f2f1205983224fa513/PeuVr7jSuJflmDBBGxoDX.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2605.22109", "authors": [{"_id": "6a0fb91ea53a61ce2e422c1c", "name": "Caixin Kang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c1d", "name": "Tianyu Yan", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c1e", "name": "Sitong Gong", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c1f", "name": "Mingfang Zhang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c20", "name": "Liangyang Ouyang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c21", "name": "Ruicong Liu", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c22", "name": "Bo Zheng", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c23", "name": "Huchuan Lu", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c24", "name": "Kaipeng Zhang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c25", "name": "Yoichi Sato", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c26", "name": "Yifei Huang", "hidden": false}], "publishedAt": "2026-05-21T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "Perception or Prejudice: Can MLLMs Go Beyond First Impressions of Personality?", "submittedOnDailyBy": {"_id": "63a286c7f30c4642278ed11a", "avatarUrl": "/avatars/974fe4f3023791e97228c53330e9b4f3.svg", "isPro": false, "fullname": "Tim Kang", "user": "Ukpkmkkk", "type": "user", "name": "Ukpkmkkk"}, "summary": "Multimodal Large Language Models (MLLMs) are increasingly deployed in human-facing roles where personality perception is critical, yet existing benchmarks evaluate this capability solely on numerical Big Five score prediction, leaving open whether models truly perceive personality through behavioral understanding or merely prejudge through superficial pattern matching. We address this gap with three contributions. (i) A new task: we formalize Grounded Personality Reasoning (GPR), which requires MLLMs to anchor each Big Five rating in observable evidence through a chain of rating, reasoning, and grounding. (ii) A new dataset: we release MM-OCEAN (1,104 videos, 5,320 MCQs), produced by a multi-agent pipeline with human verification, with timestamped behavioral observations, evidence-grounded trait analyses, and seven categories of cue-grounding MCQs. (iii) Benchmark and analysis: we design a three-tier evaluation (rating, reasoning, grounding) plus four sample-level failure-mode metrics: Prejudice Rate (PR), Confabulation Rate (CR), Integration-failure Rate (IR), and Holistic-grounding Rate (HR), and benchmark 27 MLLMs (13 closed, 14 open). The analysis uncovers a striking Prejudice Gap: across the field, 51% of correct ratings are not grounded in retrieved cues, and the Holistic-Grounding Rate spans only 0-33.5%. These findings expose a disconnect between getting the right score and reasoning for the right reason, charting a roadmap for grounded social cognition in MLLMs.", "upvotes": 151, "discussionId": "6a0fb91fa53a61ce2e422c27", "githubRepo": "https://github.com/kkkcx/MM-OCEAN", "githubRepoAddedBy": "user", "ai_summary": "Researchers introduce a new task and dataset for evaluating personality reasoning in multimodal language models, revealing significant gaps between accurate predictions and grounded reasoning processes.", "ai_keywords": ["Multimodal Large Language Models", "Big Five score prediction", "Grounded Personality Reasoning", "MM-OCEAN dataset", "chain of rating", "reasoning", "and grounding", "multi-agent pipeline", "behavioral observations", "evidence-grounded trait analyses", "cue-grounding MCQs", "three-tier evaluation", "Prejudice Rate", "Confabulation Rate", "Integration-failure Rate", "Holistic-grounding Rate"], "githubStars": 5, "organization": {"_id": "6a0fbe68162dc5d32a0057a0", "name": "utokyo-ai", "fullname": "The University of Tokyo", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/63a286c7f30c4642278ed11a/jNLYa73JGG4k3ywpoD_9k.png"}, "summary_zh": "<ul>\n    <li>\u591a\u6a21\u6001\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08MLLMs\uff09\u8d8a\u6765\u8d8a\u591a\u5730\u7528\u4e8e\u4e0e\u4eba\u7c7b\u4e92\u52a8\u7684\u89d2\u8272\uff0c\u4f46\u73b0\u6709\u8bc4\u4f30\u65b9\u6cd5\u4ec5\u901a\u8fc7\u4e94\u5927\u4eba\u683c\u8bc4\u5206\u7684\u6570\u5b57\u9884\u6d4b\u6765\u8bc4\u4ef7\u5b83\u4eec\u7684\u80fd\u529b\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u4e2a\u65b0\u4efb\u52a1\u2014\u2014\u201c\u57fa\u4e8e\u8bc1\u636e\u7684\u4eba\u683c\u63a8\u7406\u201d\uff08GPR\uff09\uff0c\u8981\u6c42MLLMs\u901a\u8fc7\u8bc4\u5206\u3001\u63a8\u7406\u548c\u8bc1\u636e\u8054\u7cfb\u6765\u652f\u6301\u6bcf\u4e2a\u4e94\u5927\u4eba\u683c\u8bc4\u5206\u3002</li>\n    <li>\u6211\u4eec\u53d1\u5e03\u4e86\u4e00\u4e2a\u65b0\u6570\u636e\u96c6MM-OCEAN\uff0c\u5305\u542b1104\u4e2a\u89c6\u9891\u548c5320\u9053\u591a\u9879\u9009\u62e9\u9898\uff0c\u7ecf\u8fc7\u591a\u4ee3\u7406\u7ba1\u9053\u548c\u4eba\u5de5\u9a8c\u8bc1\uff0c\u5305\u542b\u65f6\u95f4\u6233\u7684\u884c\u4e3a\u89c2\u5bdf\u548c\u8bc1\u636e\u57fa\u7840\u7684\u4eba\u683c\u5206\u6790\u3002</li>\n    <li>\u6211\u4eec\u8bbe\u8ba1\u4e86\u4e09\u5c42\u8bc4\u4f30\u6807\u51c6\uff08\u8bc4\u5206\u3001\u63a8\u7406\u3001\u8bc1\u636e\u8054\u7cfb\uff09\u548c\u56db\u4e2a\u6837\u672c\u7ea7\u5931\u8d25\u6a21\u5f0f\u6307\u6807\uff0c\u8bc4\u4f3027\u4e2aMLLMs\uff0c\u53d1\u73b051%\u7684\u6b63\u786e\u8bc4\u5206\u6ca1\u6709\u57fa\u4e8e\u68c0\u7d22\u5230\u7684\u7ebf\u7d22\uff0c\u6574\u4f53\u8054\u7cfb\u7387\u4ec5\u4e3a0-33.5%\u3002</li>\n    <li>\u8fd9\u4e9b\u53d1\u73b0\u63ed\u793a\u4e86\u6b63\u786e\u8bc4\u5206\u4e0e\u6b63\u786e\u63a8\u7406\u4e4b\u95f4\u7684\u8131\u8282\uff0c\u4e3aMLLMs\u7684\u57fa\u4e8e\u8bc1\u636e\u7684\u793e\u4f1a\u8ba4\u77e5\u63d0\u4f9b\u4e86\u65b0\u65b9\u5411\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Multimodal Large Language Models (MLLMs) are used in roles where understanding personality is important, but current tests only check if they can predict personality scores numerically.</li>\n    <li>The authors introduce a new task called Grounded Personality Reasoning (GPR), which requires models to support their personality ratings with observable evidence.</li>\n    <li>They created a new dataset, MM-OCEAN, which includes videos and multiple-choice questions that provide behavioral observations and trait analyses.</li>\n    <li>The study evaluates 27 MLLMs using a detailed three-part system and finds that many models make correct ratings without proper evidence, highlighting a gap in true understanding.</li>\n    <li>The results show that while models can get the right scores, they often fail to explain their reasoning correctly, suggesting a need for better social understanding in MLLMs.</li>\n</ul>"}, "publishedAt": "2026-05-20T20:00:00.000Z", "title": "Perception or Prejudice: Can MLLMs Go Beyond First Impressions of Personality?", "summary": "Multimodal Large Language Models (MLLMs) are increasingly deployed in human-facing roles where personality perception is critical, yet existing benchmarks evaluate this capability solely on numerical Big Five score prediction, leaving open whether models truly perceive personality through behavioral understanding or merely prejudge through superficial pattern matching. We address this gap with three contributions. (i) A new task: we formalize Grounded Personality Reasoning (GPR), which requires MLLMs to anchor each Big Five rating in observable evidence through a chain of rating, reasoning, and grounding. (ii) A new dataset: we release MM-OCEAN (1,104 videos, 5,320 MCQs), produced by a multi-agent pipeline with human verification, with timestamped behavioral observations, evidence-grounded trait analyses, and seven categories of cue-grounding MCQs. (iii) Benchmark and analysis: we design a three-tier evaluation (rating, reasoning, grounding) plus four sample-level failure-mode metrics: Prejudice Rate (PR), Confabulation Rate (CR), Integration-failure Rate (IR), and Holistic-grounding Rate (HR), and benchmark 27 MLLMs (13 closed, 14 open). The analysis uncovers a striking Prejudice Gap: across the field, 51% of correct ratings are not grounded in retrieved cues, and the Holistic-Grounding Rate spans only 0-33.5%. These findings expose a disconnect between getting the right score and reasoning for the right reason, charting a roadmap for grounded social cognition in MLLMs.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.22109.png", "numComments": 1, "submittedBy": {"_id": "63a286c7f30c4642278ed11a", "avatarUrl": "/avatars/974fe4f3023791e97228c53330e9b4f3.svg", "fullname": "Tim Kang", "name": "Ukpkmkkk", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "organization": {"_id": "6a0fbe68162dc5d32a0057a0", "name": "utokyo-ai", "fullname": "The University of Tokyo", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/63a286c7f30c4642278ed11a/jNLYa73JGG4k3ywpoD_9k.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.18747", "authors": [{"_id": "6a0bd45c8ca2d0b2563803fe", "name": "Xuying Ning", "hidden": false}, {"_id": "6a0bd45c8ca2d0b2563803ff", "name": "Katherine Tieu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380400", "name": "Dongqi Fu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380401", "name": "Tianxin Wei", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380402", "name": "Zihao Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380403", "name": "Yuanchen Bei", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380404", "name": "Jiaru Zou", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380405", "name": "Mengting Ai", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380406", "name": "Zhining Liu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380407", "name": "Ting-Wei Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380408", "name": "Lingjie Chen", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380409", "name": "Yanjun Zhao", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040a", "name": "Ke Yang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040b", "name": "Bingxuan Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040c", "name": "Cheng Qian", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040d", "name": "Gaotang Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040e", "name": "Xiao Lin", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040f", "name": "Zhichen Zeng", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380410", "name": "Ruizhong Qiu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380411", "name": "Sirui Chen", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380412", "name": "Yifan Sun", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380413", "name": "Xiyuan Yang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380414", "name": "Ruida Wang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380415", "name": "Rui Pan", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380416", "name": "Chenyuan Yang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380417", "name": "Dylan Zhang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380418", "name": "Liri Fang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380419", "name": "Zikun Cui", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041a", "name": "Yang Cao", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041b", "name": "Pan Chen", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041c", "name": "Dorothy Sun", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041d", "name": "Ren Chen", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041e", "name": "Mahesh Srinivasan", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041f", "name": "Nipun Mathur", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380420", "name": "Yinglong Xia", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380421", "name": "Hong Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380422", "name": "Hong Yan", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380423", "name": "Pan Lu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380424", "name": "Lingming Zhang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380425", "name": "Tong Zhang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380426", "name": "Hanghang Tong", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380427", "name": "Jingrui He", "hidden": false}], "publishedAt": "2026-05-18T00:00:00.000Z", "submittedOnDailyAt": "2026-05-19T00:00:00.000Z", "title": "Code as Agent Harness", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Recent large language models (LLMs) have demonstrated strong capabilities in understanding and generating code, from competitive programming to repository-level software engineering. In emerging agentic systems, code is no longer only a target output. It increasingly serves as an operational substrate for agent reasoning, acting, environment modeling, and execution-based verification. We frame this shift through the lens of agent harnesses and introduce code as agent harness: a unified view that centers code as the basis for agent infrastructure. To systematically study this perspective, we organize the survey around three connected layers. First, we study the harness interface, where code connects agents to reasoning, action, and environment modeling. Second, we examine harness mechanisms: planning, memory, and tool use for long-horizon execution, together with feedback-driven control and optimization that make harness reliable and adaptive. Third, we discuss scaling the harness from single-agent systems to multi-agent settings, where shared code artifacts support multi-agent coordination, review, and verification. Across these layers, we summarize representative methods and practical applications of code as agent harness, spanning coding assistants, GUI/OS automation, embodied agents, scientific discovery, personalization and recommendation, DevOps, and enterprise workflows. We further outline open challenges for harness engineering, including evaluation beyond final task success, verification under incomplete feedback, regression-free harness improvement, consistent shared state across multiple agents, human oversight for safety-critical actions, and extensions to multimodal environments. By centering code as the harness of agentic AI, this survey provides a unified roadmap toward executable, verifiable, and stateful AI agent systems.", "upvotes": 137, "discussionId": "6a0bd45c8ca2d0b256380428", "githubRepo": "https://github.com/YennNing/Awesome-Code-as-Agent-Harness-Papers", "githubRepoAddedBy": "user", "ai_summary": "Large language models are increasingly used as operational substrates for agent reasoning and execution in agentic systems, with code serving as a unified infrastructure layer across multiple domains and applications.", "ai_keywords": ["large language models", "agentic systems", "agent harness", "code as agent harness", "agent infrastructure", "reasoning", "action", "environment modeling", "planning", "memory", "tool use", "feedback-driven control", "optimization", "multi-agent coordination", "DevOps", "enterprise workflows"], "githubStars": 24, "summary_zh": "<ul>\n    <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLMs\uff09\u5728\u7406\u89e3\u548c\u751f\u6210\u4ee3\u7801\u65b9\u9762\u8868\u73b0\u51fa\u8272\uff0c\u9002\u7528\u4e8e\u7ade\u4e89\u7f16\u7a0b\u548c\u8f6f\u4ef6\u5de5\u7a0b\u3002</li>\n    <li>\u4ee3\u7801\u4e0d\u4ec5\u662f\u8f93\u51fa\u76ee\u6807\uff0c\u8fd8\u4f5c\u4e3a\u667a\u80fd\u4f53\u63a8\u7406\u548c\u6267\u884c\u7684\u57fa\u7840\u3002</li>\n    <li>\u7814\u7a76\u5206\u4e3a\u4e09\u4e2a\u5c42\u6b21\uff1a\u63a5\u53e3\uff08\u4ee3\u7801\u8fde\u63a5\u667a\u80fd\u4f53\u4e0e\u63a8\u7406\u3001\u884c\u52a8\u548c\u73af\u5883\u5efa\u6a21\uff09\u3001\u673a\u5236\uff08\u89c4\u5212\u3001\u8bb0\u5fc6\u548c\u5de5\u5177\u4f7f\u7528\uff09\u548c\u591a\u667a\u80fd\u4f53\u7cfb\u7edf\u7684\u6269\u5c55\u3002</li>\n    <li>\u603b\u7ed3\u4e86\u4ee3\u7801\u5728\u667a\u80fd\u4f53\u57fa\u7840\u8bbe\u65bd\u4e2d\u7684\u5e94\u7528\uff0c\u5305\u62ec\u7f16\u7a0b\u52a9\u624b\u3001\u81ea\u52a8\u5316\u3001\u79d1\u5b66\u53d1\u73b0\u7b49\u3002</li>\n    <li>\u63d0\u51fa\u4e86\u5728\u5de5\u7a0b\u4e2d\u9762\u4e34\u7684\u6311\u6218\uff0c\u5982\u8bc4\u4f30\u65b9\u6cd5\u3001\u53cd\u9988\u4e0d\u8db3\u4e0b\u7684\u9a8c\u8bc1\u548c\u591a\u667a\u80fd\u4f53\u7684\u72b6\u6001\u4e00\u81f4\u6027\u7b49\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Recent large language models are good at understanding and generating code for various software tasks.</li>\n    <li>Code is now used not just as an output but as a key part of how intelligent agents think, act, and verify their actions.</li>\n    <li>The study introduces the concept of \"code as agent harness,\" which views code as the foundation for agent systems.</li>\n    <li>It explores three layers: the interface connecting code and agents, mechanisms for planning and control, and scaling from single to multi-agent systems.</li>\n    <li>The survey highlights practical uses of code in different fields and outlines challenges for improving agent systems, like ensuring safety and effective collaboration among agents.</li>\n</ul>"}, "publishedAt": "2026-05-17T20:00:00.000Z", "title": "Code as Agent Harness", "summary": "Recent large language models (LLMs) have demonstrated strong capabilities in understanding and generating code, from competitive programming to repository-level software engineering. In emerging agentic systems, code is no longer only a target output. It increasingly serves as an operational substrate for agent reasoning, acting, environment modeling, and execution-based verification. We frame this shift through the lens of agent harnesses and introduce code as agent harness: a unified view that centers code as the basis for agent infrastructure. To systematically study this perspective, we organize the survey around three connected layers. First, we study the harness interface, where code connects agents to reasoning, action, and environment modeling. Second, we examine harness mechanisms: planning, memory, and tool use for long-horizon execution, together with feedback-driven control and optimization that make harness reliable and adaptive. Third, we discuss scaling the harness from single-agent systems to multi-agent settings, where shared code artifacts support multi-agent coordination, review, and verification. Across these layers, we summarize representative methods and practical applications of code as agent harness, spanning coding assistants, GUI/OS automation, embodied agents, scientific discovery, personalization and recommendation, DevOps, and enterprise workflows. We further outline open challenges for harness engineering, including evaluation beyond final task success, verification under incomplete feedback, regression-free harness improvement, consistent shared state across multiple agents, human oversight for safety-critical actions, and extensions to multimodal environments. By centering code as the harness of agentic AI, this survey provides a unified roadmap toward executable, verifiable, and stateful AI agent systems.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.18747.png", "numComments": 3, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 300, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2605.21467", "authors": [{"_id": "6a0e89f1164dbbc68a26c5de", "user": {"_id": "6523afa7389ef6864de004a1", "avatarUrl": "/avatars/cdf04857038a7c8abadd2e2306835ebe.svg", "isPro": false, "fullname": "KaiyiZhang", "user": "Cardlnal", "type": "user", "name": "Cardlnal"}, "name": "Kaiyi Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-21T19:21:52.826Z", "hidden": false}, {"_id": "6a0e89f1164dbbc68a26c5df", "name": "Wei Wu", "hidden": false}, {"_id": "6a0e89f1164dbbc68a26c5e0", "name": "Yankai Lin", "hidden": false}], "publishedAt": "2026-05-20T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "DelTA: Discriminative Token Credit Assignment for Reinforcement Learning from Verifiable Rewards", "submittedOnDailyBy": {"_id": "6523afa7389ef6864de004a1", "avatarUrl": "/avatars/cdf04857038a7c8abadd2e2306835ebe.svg", "isPro": false, "fullname": "KaiyiZhang", "user": "Cardlnal", "type": "user", "name": "Cardlnal"}, "summary": "Reinforcement learning from verifiable rewards (RLVR) has emerged as a central technique for improving the reasoning capabilities of large language models. Despite its effectiveness, how response-level rewards translate into token-level probability changes remains poorly understood. We introduce a discriminator view of RLVR updates, showing that the policy-gradient update direction implicitly acts as a linear discriminator over token-gradient vectors and thereby determines which token probabilities are increased or decreased during learning. Under standard sequence-level RLVR, this discriminator is constructed from positive- and negative-side centroids formed by advantage-weighted averaging of token-gradient vectors. However, such centroid construction can be dominated by shared high-frequency patterns, such as formatting tokens, diluting sparse yet discriminative directions that better distinguish high-reward responses from low-reward ones. To address this limitation, we propose DelTA, a discriminative token credit assignment method that estimates token coefficients to amplify side-specific token-gradient directions and downweight shared or weakly discriminative ones. These coefficients reweight a self-normalized RLVR surrogate, making the effective side-wise centroids more contrastive and thereby reshaping the RLVR update direction. On seven mathematical benchmarks, DelTA outperforms the strongest same-scale baselines by 3.26 and 2.62 average points on Qwen3-8B-Base and Qwen3-14B-Base, respectively. Additional results on code generation, a different backbone, and out-of-domain evaluations further demonstrate the generalization ability of DelTA.", "upvotes": 124, "discussionId": "6a0e89f2164dbbc68a26c5e1", "githubRepo": "https://github.com/RUCBM/DelTA", "githubRepoAddedBy": "user", "ai_summary": "Reinforcement learning from verifiable rewards is enhanced through a discriminative token credit assignment method that improves reward-based training by amplifying distinctive token-gradient directions and reducing noise from shared patterns.", "ai_keywords": ["reinforcement learning from verifiable rewards", "policy-gradient update", "token-gradient vectors", "advantage-weighted averaging", "discriminative token credit assignment", "self-normalized RLVR surrogate", "side-wise centroids"], "githubStars": 4, "summary_zh": "<ul>\n    <li>\u5f3a\u5316\u5b66\u4e60\u4ece\u53ef\u9a8c\u8bc1\u5956\u52b1\uff08RLVR\uff09\u5df2\u6210\u4e3a\u63d0\u5347\u5927\u8bed\u8a00\u6a21\u578b\u63a8\u7406\u80fd\u529b\u7684\u5173\u952e\u6280\u672f\u3002</li>\n    <li>RLVR\u7684\u53cd\u9988\u5982\u4f55\u5f71\u54cd\u5355\u8bcd\u7684\u6982\u7387\u53d8\u5316\u4ecd\u7136\u4e0d\u592a\u6e05\u695a\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u7684\u89c6\u89d2\uff0c\u901a\u8fc7\u6784\u5efa\u5224\u522b\u5668\u6765\u66f4\u65b0RLVR\uff0c\u4ee5\u66f4\u597d\u5730\u7406\u89e3\u5b66\u4e60\u8fc7\u7a0b\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u7684DelTA\u65b9\u6cd5\u80fd\u591f\u66f4\u597d\u5730\u5206\u914d\u5956\u52b1\u7ed9\u7279\u5b9a\u7684\u5355\u8bcd\uff0c\u589e\u5f3a\u6709\u7528\u7684\u68af\u5ea6\u65b9\u5411\u3002</li>\n    <li>\u5728\u4e03\u4e2a\u6570\u5b66\u57fa\u51c6\u6d4b\u8bd5\u4e2d\uff0cDelTA\u7684\u8868\u73b0\u8d85\u8fc7\u4e86\u540c\u89c4\u6a21\u7684\u57fa\u7ebf\uff0c\u663e\u793a\u4e86\u5176\u5f3a\u5927\u7684\u6cdb\u5316\u80fd\u529b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Reinforcement learning from verifiable rewards (RLVR) helps improve the thinking skills of large language models.</li>\n    <li>The way rewards affect token-level probabilities in these models is not fully understood.</li>\n    <li>We introduced a method called DelTA, which focuses on better assigning credit to tokens based on their contribution to responses.</li>\n    <li>DelTA improves the learning process by emphasizing important tokens while reducing the influence of less relevant ones.</li>\n    <li>Tests show that DelTA performs significantly better than existing methods on several mathematical tasks and other evaluations.</li>\n</ul>"}, "publishedAt": "2026-05-19T20:00:00.000Z", "title": "DelTA: Discriminative Token Credit Assignment for Reinforcement Learning from Verifiable Rewards", "summary": "Reinforcement learning from verifiable rewards (RLVR) has emerged as a central technique for improving the reasoning capabilities of large language models. Despite its effectiveness, how response-level rewards translate into token-level probability changes remains poorly understood. We introduce a discriminator view of RLVR updates, showing that the policy-gradient update direction implicitly acts as a linear discriminator over token-gradient vectors and thereby determines which token probabilities are increased or decreased during learning. Under standard sequence-level RLVR, this discriminator is constructed from positive- and negative-side centroids formed by advantage-weighted averaging of token-gradient vectors. However, such centroid construction can be dominated by shared high-frequency patterns, such as formatting tokens, diluting sparse yet discriminative directions that better distinguish high-reward responses from low-reward ones. To address this limitation, we propose DelTA, a discriminative token credit assignment method that estimates token coefficients to amplify side-specific token-gradient directions and downweight shared or weakly discriminative ones. These coefficients reweight a self-normalized RLVR surrogate, making the effective side-wise centroids more contrastive and thereby reshaping the RLVR update direction. On seven mathematical benchmarks, DelTA outperforms the strongest same-scale baselines by 3.26 and 2.62 average points on Qwen3-8B-Base and Qwen3-14B-Base, respectively. Additional results on code generation, a different backbone, and out-of-domain evaluations further demonstrate the generalization ability of DelTA.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.21467.png", "numComments": 1, "submittedBy": {"_id": "6523afa7389ef6864de004a1", "avatarUrl": "/avatars/cdf04857038a7c8abadd2e2306835ebe.svg", "fullname": "KaiyiZhang", "name": "Cardlnal", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2605.25604", "authors": [{"_id": "6a150071b57a1823d5708a1c", "user": {"_id": "644a1dbb9c340e5e1e713153", "avatarUrl": "/avatars/21cb93ad067a798a39829ef7e67c70b8.svg", "isPro": false, "fullname": "JGC", "user": "Nothing2Say", "type": "user", "name": "Nothing2Say"}, "name": "Guochao Jiang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-26T07:48:12.892Z", "hidden": false}, {"_id": "6a150071b57a1823d5708a1d", "name": "Jingyi Song", "hidden": false}, {"_id": "6a150071b57a1823d5708a1e", "name": "Guofeng Quan", "hidden": false}, {"_id": "6a150071b57a1823d5708a1f", "user": {"_id": "64ae631b58bd9e9cc2f5a749", "avatarUrl": "/avatars/ce6426ec3bdb618a9e449297e7f147e0.svg", "isPro": false, "fullname": "Chuzhan HAO", "user": "Chuzhan", "type": "user", "name": "Chuzhan"}, "name": "Chuzhan Hao", "status": "claimed_verified", "statusLastChangedAt": "2026-05-26T07:48:05.761Z", "hidden": false}, {"_id": "6a150071b57a1823d5708a20", "name": "Guohua Liu", "hidden": false}, {"_id": "6a150071b57a1823d5708a21", "name": "Yuewei Zhang", "hidden": false}], "publishedAt": "2026-05-25T00:00:00.000Z", "submittedOnDailyAt": "2026-05-26T00:00:00.000Z", "title": "DVAO: Dynamic Variance-adaptive Advantage Optimization for Multi-reward Reinforcement Learning", "submittedOnDailyBy": {"_id": "644a1dbb9c340e5e1e713153", "avatarUrl": "/avatars/21cb93ad067a798a39829ef7e67c70b8.svg", "isPro": false, "fullname": "JGC", "user": "Nothing2Say", "type": "user", "name": "Nothing2Say"}, "summary": "Reinforcement Learning has become a standard paradigm for aligning Large Language Models with human intent and task requirements. While Group Relative Policy Optimization offers an efficient, value-model-free alternative to Proximal Policy Optimization, adapting it to real-world multi-reward settings remains challenging. Standard scalarization practices, such as Reward Combination and Advantage Combination, suffer from significant drawbacks: Reward Combination frequently generates advantages with excessively large squared magnitudes that lead to training instability, while Advantage Combination relies on static hyperparameters and ignores cross-objective correlations. To address these limitations, we propose Dynamic Variance-adaptive Advantage Optimization (DVAO), which dynamically adjusts combination weights based on the empirical reward variance of each objective within a rollout group, effectively up-weighting objectives with a stronger learning signal while suppressing noisy ones. We mathematically prove that DVAO maintains bounded advantage magnitudes for stable training and introduces a self-adaptive cross-objective regularization mechanism. Extensive experiments on mathematical reasoning and tool-use benchmarks using Qwen3 and Qwen2.5 models demonstrate that DVAO significantly outperforms baseline methods, achieving a superior multi-objective Pareto frontier and robust training stability.", "upvotes": 116, "discussionId": "6a150072b57a1823d5708a22", "ai_summary": "Dynamic Variance-adaptive Advantage Optimization (DVAO) addresses training instability in multi-reward reinforcement learning by adaptively weighting objectives based on empirical reward variance, maintaining bounded advantage magnitudes and improving multi-objective performance.", "ai_keywords": ["Reinforcement Learning", "Large Language Models", "Group Relative Policy Optimization", "Proximal Policy Optimization", "Reward Combination", "Advantage Combination", "Dynamic Variance-adaptive Advantage Optimization", "multi-objective Pareto frontier", "training stability", "empirical reward variance"], "summary_zh": "<ul>\n    <li>\u5f3a\u5316\u5b66\u4e60\u5df2\u6210\u4e3a\u5c06\u5927\u578b\u8bed\u8a00\u6a21\u578b\u4e0e\u4eba\u7c7b\u610f\u56fe\u5bf9\u9f50\u7684\u6807\u51c6\u65b9\u6cd5\u3002</li>\n    <li>\u73b0\u6709\u7684\u5956\u52b1\u7ec4\u5408\u65b9\u6cd5\u5b58\u5728\u7f3a\u9677\uff0c\u5bfc\u81f4\u8bad\u7ec3\u4e0d\u7a33\u5b9a\uff0c\u65e0\u6cd5\u6709\u6548\u5904\u7406\u591a\u5956\u52b1\u8bbe\u7f6e\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u52a8\u6001\u65b9\u5dee\u81ea\u9002\u5e94\u4f18\u52bf\u4f18\u5316\uff08DVAO\uff09\uff0c\u6839\u636e\u6bcf\u4e2a\u76ee\u6807\u7684\u7ecf\u9a8c\u5956\u52b1\u65b9\u5dee\u52a8\u6001\u8c03\u6574\u7ec4\u5408\u6743\u91cd\u3002</li>\n    <li>DVAO\u80fd\u591f\u4fdd\u6301\u4f18\u52bf\u5e45\u5ea6\u7684\u7a33\u5b9a\uff0c\u5e76\u5f15\u5165\u81ea\u9002\u5e94\u7684\u8de8\u76ee\u6807\u6b63\u5219\u5316\u673a\u5236\u3002</li>\n    <li>\u5728\u6570\u5b66\u63a8\u7406\u548c\u5de5\u5177\u4f7f\u7528\u57fa\u51c6\u6d4b\u8bd5\u4e2d\uff0cDVAO\u663e\u8457\u4f18\u4e8e\u57fa\u7ebf\u65b9\u6cd5\uff0c\u63d0\u5347\u4e86\u8bad\u7ec3\u7a33\u5b9a\u6027\u548c\u591a\u76ee\u6807\u6027\u80fd\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Reinforcement Learning helps align Large Language Models with what humans want and need.</li>\n    <li>Current methods for combining multiple rewards in training have problems that can cause instability.</li>\n    <li>Dynamic Variance-adaptive Advantage Optimization (DVAO) improves on these methods by adjusting weights based on reward variability.</li>\n    <li>DVAO keeps training stable by controlling the size of advantages and includes a mechanism to manage multiple objectives.</li>\n    <li>Tests show that DVAO performs better than other methods in tasks like math reasoning and tool use.</li>\n</ul>"}, "publishedAt": "2026-05-24T20:00:00.000Z", "title": "DVAO: Dynamic Variance-adaptive Advantage Optimization for Multi-reward Reinforcement Learning", "summary": "Reinforcement Learning has become a standard paradigm for aligning Large Language Models with human intent and task requirements. While Group Relative Policy Optimization offers an efficient, value-model-free alternative to Proximal Policy Optimization, adapting it to real-world multi-reward settings remains challenging. Standard scalarization practices, such as Reward Combination and Advantage Combination, suffer from significant drawbacks: Reward Combination frequently generates advantages with excessively large squared magnitudes that lead to training instability, while Advantage Combination relies on static hyperparameters and ignores cross-objective correlations. To address these limitations, we propose Dynamic Variance-adaptive Advantage Optimization (DVAO), which dynamically adjusts combination weights based on the empirical reward variance of each objective within a rollout group, effectively up-weighting objectives with a stronger learning signal while suppressing noisy ones. We mathematically prove that DVAO maintains bounded advantage magnitudes for stable training and introduces a self-adaptive cross-objective regularization mechanism. Extensive experiments on mathematical reasoning and tool-use benchmarks using Qwen3 and Qwen2.5 models demonstrate that DVAO significantly outperforms baseline methods, achieving a superior multi-objective Pareto frontier and robust training stability.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.25604.png", "numComments": 2, "submittedBy": {"_id": "644a1dbb9c340e5e1e713153", "avatarUrl": "/avatars/21cb93ad067a798a39829ef7e67c70b8.svg", "fullname": "JGC", "name": "Nothing2Say", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 5, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2605.19833", "authors": [{"_id": "6a0df8e4d1ef9ecdf71c0e9d", "user": {"_id": "678f850bec882f210c1b59f2", "avatarUrl": "/avatars/f25bab4afb86de92f75bf9a90e02f59f.svg", "isPro": false, "fullname": "XIE ZHIFEI", "user": "zhifeixie", "type": "user", "name": "zhifeixie"}, "name": "Zhifei Xie", "status": "admin_assigned", "statusLastChangedAt": "2026-05-21T13:39:13.670Z", "hidden": false}, {"_id": "6a0df8e4d1ef9ecdf71c0e9e", "name": "Kaiyu Pang", "hidden": false}, {"_id": "6a0df8e4d1ef9ecdf71c0e9f", "name": "Haobin Zhang", "hidden": false}, {"_id": "6a0df8e4d1ef9ecdf71c0ea0", "name": "Deheng Ye", "hidden": false}, {"_id": "6a0df8e4d1ef9ecdf71c0ea1", "name": "Xiaobin Hu", "hidden": false}, {"_id": "6a0df8e4d1ef9ecdf71c0ea2", "name": "Shuicheng Yan", "hidden": false}, {"_id": "6a0df8e4d1ef9ecdf71c0ea3", "name": "Chunyan Miao", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66c5d81a4061fd5907443787/z0m7qDFg_25I0H1Ttgo16.jpeg"], "publishedAt": "2026-05-19T00:00:00.000Z", "submittedOnDailyAt": "2026-05-21T00:00:00.000Z", "title": "Mega-ASR: Towards In-the-wild^2 Speech Recognition via Scaling up Real-world Acoustic Simulation", "submittedOnDailyBy": {"_id": "66c5d81a4061fd5907443787", "avatarUrl": "/avatars/2e107195b1ff7d06bbc6c9bd4e5620cf.svg", "isPro": false, "fullname": "zhifei", "user": "filicos", "type": "user", "name": "filicos"}, "summary": "Despite rapid advances in automatic speech recognition (ASR) and large audio-language models, robust recognition in real-world environments remains limited by an \"acoustic robustness bottleneck\": models often lose acoustic grounding and produce omissions or hallucinations under severe, compositional distortions. We propose Mega-ASR, a unified ASR-in-the-wild framework that combines scalable compound-data construction with progressive acoustic-to-semantic optimization. We introduce Voices-in-the-Wild-2M, covering 7 classic acoustic phenomena and 54 physically plausible compound scenarios, and train Mega-ASR with Acoustic-to-Semantic Progressive Supervised Fine-Tuning and Dual-Granularity WER-Gated Policy Optimization. Extensive experiments demonstrate that Mega-ASR achieves significant advantages over prior state-of-the-art systems on adverse-condition ASR benchmarks (45.69% vs. 54.01% on VOiCES R4-B-F, and 21.49% vs. 29.34% on NOIZEUS Sta-0). On complex compositional acoustic scenarios, Mega-ASR further delivers over 30% relative WER reduction against strong open- and closed-source baselines, establishing a scalable paradigm for robust ASR in-the-wild.", "upvotes": 111, "discussionId": "6a0df8e4d1ef9ecdf71c0ea4", "projectPage": "https://xzf-thu.github.io/Mega-ASR/", "githubRepo": "https://github.com/xzf-thu/Mega-ASR", "githubRepoAddedBy": "user", "ai_summary": "Mega-ASR framework improves robustness in real-world speech recognition through compound-data construction and progressive acoustic-to-semantic optimization techniques.", "ai_keywords": ["automatic speech recognition", "acoustic robustness bottleneck", "compound-data construction", "progressive acoustic-to-semantic optimization", "Acoustic-to-Semantic Progressive Supervised Fine-Tuning", "Dual-Granularity WER-Gated Policy Optimization", "VOiCES R4-B-F", "NOIZEUS Sta-0", "WER reduction"], "githubStars": 100, "organization": {"_id": "6508ab2b349930913196378b", "name": "NationalUniversityofSingapore", "fullname": "National University of Singapore", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/630ca0817dacb93b33506ce7/ZYUmpSMsa5Whihw3me2Bw.png"}, "summary_zh": "<ul>\n    <li>\u5c3d\u7ba1\u81ea\u52a8\u8bed\u97f3\u8bc6\u522b\uff08ASR\uff09\u548c\u5927\u578b\u97f3\u9891\u8bed\u8a00\u6a21\u578b\u5feb\u901f\u8fdb\u5c55\uff0c\u4f46\u5728\u771f\u5b9e\u73af\u5883\u4e2d\u7684\u8bc6\u522b\u4ecd\u7136\u53d7\u9650\u4e8e\u201c\u58f0\u5b66\u9c81\u68d2\u6027\u74f6\u9888\u201d\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86Mega-ASR\uff0c\u8fd9\u662f\u4e00\u4e2a\u7edf\u4e00\u7684ASR\u6846\u67b6\uff0c\u7ed3\u5408\u4e86\u53ef\u6269\u5c55\u7684\u6570\u636e\u6784\u5efa\u548c\u9010\u6b65\u7684\u58f0\u5b66\u5230\u8bed\u4e49\u4f18\u5316\u3002</li>\n    <li>\u63a8\u51fa\u4e86Voices-in-the-Wild-2M\uff0c\u6db5\u76d67\u79cd\u7ecf\u5178\u58f0\u5b66\u73b0\u8c61\u548c54\u79cd\u7269\u7406\u4e0a\u5408\u7406\u7684\u590d\u5408\u573a\u666f\u3002</li>\n    <li>Mega-ASR\u901a\u8fc7\u76d1\u7763\u5fae\u8c03\u548c\u53cc\u7c92\u5ea6WER\u95e8\u63a7\u7b56\u7565\u4f18\u5316\u8fdb\u884c\u8bad\u7ec3\uff0c\u53d6\u5f97\u4e86\u663e\u8457\u7684\u6027\u80fd\u63d0\u5347\u3002</li>\n    <li>\u5728\u590d\u6742\u7684\u58f0\u5b66\u573a\u666f\u4e2d\uff0cMega-ASR\u5728\u9c81\u68d2\u6027\u4e0a\u8868\u73b0\u8d85\u8d8a\u4e86\u8bb8\u591a\u73b0\u6709\u7cfb\u7edf\uff0c\u5efa\u7acb\u4e86\u4e00\u79cd\u53ef\u6269\u5c55\u7684\u5f3a\u5065ASR\u65b0\u6a21\u5f0f\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Automatic speech recognition (ASR) struggles with accuracy in noisy real-world environments due to various acoustic challenges.</li>\n    <li>Mega-ASR is a new framework designed to improve ASR performance by using advanced data and optimization techniques.</li>\n    <li>It includes a large dataset called Voices-in-the-Wild-2M, which simulates different acoustic conditions and scenarios.</li>\n    <li>Mega-ASR has shown better performance in tests compared to previous ASR systems, with significant improvements in difficult conditions.</li>\n    <li>This approach offers a scalable solution for making ASR more reliable in real-life situations.</li>\n</ul>"}, "publishedAt": "2026-05-18T20:00:00.000Z", "title": "Mega-ASR: Towards In-the-wild^2 Speech Recognition via Scaling up Real-world Acoustic Simulation", "summary": "Despite rapid advances in automatic speech recognition (ASR) and large audio-language models, robust recognition in real-world environments remains limited by an \"acoustic robustness bottleneck\": models often lose acoustic grounding and produce omissions or hallucinations under severe, compositional distortions. We propose Mega-ASR, a unified ASR-in-the-wild framework that combines scalable compound-data construction with progressive acoustic-to-semantic optimization. We introduce Voices-in-the-Wild-2M, covering 7 classic acoustic phenomena and 54 physically plausible compound scenarios, and train Mega-ASR with Acoustic-to-Semantic Progressive Supervised Fine-Tuning and Dual-Granularity WER-Gated Policy Optimization. Extensive experiments demonstrate that Mega-ASR achieves significant advantages over prior state-of-the-art systems on adverse-condition ASR benchmarks (45.69% vs. 54.01% on VOiCES R4-B-F, and 21.49% vs. 29.34% on NOIZEUS Sta-0). On complex compositional acoustic scenarios, Mega-ASR further delivers over 30% relative WER reduction against strong open- and closed-source baselines, establishing a scalable paradigm for robust ASR in-the-wild.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66c5d81a4061fd5907443787/z0m7qDFg_25I0H1Ttgo16.jpeg"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.19833.png", "numComments": 2, "submittedBy": {"_id": "66c5d81a4061fd5907443787", "avatarUrl": "/avatars/2e107195b1ff7d06bbc6c9bd4e5620cf.svg", "fullname": "zhifei", "name": "filicos", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "6508ab2b349930913196378b", "name": "NationalUniversityofSingapore", "fullname": "National University of Singapore", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/630ca0817dacb93b33506ce7/ZYUmpSMsa5Whihw3me2Bw.png"}, "isAuthorParticipating": false}]
};
